insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('md-ishfaq-ahmed-wani-anantnag-jammu-and-kashmir', 'Md. Ishfaq Ahmed Wani', 'Farmers faced a persistent challenge—trees overloaded with ripening fruits often had their branches snap under pressure, while strong winds, heavy rain, and snowfall further damaged their orchards. This led to significant fruit loss, reducing their overall yield and income.', 'https://gian.org/multilingual_data/the-clipper-fruit-tree-safety-holder/', 'Anantnag, Jammu and Kashmir', null, 'Anantnag , Jammu and Kashmir', 'India', ARRAY['Anantnag, Jammu and Kashmir']::text[], ARRAY['fruit', 'safety', 'tree', 'orchard', 'device', 'snow', 'farmer']::text[], 'https://gian.org/multilingual_data/the-clipper-fruit-tree-safety-holder/', 'Md. Ishfaq Ahmed Wani', null, null, null, null, null, null, null, 'Anantnag , Jammu and Kashmir', 'https://gian.org/multilingual_data/the-clipper-fruit-tree-safety-holder/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/the-clipper-fruit-tree-safety-holder/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/Ishfaq--scaled.jpg"]'::jsonb, '["https://youtu.be/JV4RARcjzhM"]'::jsonb, 0, 0, 1, 'Md. Ishfaq Ahmed Wani Farmers faced a persistent challenge—trees overloaded with ripening fruits often had their branches snap under pressure, while strong winds, heavy rain, and snowfall further damaged their orchards. This led to significant fruit loss, reducing their overall yield and income. Anantnag, Jammu and Kashmir fruit safety tree orchard device snow farmer The Clipper (Fruit tree safety holder) Farmers faced a persistent challenge—trees overloaded with ripening fruits often had their branches snap under pressure, while strong winds, heavy rain, and snowfall further damaged their orchards. This led to significant fruit loss, reducing their overall yield and income. The Mechanical Safety Holder emerged as a game-changer, designed to support and balance multiple branches against external forces. This durable, adjustable clipper prevented breakage, reduced wastage, and even allowed farmers to shape their trees conveniently. With its use, they saved 4-5 extra boxes of fruit per tree, leading to higher earnings. With 3,000 units already sold and three new designs under testing, the impact of this innovation continues to grow. By strengthening trees and protecting harvests, the device is transforming farming, ensuring greater stability, less waste, and a more secure future for fruit growers.', '{"innovator_name":"Md. Ishfaq Ahmed Wani","location":"Anantnag , Jammu and Kashmir","detail_url":"https://gian.org/multilingual_data/the-clipper-fruit-tree-safety-holder/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('suneel-singh-jammu-and-kashmir', 'Suneel Singh', 'Sunil, a former soldier who served the Indian Army for 17 years, returned to his native Kishtwar with a vision to reverse the tide of migration and create sustainable livelihoods in his village. What began as a personal quest to improve farming conditions has blossomed into a community-wide movement, empowering over 2000 farmers with knowledge, training, and improved agricultural practices. His relentless experimentation, deep-rooted understanding of the region, and passion for organic farming have led to innovations that not only boost income but also restore ecological balance. From dairy to horticulture to infrastructure, every step of Sunil’s journey is marked by self-taught ingenuity and a drive to serve. His commitment is grounded in local wisdom, adapted to the region’s unique challenges and potentials. “Know about your area, see what potential exists in your area. Work in your area,” he says—words that reflect not just his philosophy but a model of rural innovation rooted in self-reliance, sustainability, and shared growth.', 'https://gian.org/multilingual_data/suneel-s1-walnut-variety/', 'Jammu and Kashmir', null, 'Jammu and Kashmir', 'India', ARRAY['Jammu and Kashmir']::text[], ARRAY['agriculture', 'horticulture', 'walnut', 'safety', 'tree', 'kiwi', 'polyhouse', 'snow', 'grafting', 'farmer', 'livelihood']::text[], 'https://gian.org/multilingual_data/suneel-s1-walnut-variety/', 'Suneel Singh', null, null, null, null, null, null, null, 'Jammu and Kashmir', 'https://gian.org/multilingual_data/suneel-s1-walnut-variety/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/suneel-s1-walnut-variety/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/01/suneel.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=3SNHjM2M_IY"]'::jsonb, 0, 0, 1, 'Suneel Singh Sunil, a former soldier who served the Indian Army for 17 years, returned to his native Kishtwar with a vision to reverse the tide of migration and create sustainable livelihoods in his village. What began as a personal quest to improve farming conditions has blossomed into a community-wide movement, empowering over 2000 farmers with knowledge, training, and improved agricultural practices. His relentless experimentation, deep-rooted understanding of the region, and passion for organic farming have led to innovations that not only boost income but also restore ecological balance. From dairy to horticulture to infrastructure, every step of Sunil’s journey is marked by self-taught ingenuity and a drive to serve. His commitment is grounded in local wisdom, adapted to the region’s unique challenges and potentials. “Know about your area, see what potential exists in your area. Work in your area,” he says—words that reflect not just his philosophy but a model of rural innovation rooted in self-reliance, sustainability, and shared growth. Jammu and Kashmir agriculture horticulture walnut safety tree kiwi polyhouse snow grafting farmer livelihood Suneel S1 Walnut Variety In the high-altitude region of Kishtwar, Jammu & Kashmir, Sunil has pioneered a remarkable transformation in agriculture through his innovative and sustainable practices. Recognising the dangers and inefficiencies of traditional walnut farming—where trees often grow as high as 70 feet—he developed a grafted variety called S1 Walnut by mastering bud grafting techniques under specific temperature and humidity conditions. This not only brought down the height of walnut trees to a manageable 25–30 feet but also achieved a 98% grafting success rate, ensuring uniform quality and safety during harvest. Sunil extended his efforts to a wide variety of crops including hazelnuts, pecan nuts, kiwis, grapes, apricots, and persimmons, all grown sustainably using local mother plants. He also redesigned polyhouse structures to withstand Kishtwar’s heavy snowfall, enabling farmers to continue cultivation through harsh winters. Today, his S1 walnuts have reached global markets, with samples already sent to the U.S., symbolising the world-class potential of Kishtwar’s produce.', '{"innovator_name":"Suneel Singh","location":"Jammu and Kashmir","detail_url":"https://gian.org/multilingual_data/suneel-s1-walnut-variety/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('hariman-sharma-bilaspur-hp', 'Hariman Sharma', 'In 1998, Hariman purchased some apples from a village in Bilaspur. After eating the fruit, he discarded the seeds in his backyard. He noticed that the seeds started germinating in 2001. He got some fruits on that tree. As an experienced farmer, he could sense that this apple tree bearing fruits in a warm area like his village situated at 1800 ft above mean sea level was extraordinary. Hence, he preserved this plant, and the next year, he grafted some branches on a plum tree as no apple tree was available. Proceeding with such research and plantation process. He finally came up with a variety of apples that can be grown in tropical subtropical and plain areas. It was named HRMN -99. Generally, apples can be grown at an altitude of 5000 to 8,500 ft above mean sea level in Himalayan ranges, and it needs 1000 to 1500 hours of chilling. But the variety developed by Hariman can grow at low hills or plain areas, which are about 1800 ft above means sea level. This variety does not require chilling hours. It is a scab disease-resistant apple variety that contains common characteristics such as; it can be grown in high-temperature areas. The plane height is up to 12 -15 ft fruit starts after three years of plantation. Flowering starts in early January, and harvesting can be done after six months, that is, in June. The ripe fruit color is yellow to red, with normal fruit size and sweetness. The only disadvantage of fruit is that it has a short shelf life of around 10 to 12 days at room temperature. The average yield of a well-grown plant is about one quintal per plant. Hariman’s innovation has received various regional, state, and national awards. He has received great recognition, and newspapers and magazines have written about his Apple variety. Today his farming practices are recognized nationally and internationally.', 'https://gian.org/multilingual_data/hrmn-99-apple-variety-for-low-altitude/', 'Bilaspur (HP)', null, 'Bilaspur (HP)', 'India', ARRAY['Bilaspur (HP)']::text[], ARRAY['fruit', 'tree', 'farmer']::text[], 'https://gian.org/multilingual_data/hrmn-99-apple-variety-for-low-altitude/', 'Hariman Sharma', null, null, null, null, null, null, null, 'Bilaspur (HP)', 'https://gian.org/multilingual_data/hrmn-99-apple-variety-for-low-altitude/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/hrmn-99-apple-variety-for-low-altitude/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/HRMN-99-Apple-variety-for-low-altitude-Hariman-Sharma.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=JCZskguBNs4"]'::jsonb, 31.4702174, 76.745195, 1, 'Hariman Sharma In 1998, Hariman purchased some apples from a village in Bilaspur. After eating the fruit, he discarded the seeds in his backyard. He noticed that the seeds started germinating in 2001. He got some fruits on that tree. As an experienced farmer, he could sense that this apple tree bearing fruits in a warm area like his village situated at 1800 ft above mean sea level was extraordinary. Hence, he preserved this plant, and the next year, he grafted some branches on a plum tree as no apple tree was available. Proceeding with such research and plantation process. He finally came up with a variety of apples that can be grown in tropical subtropical and plain areas. It was named HRMN -99. Generally, apples can be grown at an altitude of 5000 to 8,500 ft above mean sea level in Himalayan ranges, and it needs 1000 to 1500 hours of chilling. But the variety developed by Hariman can grow at low hills or plain areas, which are about 1800 ft above means sea level. This variety does not require chilling hours. It is a scab disease-resistant apple variety that contains common characteristics such as; it can be grown in high-temperature areas. The plane height is up to 12 -15 ft fruit starts after three years of plantation. Flowering starts in early January, and harvesting can be done after six months, that is, in June. The ripe fruit color is yellow to red, with normal fruit size and sweetness. The only disadvantage of fruit is that it has a short shelf life of around 10 to 12 days at room temperature. The average yield of a well-grown plant is about one quintal per plant. Hariman’s innovation has received various regional, state, and national awards. He has received great recognition, and newspapers and magazines have written about his Apple variety. Today his farming practices are recognized nationally and internationally. Bilaspur (HP) fruit tree farmer HRMN 99 Apple variety for low altitude A well-known progressive farmer cum innovator Hariman Sharma from Bilaspur, Himachal Pradesh, formulated an innovative variety of apples that can be successfully grown in plains. In these tropical and subtropical areas, temperatures can be as high as 40 to 45° Celsius during summers. GIAN and the Honey Bee Network aided this innovation. GIAN and NIF applied on behalf of Hariman Sharma to register HRMN 99 under the PPV and FR Act 2001.', '{"innovator_name":"Hariman Sharma","location":"Bilaspur (HP)","detail_url":"https://gian.org/multilingual_data/hrmn-99-apple-variety-for-low-altitude/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('suresh-p-v-malappuram-kerala', 'Suresh P V', 'Arecanut trees have to be climbed three times a year for harvesting. This work involves many risks, and only skilled laborers can do this. Suresh came up with the idea of making a machine to help climb the Arecanut tree. His prototype could carry a man and work on electricity. However, the power supply was an issue, so he fabricated a petrol engine-based automated Arecanut climbing and harvesting machine. The device is powered by a 42cc petrol engine operated using a remote/ mobile app. It comprises dumbbell-shaped rubber grip rollers clamped on the tree, and their rolling motion along the tree trunk provides upward motion. It is a self-adjusting machine for diameters wearing between 100 to 203 mm of the tree and can climb over dents or bumps in the surface of the tree. The machine works on the forward, reverse, neutral, and cutting modes. An accelerator is provided to control the rate of climb. The machine has been designed so that on full throttle, it can climb the tree in 1 minute (approx. 50- 60 ft), perform the cutting operation in 1 minute, and climb down the tree in another minute. The device weighs approx. 28 kg and can run for around 3 hours on 1 l of petrol. By any chance, if the machine stops functioning while climbing up or down the tree, a rope connected to it will enable the user to bring it down without climbing the tree. The innovation enables safety and effective labor performance for Arecanut cutting and harvesting. It has also helped reduce injury and fatalities among laborers climbing the Arecanut tree. Suresh was awarded the third prize at the 10th Biennial innovation award of the national innovation foundation inaugurated by President Ram Nath Kovind in Gujarat.', 'https://gian.org/multilingual_data/automated-arecanut-climbing-and-harvesting-machine/', 'Malappuram, Kerala', null, 'Malappuram , Kerala', 'India', ARRAY['Malappuram, Kerala']::text[], ARRAY['safety', 'tree', 'machine', 'device']::text[], 'https://gian.org/multilingual_data/automated-arecanut-climbing-and-harvesting-machine/', 'Suresh P V', null, null, null, null, null, null, null, 'Malappuram , Kerala', 'https://gian.org/multilingual_data/automated-arecanut-climbing-and-harvesting-machine/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/automated-arecanut-climbing-and-harvesting-machine/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/suresh-P.V.png"]'::jsonb, '["https://youtu.be/hHVLK4M_TbE?si=0Tv3Zpja3zClwFxf"]'::jsonb, 11.2779512, 76.4331698, 1, 'Suresh P V Arecanut trees have to be climbed three times a year for harvesting. This work involves many risks, and only skilled laborers can do this. Suresh came up with the idea of making a machine to help climb the Arecanut tree. His prototype could carry a man and work on electricity. However, the power supply was an issue, so he fabricated a petrol engine-based automated Arecanut climbing and harvesting machine. The device is powered by a 42cc petrol engine operated using a remote/ mobile app. It comprises dumbbell-shaped rubber grip rollers clamped on the tree, and their rolling motion along the tree trunk provides upward motion. It is a self-adjusting machine for diameters wearing between 100 to 203 mm of the tree and can climb over dents or bumps in the surface of the tree. The machine works on the forward, reverse, neutral, and cutting modes. An accelerator is provided to control the rate of climb. The machine has been designed so that on full throttle, it can climb the tree in 1 minute (approx. 50- 60 ft), perform the cutting operation in 1 minute, and climb down the tree in another minute. The device weighs approx. 28 kg and can run for around 3 hours on 1 l of petrol. By any chance, if the machine stops functioning while climbing up or down the tree, a rope connected to it will enable the user to bring it down without climbing the tree. The innovation enables safety and effective labor performance for Arecanut cutting and harvesting. It has also helped reduce injury and fatalities among laborers climbing the Arecanut tree. Suresh was awarded the third prize at the 10th Biennial innovation award of the national innovation foundation inaugurated by President Ram Nath Kovind in Gujarat. Malappuram, Kerala safety tree machine device Automated Arecanut climbing and harvesting machine Suresh PV, a 41-year-old enthusiastic innovator from Malappuram, Kerala, developed an automatic arecanut climbing and harvesting machine. The innovation was guided and supported by GIAN and the Honey Bee Network.Suresh, a school dropout, works as a driver and a rubber tapping worker in rubber plantations in his locality. Besides the Arecanut climbing and harvesting machine, he also developed a hydroelectric power plant of 2-kilowatt capacity for his village in 2004 and a ropeway system for transporting goods.', '{"innovator_name":"Suresh P V","location":"Malappuram , Kerala","detail_url":"https://gian.org/multilingual_data/automated-arecanut-climbing-and-harvesting-machine/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('ram-prasad-meher-bargarh-orissa', 'Ram Prasad Meher', 'Prasad’s father used tree trunks to make thread bundles for dying and making different designs. The process involves walking around the tree trunks making an elliptical shape for winding the thread bundle. The traditional method leads to less output with more time consumption. Looking at this, Ram Prasad started designing a machine that could do winding and spinning work at high speed. After working hard for over two months, he designed a prototype that could wind cotton automatically. The machine is fabricated with a drum over which weft winding works using power from a 0.25 HP electric motor. The innovator fabricated the special component that rotates periodically due to the impulse provided by the flat bars with the help of its cutting edges; this is responsible for feeding the threads in both forward and reverse movement. A uniform thread distribution system is attached to the chain and moves along the length of the drum. The attached lever controls the forward and reverse action of the uniform thread distribution system. A foot pedal-actuated brake system is provided to stop the drum’s rotation. Ram Prasad’s innovation can wind five bundles of yarn within an hour, which otherwise takes two to three days. The Innovator has successfully sold more than 90 units of the machines. The innovation was appreciated and awarded at the 10th national grassroots innovation and outstanding traditional knowledge awards in 2019', 'https://gian.org/multilingual_data/automatic-weft-winding-machine/', 'Bargarh, Orissa', null, 'Bargarh , Orissa', 'India', ARRAY['Bargarh, Orissa']::text[], ARRAY['tree', 'machine', 'weaving']::text[], 'https://gian.org/multilingual_data/automatic-weft-winding-machine/', 'Ram Prasad Meher', null, null, null, null, null, null, null, 'Bargarh , Orissa', 'https://gian.org/multilingual_data/automatic-weft-winding-machine/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/automatic-weft-winding-machine/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/Ramprasad-mehar-1.png"]'::jsonb, '["https://www.youtube.com/watch?v=iQ_3FjTwAr8"]'::jsonb, 21.3303107, 83.6135572, 1, 'Ram Prasad Meher Prasad’s father used tree trunks to make thread bundles for dying and making different designs. The process involves walking around the tree trunks making an elliptical shape for winding the thread bundle. The traditional method leads to less output with more time consumption. Looking at this, Ram Prasad started designing a machine that could do winding and spinning work at high speed. After working hard for over two months, he designed a prototype that could wind cotton automatically. The machine is fabricated with a drum over which weft winding works using power from a 0.25 HP electric motor. The innovator fabricated the special component that rotates periodically due to the impulse provided by the flat bars with the help of its cutting edges; this is responsible for feeding the threads in both forward and reverse movement. A uniform thread distribution system is attached to the chain and moves along the length of the drum. The attached lever controls the forward and reverse action of the uniform thread distribution system. A foot pedal-actuated brake system is provided to stop the drum’s rotation. Ram Prasad’s innovation can wind five bundles of yarn within an hour, which otherwise takes two to three days. The Innovator has successfully sold more than 90 units of the machines. The innovation was appreciated and awarded at the 10th national grassroots innovation and outstanding traditional knowledge awards in 2019 Bargarh, Orissa tree machine weaving Automatic weft winding machine Innovator Ram Prasad, a school dropout from Bargarh, Orissa, fabricated an automatic weft winding machine that can wind cotton automatically. The innovation was recognized and underpinned by GIAN and the Honey Bee Network.Since childhood, Ram Prasad has been interested in arts and crafts and joined his family’s weaving business. He owns a small workshop and develops textiles and saree weaving machines, mainly Sambalpuri sarees.', '{"innovator_name":"Ram Prasad Meher","location":"Bargarh , Orissa","detail_url":"https://gian.org/multilingual_data/automatic-weft-winding-machine/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('balwan-singh-bhiwani-haryana', 'Balwan Singh', 'The quality of seeds supplied by different companies and the farmers’ expectations in growing onions are clashing. Hence, Balwan thought of developing some variety of his own that could provide a high yield to the farmers. Once, Balwan’s brother bought some onions from the neighboring village. Balwan observed that the onions were large and well-shaped bulbs, red-colored, thick, and tight-skinned. Being an experienced farmer, he knew that good quality plants yield good fruits, and hence he started greeting and breeding through selection considering parameters such as the plant’s health, tight skin, large size, and well-shaped red-colored bulb. After years of repeating the same process to purify the variety and stabilize the characters, he finally developed Balwan Pyaj, a good-quality onion variety. This yield of onion is about 350 q/ha and has a good thickness of rings tolerance to Stemphylium blight and moderate pungency. The onions are 5 cm in diameter with dark red colored globular shaped bulbs. The neck thickness is 0.8 cm, weighing 50 to 60 g. It is attractive compared to conventional ones with firm, bright red colored mild pungent bulbs with an average yield of 200 q/ha. Balwan Singh, a generous person, gained a very respectful place in the village community and local administrations. Many local and national media covered his innovative work, and he does not mind sharing his knowledge and seeds with other farmers for prosperity', 'https://gian.org/multilingual_data/balwan-pyaj-onion/', 'Bhiwani, Haryana', null, 'Bhiwani , Haryana', 'India', ARRAY['Bhiwani, Haryana']::text[], ARRAY['fruit', 'health', 'farmer']::text[], 'https://gian.org/multilingual_data/balwan-pyaj-onion/', 'Balwan Singh', null, null, null, null, null, null, null, 'Bhiwani , Haryana', 'https://gian.org/multilingual_data/balwan-pyaj-onion/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/balwan-pyaj-onion/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/balwant-singh.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=MDNwlL1GySY"]'::jsonb, 28.7693181, 76.1551866, 1, 'Balwan Singh The quality of seeds supplied by different companies and the farmers’ expectations in growing onions are clashing. Hence, Balwan thought of developing some variety of his own that could provide a high yield to the farmers. Once, Balwan’s brother bought some onions from the neighboring village. Balwan observed that the onions were large and well-shaped bulbs, red-colored, thick, and tight-skinned. Being an experienced farmer, he knew that good quality plants yield good fruits, and hence he started greeting and breeding through selection considering parameters such as the plant’s health, tight skin, large size, and well-shaped red-colored bulb. After years of repeating the same process to purify the variety and stabilize the characters, he finally developed Balwan Pyaj, a good-quality onion variety. This yield of onion is about 350 q/ha and has a good thickness of rings tolerance to Stemphylium blight and moderate pungency. The onions are 5 cm in diameter with dark red colored globular shaped bulbs. The neck thickness is 0.8 cm, weighing 50 to 60 g. It is attractive compared to conventional ones with firm, bright red colored mild pungent bulbs with an average yield of 200 q/ha. Balwan Singh, a generous person, gained a very respectful place in the village community and local administrations. Many local and national media covered his innovative work, and he does not mind sharing his knowledge and seeds with other farmers for prosperity Bhiwani, Haryana fruit health farmer Balwan Pyaj – Onion 50-year-old innovator and progressive farmer Balwan Singh from Bhavani, Haryana, has developed a high-yield improved variety of onions with good keeping quality. GIAN and the Honey Bee Network supported the innovation. The Honey Bee Network helped Balwan Singh represent his innovation at various agricultural exhibitions, including the People’s Festival Of Innovation in New Delhi. NIF facilitated the variety testing at the vegetable research farm department of vegetable science in CCS HAU, Haryana, in 2010-11.', '{"innovator_name":"Balwan Singh","location":"Bhiwani , Haryana","detail_url":"https://gian.org/multilingual_data/balwan-pyaj-onion/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('ratanram-dudhval-sikar-rajasthan', 'Ratanram Dudhval', 'Ratanram observed the difficulties associated with commercial tractor-operated groundnut diggers and problems farmers face in getting laborers and also incurring losses due to insufficient digging and problems of wear and tear and maneuverability, especially at the corners. His small-scale industry manufactures agricultural machinery like blocks, seed drills, groundnut, digger, trolley, chaff cutter, tractor-operated bulldozers, etc. As an experienced manufacturer, he decided to modify the conventional groundnut digger with an additional vibration pad/ shock, absorbers spring, and two pivoted wheels in the rear of the groundnut digger. It reduces the load in the tractor’s 3-point leakages and increases maneuverability due to wheels, reduction in breakages due to the vibration pad, the approach of the machine in corners, and is easily driven on bunds and channels in the field. The modified innovation can fit any standard 540 rpm PTO, cover 4 ha in 8 hours, and consume only six lit diesel. The innovation is a great help to farmers, and Ratanram managed to sell more than 400 machines in just five years. The customers who purchased the machine in 2011 are still using the machine, and the sale is mainly based on word of mouth, which confirms the acceptability of the machine among the farmers. Ratanram received an award at the 9th National grassroots innovation award 2017', 'https://gian.org/multilingual_data/groundnut-digger-with-vibration-pads/', 'Sikar, Rajasthan', null, 'Sikar, Rajasthan', 'India', ARRAY['Sikar, Rajasthan']::text[], ARRAY['machine', 'farmer']::text[], 'https://gian.org/multilingual_data/groundnut-digger-with-vibration-pads/', 'Ratanram Dudhval', null, null, null, null, null, null, null, 'Sikar, Rajasthan', 'https://gian.org/multilingual_data/groundnut-digger-with-vibration-pads/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/groundnut-digger-with-vibration-pads/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/IMG-20240308-WA0006.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=9jtm58N-Q7Q"]'::jsonb, 27.1659844, 75.1895576, 1, 'Ratanram Dudhval Ratanram observed the difficulties associated with commercial tractor-operated groundnut diggers and problems farmers face in getting laborers and also incurring losses due to insufficient digging and problems of wear and tear and maneuverability, especially at the corners. His small-scale industry manufactures agricultural machinery like blocks, seed drills, groundnut, digger, trolley, chaff cutter, tractor-operated bulldozers, etc. As an experienced manufacturer, he decided to modify the conventional groundnut digger with an additional vibration pad/ shock, absorbers spring, and two pivoted wheels in the rear of the groundnut digger. It reduces the load in the tractor’s 3-point leakages and increases maneuverability due to wheels, reduction in breakages due to the vibration pad, the approach of the machine in corners, and is easily driven on bunds and channels in the field. The modified innovation can fit any standard 540 rpm PTO, cover 4 ha in 8 hours, and consume only six lit diesel. The innovation is a great help to farmers, and Ratanram managed to sell more than 400 machines in just five years. The customers who purchased the machine in 2011 are still using the machine, and the sale is mainly based on word of mouth, which confirms the acceptability of the machine among the farmers. Ratanram received an award at the 9th National grassroots innovation award 2017 Sikar, Rajasthan machine farmer Groundnut digger with Vibration pads Ratanram Dudhval is an innovator from Rajasthan. He modified the groundnut digger by adding a vibration pad shock absorber spring, and two pivoted wheels to its rear. The innovation was acknowledged and supported by GIAN and the Honey Bee Network.Ratanram Dudhval is a mechanic, and he runs his small-scale industry named Jai Kishan Krishi Yantra Udyog with his younger brother in Rajasthan.', '{"innovator_name":"Ratanram Dudhval","location":"Sikar, Rajasthan","detail_url":"https://gian.org/multilingual_data/groundnut-digger-with-vibration-pads/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-ashok-thakur-east-champaran-bihar', 'Mr. Ashok Thakur', 'Ashok Thakur observed that a large amount of paddy husk was discarded as agricultural waste in his area. As a professional fabricator of coal and wood husk stoves, he fabricated an efficient stove that can use paddy husk as fuel. He experimented with the common stove and suitably modified it for paddy husk. The stove consists of a frustum made up of an iron sheet of thickness 22 gauge and has a lot of holes of sizes 6 mm in a zigzag manner on the downward side. It weighs 4 kg and has a height of 8 inches. It is designed so that it can use paddy husk as fuel. It can be used anywhere as it is a portable stove. IIT GUWAHATI and TERI University, New Delhi, have tested it. Good reports stated that the stove has a fuel combustion rate of 4.67%, and the thermal efficiency is 23% in the cold and hot start and 32% during simmering. The innovator claims this stove can safely be used on a boat to cook food. It is a very good innovation for the regions where paddy is abundant. The innovation was appreciated and awarded at the 7th National grassroots innovation awards 2013', 'https://gian.org/multilingual_data/paddy-husk-stove/', 'East Champaran, Bihar', null, 'East Champaran , Bihar', 'India', ARRAY['East Champaran, Bihar']::text[], ARRAY['food']::text[], 'https://gian.org/multilingual_data/paddy-husk-stove/', 'Mr. Ashok Thakur', null, null, null, null, null, null, null, 'East Champaran , Bihar', 'https://gian.org/multilingual_data/paddy-husk-stove/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/paddy-husk-stove/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/03/paddy-husk-stove-Ashok-Thakur.jpg"]'::jsonb, '["https://youtu.be/OciBojiS6EQ%20"]'::jsonb, 26.6704794, 84.9088938, 1, 'Mr. Ashok Thakur Ashok Thakur observed that a large amount of paddy husk was discarded as agricultural waste in his area. As a professional fabricator of coal and wood husk stoves, he fabricated an efficient stove that can use paddy husk as fuel. He experimented with the common stove and suitably modified it for paddy husk. The stove consists of a frustum made up of an iron sheet of thickness 22 gauge and has a lot of holes of sizes 6 mm in a zigzag manner on the downward side. It weighs 4 kg and has a height of 8 inches. It is designed so that it can use paddy husk as fuel. It can be used anywhere as it is a portable stove. IIT GUWAHATI and TERI University, New Delhi, have tested it. Good reports stated that the stove has a fuel combustion rate of 4.67%, and the thermal efficiency is 23% in the cold and hot start and 32% during simmering. The innovator claims this stove can safely be used on a boat to cook food. It is a very good innovation for the regions where paddy is abundant. The innovation was appreciated and awarded at the 7th National grassroots innovation awards 2013 East Champaran, Bihar food Paddy Husk Stove The innovator Mr. Ashok Thakur, a 44-year-old professional blacksmith from East Champaran, Bihar, developed a stove that uses paddy husk as a fuel. GIAN and the Honey Bee Network supported his innovation as a good example of sustainable living. GIAN and NIF filed a patent in the innovator’s name.Ashok Thakur is a school dropout who started working in a factory but returned to his village and started his fabrication workshop under the guidance of his father. He started his journey by making and selling coal and wood husk Chulhas (stoves).', '{"innovator_name":"Mr. Ashok Thakur","location":"East Champaran , Bihar","detail_url":"https://gian.org/multilingual_data/paddy-husk-stove/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('anang-tadar-papum-parearunachal-pradesh', 'Anang Tadar', 'Anang once helped a blind lady find directions; this incident made him ponder the difficulties visually impaired people face in their daily lives. Visually challenged people face many difficulties walking and navigating due to obstacles. This incident made him study and research the problems faced by blind people. He found out that blind man sticks and smart walking sticks are already available in the market, which can detect obstacles at the ground level to help visually impaired people. Still, nothing in the market can detect obstacles at waist level and above. Anang then developed an intelligent goggle for the blind called G4B. Anang took inspiration from the navigation mechanism used by bats and integrated the same into a goggle. Bats emit specific frequency ultrasound from their nostrils or mouth and detect obstacles by sensing the echo bounced back from the obstacles. Bats do not use their eyes for navigation. Anang developed intelligent sunglasses which could detect obstacles present ahead of the usually challenged people and give an alert in the form of vibrations. The innovative goggle comprises an ultrasonic transmitter-receiver and a microprocessor. The normal sunglasses are fitted with sensors to alert visually challenged users about the obstacles ahead. Nissan glasses contain vibration alerts on the sides, and as the user moves nearer to the obstruction, the vibrations get stronger. These intelligent sunglasses complement blind man sticks/ smart walking sticks and are not designed to replace them. The innovation announcement was so impactful that UNICEF expressed interest in refining the prototype to make it market ready. His innovation has won many awards, including Dr. APJ Abdul Kalam’s ignite awards 2017, the Deena Nath Pandey smart India innovation award 2017, and the national award at the 10th National grassroots innovation award. 2019.', 'https://gian.org/multilingual_data/intelligent-sunglasses-for-the-blind/', 'Papum Pare, Arunachal Pradesh', null, 'Papum Pare,Arunachal Pradesh', 'India', ARRAY['Papum Pare, Arunachal Pradesh']::text[], ARRAY[]::text[], 'https://gian.org/multilingual_data/intelligent-sunglasses-for-the-blind/', 'Anang Tadar', null, null, null, null, null, null, null, 'Papum Pare,Arunachal Pradesh', 'https://gian.org/multilingual_data/intelligent-sunglasses-for-the-blind/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/intelligent-sunglasses-for-the-blind/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/6253Anang-Tadar.jpg"]'::jsonb, '["https://youtu.be/SFhHPFBZbUo%20"]'::jsonb, 27.0820739, 93.5407909, 1, 'Anang Tadar Anang once helped a blind lady find directions; this incident made him ponder the difficulties visually impaired people face in their daily lives. Visually challenged people face many difficulties walking and navigating due to obstacles. This incident made him study and research the problems faced by blind people. He found out that blind man sticks and smart walking sticks are already available in the market, which can detect obstacles at the ground level to help visually impaired people. Still, nothing in the market can detect obstacles at waist level and above. Anang then developed an intelligent goggle for the blind called G4B. Anang took inspiration from the navigation mechanism used by bats and integrated the same into a goggle. Bats emit specific frequency ultrasound from their nostrils or mouth and detect obstacles by sensing the echo bounced back from the obstacles. Bats do not use their eyes for navigation. Anang developed intelligent sunglasses which could detect obstacles present ahead of the usually challenged people and give an alert in the form of vibrations. The innovative goggle comprises an ultrasonic transmitter-receiver and a microprocessor. The normal sunglasses are fitted with sensors to alert visually challenged users about the obstacles ahead. Nissan glasses contain vibration alerts on the sides, and as the user moves nearer to the obstruction, the vibrations get stronger. These intelligent sunglasses complement blind man sticks/ smart walking sticks and are not designed to replace them. The innovation announcement was so impactful that UNICEF expressed interest in refining the prototype to make it market ready. His innovation has won many awards, including Dr. APJ Abdul Kalam’s ignite awards 2017, the Deena Nath Pandey smart India innovation award 2017, and the national award at the 10th National grassroots innovation award. 2019. Papum Pare, Arunachal Pradesh Intelligent sunglasses for the blind The 25-year-old innovator Anang Tadar from Papum Pare, Arunachal Pradesh, pursuing college, developed intelligent sunglasses for visually impaired people when he was a school student. His innovation was appreciated and supported by GIAN and the Honey Bee Network.', '{"innovator_name":"Anang Tadar","location":"Papum Pare,Arunachal Pradesh","detail_url":"https://gian.org/multilingual_data/intelligent-sunglasses-for-the-blind/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('arun-cherian-bengaluru-karnataka', 'Arun Cherian', 'As per WHO estimates, around 1.5 million people undergo amputations yearly and require prosthetic services, of which only 5 to 15% of patients have access to devices in low and middle-income countries. Orthotic and prosthetic devices have significant capabilities to improve mobility and reduce mortality, and yet over 70% of patients in India do not have access to it. The main reasons are the concentration of medical centers in urban areas leading to large travel and stay expenses, traditional casting methods limited to the geographical reach, and high device prices and delivery times. To overcome the main downsides associated with this, Arun decided to work on finding a solution. After completing his Master’s, Arun Cherian started his Ph.D. at Purdue University in developing exoskeletal suits. However, he left it incomplete and pursued recreating high-quality, affordable assistive devices from natural composite bamboo. After more than a year of research and testing through multi-center clinical trials, Rise Bionics developed a natural composite-based flexible foot using which people can run, play, and dance. Started in 2015, Rise Bionics provides custom-fitted prosthetic or orthotic devices within a day or two of scanning the patient. Arun Cherian spent over six years developing this system. Hence, today they can 3D scan a patient any part of the body, head, neck, spine, skull, hand, or leg at their home. We can digitally manufacture any bionics with subliminal accuracy in 2-3 hrs. The process is simple; a local healthcare practitioner scans the patient in their home or neighborhood hospital in two to three minutes and uploads the file to the cloud. Secondly, the central facility digitally modifies and fabricates the file per the diagnosis. Rise Bionics does not 3D print; because it takes 15-24 hrs minimum to print one device. They create prosthetics with their proprietary machine, which they wholly make in their facility; Rise Bionics’ digital carving will take about 7-8 minutes only. Thirdly, it is couriered within a few hours to the medical practitioner for patient fitting and device service. The cane prosthetics leg is now less than 1% of their business. Arun and his team went to Zurich and competed with German, Japanese, and American teams, which came up with experimental devices like 100000$, theirs was a couple of 100$, and they came first in the competition in 2016. Athletes wearing Rise Bionics devices clocked in the fastest lap time and came first in two of the three obstacle races for prosthetic legs at the Cybathlon in Zurich. Physical disability can be financially stressful; hence, Rise Bionics works towards reintegrating patients into society as soon as possible. They have served more than 1000 patients across India with assistive devices for the whole body. They serve at corporate hospitals, community hospitals, and not-for-profit organizations. They are planning a pan-India rollout with the Indian central government and even other state governments mixed; they are doing their first project with the Karnataka state government starting February 2023. They also work with ALIMCO, a central government PSU for all-India expansion. The challenge faced by Arun in expanding is that they are looking for Capex Infrastructure investment to shift their manufacturing unit to a 4000 sq. ft. place and also need help in finding ancillary personnel to train other hospitals and also sales and marketing personnel. In all of Asia, Rise Bionics is the only one providing this, and if the central government can take up this technology, Arun has already cleared clinical evaluation and trained all the 12 centers of the central government across India; they have purchased the Rise Bionics scanners, and now they are doing a pilot pan India roll-out, and if the central government can take this up, this would put India ahead of US and Europe in providing access to patients to high quality bionic assistive devices.', 'https://gian.org/multilingual_data/rise-bionics-by-arun-cherian-karnataka/', 'Bengaluru, Karnataka', null, 'Bengaluru , Karnataka', 'India', ARRAY['Bengaluru, Karnataka']::text[], ARRAY['machine', 'device', 'health', 'bamboo']::text[], 'https://gian.org/multilingual_data/rise-bionics-by-arun-cherian-karnataka/', 'Arun Cherian', null, null, null, null, null, null, null, 'Bengaluru , Karnataka', 'https://gian.org/multilingual_data/rise-bionics-by-arun-cherian-karnataka/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/rise-bionics-by-arun-cherian-karnataka/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/Screenshot-2024-03-08-175915.png"]'::jsonb, '["https://www.youtube.com/watch?v=38cFpEfv03E"]'::jsonb, 13.10197, 77.5863591, 1, 'Arun Cherian As per WHO estimates, around 1.5 million people undergo amputations yearly and require prosthetic services, of which only 5 to 15% of patients have access to devices in low and middle-income countries. Orthotic and prosthetic devices have significant capabilities to improve mobility and reduce mortality, and yet over 70% of patients in India do not have access to it. The main reasons are the concentration of medical centers in urban areas leading to large travel and stay expenses, traditional casting methods limited to the geographical reach, and high device prices and delivery times. To overcome the main downsides associated with this, Arun decided to work on finding a solution. After completing his Master’s, Arun Cherian started his Ph.D. at Purdue University in developing exoskeletal suits. However, he left it incomplete and pursued recreating high-quality, affordable assistive devices from natural composite bamboo. After more than a year of research and testing through multi-center clinical trials, Rise Bionics developed a natural composite-based flexible foot using which people can run, play, and dance. Started in 2015, Rise Bionics provides custom-fitted prosthetic or orthotic devices within a day or two of scanning the patient. Arun Cherian spent over six years developing this system. Hence, today they can 3D scan a patient any part of the body, head, neck, spine, skull, hand, or leg at their home. We can digitally manufacture any bionics with subliminal accuracy in 2-3 hrs. The process is simple; a local healthcare practitioner scans the patient in their home or neighborhood hospital in two to three minutes and uploads the file to the cloud. Secondly, the central facility digitally modifies and fabricates the file per the diagnosis. Rise Bionics does not 3D print; because it takes 15-24 hrs minimum to print one device. They create prosthetics with their proprietary machine, which they wholly make in their facility; Rise Bionics’ digital carving will take about 7-8 minutes only. Thirdly, it is couriered within a few hours to the medical practitioner for patient fitting and device service. The cane prosthetics leg is now less than 1% of their business. Arun and his team went to Zurich and competed with German, Japanese, and American teams, which came up with experimental devices like 100000$, theirs was a couple of 100$, and they came first in the competition in 2016. Athletes wearing Rise Bionics devices clocked in the fastest lap time and came first in two of the three obstacle races for prosthetic legs at the Cybathlon in Zurich. Physical disability can be financially stressful; hence, Rise Bionics works towards reintegrating patients into society as soon as possible. They have served more than 1000 patients across India with assistive devices for the whole body. They serve at corporate hospitals, community hospitals, and not-for-profit organizations. They are planning a pan-India rollout with the Indian central government and even other state governments mixed; they are doing their first project with the Karnataka state government starting February 2023. They also work with ALIMCO, a central government PSU for all-India expansion. The challenge faced by Arun in expanding is that they are looking for Capex Infrastructure investment to shift their manufacturing unit to a 4000 sq. ft. place and also need help in finding ancillary personnel to train other hospitals and also sales and marketing personnel. In all of Asia, Rise Bionics is the only one providing this, and if the central government can take up this technology, Arun has already cleared clinical evaluation and trained all the 12 centers of the central government across India; they have purchased the Rise Bionics scanners, and now they are doing a pilot pan India roll-out, and if the central government can take this up, this would put India ahead of US and Europe in providing access to patients to high quality bionic assistive devices. Bengaluru, Karnataka machine device health bamboo Rise Bionics by Arun Cherian (Karnataka) Innovator Arun Joshua Cherian, who completed his master’s and mechanical engineering degree with a specialization in robotics, innovated and developed Rise Bionics, an accessible and affordable health tech company for prosthetics and orthotics. Apart from this innovation, he developed the 4th generation of wearable medical exoskeletal suits.Rise Bionics is a one-stop solution for custom-fitted prosthetic or orthotic devices such as arms and legs. Rise Bionics develops natural composite-based flexible feet and arms with which people can run, play and dance at a small fraction of the cost of carbon fiber prosthetic legs.', '{"innovator_name":"Arun Cherian","location":"Bengaluru , Karnataka","detail_url":"https://gian.org/multilingual_data/rise-bionics-by-arun-cherian-karnataka/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('sivakumar-modha-hyderabad-telangana', 'Sivakumar Modha', 'After completing his bachelor’s in 2000, Sivakumar Modha was set to pursue his MCA at a private college in Hyderabad. The direction of his life changed when he visited a village named Moda near his hometown Hindupur, where many people are employed in the weaving industry. Here the weavers’ committee designs the silk sarees using punch card-based Jacquard machines, where the weaver manually creates and controls every single card. Not only is this punch card process time-consuming, but the efforts of the weavers are quite short-lived, as the cards last only up to 3 years. Every design easily takes a minimum of 15 days to complete on a punch card. Looking at this, Sivakumar Modha decided to help the weavers’ committee, which had suffered losses due to this manual system. “If I cannot catalyze a change in people’s lives, what is the use of higher education and modern technology? I will alter this industry fully,” Sivakumar remarked. After 14 years of struggle, research, and hard work, Sivakumar developed an electronic Jacquard machine. This machine was prototyped to replace the traditional punch card machines with an image-based system integrated into the loom through a pen drive. This technology not only downsizes the time and effort but can also design sarees using distinct patterns or portraits. After the innovation was successful, Sivakumar received an offer of 20 crores rupees from a Kolkata-based firm to sell his innovation and machine to them. Sivakumar refused the offer as he believed this innovation was not for his profit but for the betterment of handloom weavers. GIAN recognized and awarded him the Honey Bee Network Creativity & Inclusive Innovation Awards (HBNCRIIA) 2020', 'https://gian.org/multilingual_data/modha-technologies/', 'Hyderabad, Telangana', null, 'Hyderabad , Telangana', 'India', ARRAY['Hyderabad, Telangana']::text[], ARRAY['machine', 'device', 'weaving']::text[], 'https://gian.org/multilingual_data/modha-technologies/', 'Sivakumar Modha', null, null, null, null, null, null, null, 'Hyderabad , Telangana', 'https://gian.org/multilingual_data/modha-technologies/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/modha-technologies/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/12/Sivkumar-modha-.png"]'::jsonb, '["https://www.youtube.com/watch?v=I9qguPlIIAY"]'::jsonb, 0, 0, 1, 'Sivakumar Modha After completing his bachelor’s in 2000, Sivakumar Modha was set to pursue his MCA at a private college in Hyderabad. The direction of his life changed when he visited a village named Moda near his hometown Hindupur, where many people are employed in the weaving industry. Here the weavers’ committee designs the silk sarees using punch card-based Jacquard machines, where the weaver manually creates and controls every single card. Not only is this punch card process time-consuming, but the efforts of the weavers are quite short-lived, as the cards last only up to 3 years. Every design easily takes a minimum of 15 days to complete on a punch card. Looking at this, Sivakumar Modha decided to help the weavers’ committee, which had suffered losses due to this manual system. “If I cannot catalyze a change in people’s lives, what is the use of higher education and modern technology? I will alter this industry fully,” Sivakumar remarked. After 14 years of struggle, research, and hard work, Sivakumar developed an electronic Jacquard machine. This machine was prototyped to replace the traditional punch card machines with an image-based system integrated into the loom through a pen drive. This technology not only downsizes the time and effort but can also design sarees using distinct patterns or portraits. After the innovation was successful, Sivakumar received an offer of 20 crores rupees from a Kolkata-based firm to sell his innovation and machine to them. Sivakumar refused the offer as he believed this innovation was not for his profit but for the betterment of handloom weavers. GIAN recognized and awarded him the Honey Bee Network Creativity & Inclusive Innovation Awards (HBNCRIIA) 2020 Hyderabad, Telangana machine device weaving Modha Technologies A young degree holder from the United Andhra Pradesh, Sivakumar Modha chose to become an innovator to help the weaving community instead of pursuing his MCA. His innovation of the Modha device replacing Jacquard in handlooms took a decade and a half to complete. His prototype was recognized and facilitated by GIAN and the Honey Bee Network. GIAN (Grassroots Innovation Augmentation Network) encouraged and reinforced the innovation.', '{"innovator_name":"Sivakumar Modha","location":"Hyderabad , Telangana","detail_url":"https://gian.org/multilingual_data/modha-technologies/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('bisu-hang-limbu-west-sikkim', 'Bisu Hang Limbu', 'Bisu Hang Lambu, a 22-year-old innovator from West Sikkim, came up with a Selroti maker. Selroti is a traditional sweet bread of Nepali culture. GIAN and the Honey Bee Network accepted and appreciated the innovation.', 'https://gian.org/multilingual_data/selroti-maker/', 'West Sikkim', null, 'West Sikkim', 'India', ARRAY['West Sikkim']::text[], ARRAY['device', 'food', 'machine']::text[], 'https://gian.org/multilingual_data/selroti-maker/', 'Bisu Hang Limbu', null, null, null, null, null, null, null, 'West Sikkim', 'https://gian.org/multilingual_data/selroti-maker/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/selroti-maker/
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('prof-saji-varghese-bangalore-karnataka', 'Prof. Saji Varghese', 'Innovator cum associate professor at the department of English, Christ University, Bangalore professor Saji Varghese developed straws from coconut leaves that are fallen from trees as an eco-friendly alternative to the available plastic straws. Christ University initially funded the innovation, but GIAN and the Honey Bee Network eventually supported the project in whatever way needed. Straws developed from coconut leaves are a good alternative to plastic straws and create impact. Apart from these straws, they also started producing pens and pencils made of coconut leaves. Prof. Saji has received around 20 million orders for his innovative drinking straw. Professor Saji received many inquiries; he could send it to 10 countries, including the Netherlands, Australia, New Zealand, Canada, the Middle East, Belgium, the US, Dubai, and others. In India, Sunbird Straws onboarded major hotel chains like four seasons, 46 Ounces, and JW Marriot, and they all are repeat customers. The Philippines and people from other countries abroad have sent an inquiry to adopt their technology.', 'https://gian.org/multilingual_data/sunbird-straw-drinking-straws-from-coconut-leaves/', 'Bangalore, Karnataka', null, 'Bangalore , Karnataka', 'India', ARRAY['Bangalore, Karnataka']::text[], ARRAY['tree', 'machine']::text[], 'https://gian.org/multilingual_data/sunbird-straw-drinking-straws-from-coconut-leaves/', 'Prof. Saji Varghese', null, null, null, null, null, null, null, 'Bangalore , Karnataka', 'https://gian.org/multilingual_data/sunbird-straw-drinking-straws-from-coconut-leaves/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/sunbird-straw-drinking-straws-from-coconut-leaves/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/IMG_20230313_103757_404.webp"]'::jsonb, '["https://www.youtube.com/watch?v=lOB4blYxUtI"]'::jsonb, 12.9866413, 77.4904285, 1, 'Prof. Saji Varghese Innovator cum associate professor at the department of English, Christ University, Bangalore professor Saji Varghese developed straws from coconut leaves that are fallen from trees as an eco-friendly alternative to the available plastic straws. Christ University initially funded the innovation, but GIAN and the Honey Bee Network eventually supported the project in whatever way needed. Straws developed from coconut leaves are a good alternative to plastic straws and create impact. Apart from these straws, they also started producing pens and pencils made of coconut leaves. Prof. Saji has received around 20 million orders for his innovative drinking straw. Professor Saji received many inquiries; he could send it to 10 countries, including the Netherlands, Australia, New Zealand, Canada, the Middle East, Belgium, the US, Dubai, and others. In India, Sunbird Straws onboarded major hotel chains like four seasons, 46 Ounces, and JW Marriot, and they all are repeat customers. The Philippines and people from other countries abroad have sent an inquiry to adopt their technology. Bangalore, Karnataka tree machine Sunbird straw: Drinking straws from coconut leaves According to a survey conducted in 2018, India creates 25,000 tons of plastic waste every year, of which only 9% is recycled. One of the classic examples of single-use plastic is plastic straws. Plastic products are majorly made from polypropylene, a material that degrades very slowly, out of which small items are even more difficult to recycle; hence materials like straws end up in a landfill or damage our oceans and marine wildlife. Professor Saji devised an alternative to replace plastic straws with eco-friendly straws made from coconut leaves. From 1 fallen coconut leaf, 150 -200 straws can be made; they realized it is a very good scalable and sustainable product and an alternative to plastic straws. The country aims to revolutionize rural employment and meet global demand. These straws are developed from falling coconut leaves which are abundant in our country and are mostly discarded or burned. As the first sample, Saji developed a single-layer coconut leaf straw in 2017. But by 2018, Prof. Saji came up with a final product of coconut leaf straws available, from regular ones to straws that can be used for cocktails, shakes, smoothies, and boba tea. These eco-friendly straws range from 4 to 8 inches long and 3 to 13 mm in diameter. They developed a 2nd gen machine (multi-purpose machine), which took 45s to develop one straw. They recently upgraded the technology and have developed a conveyor system where time has reduced to 1.5s from 45s, and fatigue is also reduced. Machines are developed in-house and are patented. The product process technology is also patented and has 31 claims under it. The company aims to employ 2000 women at the end of the year and reach production of 1 lakh/day. Prof. Saji has developed a start-up named Sunbird straw to make a difference. This innovation is a blessing to mother nature as it has prevented the burning of coconut leaves, has played a part in reducing the usage of plastic straws and has empowered women in rural communities through employment. Also, this innovation has received several acknowledgments and awards, including the Shreshta Udyami Guru Puraskar 2020 from the entrepreneurship development institute of India and the first position at the startup launchpad by the ASSOCHAM, New Delhi.', '{"innovator_name":"Prof. Saji Varghese","location":"Bangalore , Karnataka","detail_url":"https://gian.org/multilingual_data/sunbird-straw-drinking-straws-from-coconut-leaves/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('manish-patel-deoria-uttar-pradesh', 'Manish Patel', 'A student innovator Manish Patel innovated a battery-operated bike that will not allow the rider to ride without a helmet and after drinking alcohol. The Honey Bee Network and GIAN governed this innovation. The innovation is unique and has been appreciated by many innovators. GIAN helped the innovator with marketing and participation in different events for more visibility. The innovation is with advanced technology and is successfully prototyped.', 'https://gian.org/multilingual_data/battery-operated-bike/', 'Deoria, Uttar Pradesh', null, 'Deoria , Uttar Pradesh', 'India', ARRAY['Deoria, Uttar Pradesh']::text[], ARRAY['device']::text[], 'https://gian.org/multilingual_data/battery-operated-bike/', 'Manish Patel', null, null, null, null, null, null, null, 'Deoria , Uttar Pradesh', 'https://gian.org/multilingual_data/battery-operated-bike/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/battery-operated-bike/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/manish-patel.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=G1GafdcqpNo"]'::jsonb, 26.2111973, 83.985008, 1, 'Manish Patel A student innovator Manish Patel innovated a battery-operated bike that will not allow the rider to ride without a helmet and after drinking alcohol. The Honey Bee Network and GIAN governed this innovation. The innovation is unique and has been appreciated by many innovators. GIAN helped the innovator with marketing and participation in different events for more visibility. The innovation is with advanced technology and is successfully prototyped. Deoria, Uttar Pradesh device Battery-operated bike So many youngsters often ride bikes without wearing helmets and after drinking alcohol. Being a young innovator, Manish thought of innovating a device with a bike so that if a rider is not wearing a helmet or is under the influence of alcohol, the bike will not run. Manish then fabricated his circuits for a cycle with the dynamo attached. The sensors present in the circuit detect the faces and smell alcohol, so if the rider is not wearing a helmet or is under the influence of alcohol, the bike will not start. It will greatly help to prevent drunk driving and accident casualties. The bike prototype is ready but yet to commercialize as the innovator needs more help with design inputs, manufacturability, and robustness of the functionality. The innovation has been successfully presented at the IIC’s People’s Festival of Innovation.', '{"innovator_name":"Manish Patel","location":"Deoria , Uttar Pradesh","detail_url":"https://gian.org/multilingual_data/battery-operated-bike/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('niki-bharatbhai-parmar-amreli-gujarat', 'Niki Bharatbhai Parmar', 'The innovator Niki Bharatbhai Parmar, based in Amreli, Gujarat, innovated a tractor-mounted crane that is portable, low-cost, and more efficient. The innovation was appreciated and aided by the Honey Bee Network and GIAN. Niki Bharatbhai Parmar owns Parmar Engineers, and other than mini cranes, there are several products under the brand name of Parmar Engineers. Apart from this, Niki has also started making firefighting equipment and several other innovations and modifications for different types of crops which are not yet present in the market. They are passionate and are doing a lot of R&D in this field.', 'https://gian.org/multilingual_data/tractor-mounted-mini-crane-by-niki-bharatbhai-parmar-gujarat/', 'Amreli, Gujarat', null, 'Amreli , Gujarat', 'India', ARRAY['Amreli, Gujarat']::text[], ARRAY['tool', 'machine', 'farmer']::text[], 'https://gian.org/multilingual_data/tractor-mounted-mini-crane-by-niki-bharatbhai-parmar-gujarat/', 'Niki Bharatbhai Parmar', null, null, null, null, null, null, null, 'Amreli , Gujarat', 'https://gian.org/multilingual_data/tractor-mounted-mini-crane-by-niki-bharatbhai-parmar-gujarat/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/tractor-mounted-mini-crane-by-niki-bharatbhai-parmar-gujarat/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Nikki-parmar-tractor-mounted-mini-crane-11.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=VeSu7Bvsr9s"]'::jsonb, 21.6425971, 71.2161428, 1, 'Niki Bharatbhai Parmar The innovator Niki Bharatbhai Parmar, based in Amreli, Gujarat, innovated a tractor-mounted crane that is portable, low-cost, and more efficient. The innovation was appreciated and aided by the Honey Bee Network and GIAN. Niki Bharatbhai Parmar owns Parmar Engineers, and other than mini cranes, there are several products under the brand name of Parmar Engineers. Apart from this, Niki has also started making firefighting equipment and several other innovations and modifications for different types of crops which are not yet present in the market. They are passionate and are doing a lot of R&D in this field. Amreli, Gujarat tool machine farmer Tractor-mounted mini crane by Niki Bharatbhai Parmar (Gujarat) An engineer thought of a tractor-mounted mini crane that can be used when the place is congested, and a huge industrial crane cannot be used. The mini attachments are equipped with advanced technologies and all the necessary tools to carry out assigned tasks efficiently. It can also be customized as per the customers’ requirements. It is a great alternative and will directly create employment opportunities for the operator. It can also be aided in farming and infrastructure building. It is a mini crane that can be mounted to any 25 HP tractor, providing an option to small-scale buyers across India who earlier were strained by high-cost machines. At first, they created a modified crane design according to its usage and capacity of 1.5 tons. They made it cost-effective as 80% of customers needed such equipment but could not afford it. Their focus was on tractor attachments because it is the only viable and feasible machine that farmers can afford and is easily available. A project of a 360-degree mounted crane starts around 12- 16 lakhs in the market; Parmar engineers launched it at the cost of 5-8 lakhs. Then after tractor-mounted loaders, which come for 4.5 lahks in the market, they made similar models for 1.5-2 lakhs. Niki Parmar also designed a stone picker machine and sold it in Akola, Maharashtra, which was five lakhs in the market, and he made it available for 2.5 lahks. They focus on equipment customization, giving them the upper hand in the market because very few companies offer customized products. The innovation was successful, and the order flow is also quite high. In total, they have sold 200+ mini cranes since 2015, more than 200 mini loaders, 360 degrees sold five units; and in 3 months, they managed to sell six stone pickers. In 2018 their turnover was ten lakhs; in 2020, it was 83 lakhs; and in the last audit, Parmar engineer’s turnover was 1.9 Cr', '{"innovator_name":"Niki Bharatbhai Parmar","location":"Amreli , Gujarat","detail_url":"https://gian.org/multilingual_data/tractor-mounted-mini-crane-by-niki-bharatbhai-parmar-gujarat/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('ralte-and-l-salio-aizawl-mizoram', 'Ralte and L Salio', 'The innovators, Ralte and L Salio from Aizawl, Mizoram, developed a bamboo splint and stick-making machine which can be used for incense stick-making. This machine is manually operated and hence is eco-friendly. It was supported and guided by the Honey Bee Network and GIAN under the MVIF scheme. In the whole world, India is the largest producer of incense sticks. They are mostly manufactured in the interior part of northeastern states (like Tripura, Assam, Mizoram, etc.) by tribal people. This innovation is a boon for the tribal community of India, and innovators have managed to sell more than 2500 units in the northeastern hilly state of India and neighboring states of Nepal and Bangladesh. The innovator has also developed prototypes, such as room lighting systems, river water-operated grinders, and huskers.', 'https://gian.org/multilingual_data/bamboo-splint-and-stick-making-machine/', 'Aizawl, Mizoram', null, 'Aizawl , Mizoram', 'India', ARRAY['Aizawl, Mizoram']::text[], ARRAY['tool', 'machine', 'water', 'bamboo']::text[], 'https://gian.org/multilingual_data/bamboo-splint-and-stick-making-machine/', 'Ralte and L Salio', null, null, null, null, null, null, null, 'Aizawl , Mizoram', 'https://gian.org/multilingual_data/bamboo-splint-and-stick-making-machine/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/bamboo-splint-and-stick-making-machine/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/IMG-20230310-WA0006.jpg"]'::jsonb, '["https://youtu.be/0cjtLGVgpcY?si=8dRyPCZiW8bgABEy"]'::jsonb, 23.734269387887775, 92.72361797130237, 1, 'Ralte and L Salio The innovators, Ralte and L Salio from Aizawl, Mizoram, developed a bamboo splint and stick-making machine which can be used for incense stick-making. This machine is manually operated and hence is eco-friendly. It was supported and guided by the Honey Bee Network and GIAN under the MVIF scheme. In the whole world, India is the largest producer of incense sticks. They are mostly manufactured in the interior part of northeastern states (like Tripura, Assam, Mizoram, etc.) by tribal people. This innovation is a boon for the tribal community of India, and innovators have managed to sell more than 2500 units in the northeastern hilly state of India and neighboring states of Nepal and Bangladesh. The innovator has also developed prototypes, such as room lighting systems, river water-operated grinders, and huskers. Aizawl, Mizoram tool machine water bamboo Bamboo Splint and Stick Making Machine Making strips and sticks with the conventional knife method is time-consuming, tedious, and risky. Electrically operated high-power machines are available for industries; the rural community cannot afford such tools due to the village’s lack of electricity and finances. Ralte and L. Salio decided to create an affordable bamboo splint and stick-making machine to assist the tribal community in overcoming the problems associated with the traditional method. The innovator successfully prototyped a manually operated bamboo splint-making machine that can convert bamboo into 1.2 mm thick strips and sticks. It is made of carbon steel and has a capacity of 5,000 splints/hour or 5 kg /hour. It is easy to operate, affordable, and easy to maintain. It can be used to generate employment in rural areas and to make toothpicks, ice cream sticks, etc. They have been recognized for their innovation all around the country and are getting inquiries for sale in Brazil and Sri Lanka', '{"innovator_name":"Ralte and L Salio","location":"Aizawl , Mizoram","detail_url":"https://gian.org/multilingual_data/bamboo-splint-and-stick-making-machine/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('gopal-surtia-right-and-paresh-panchal-left-ahmedabad-gujarat', 'Gopal Surtia (right) and Paresh Panchal (left)', 'The cow dung pot-making machine was innovated by two innovators, Gopal Bhai Surtia and Prakash Bhai Panchal, from Ahmedabad, Gujarat. This eco-friendly, sustainable innovation was successfully developed and marketed with the help of the Honey Bee Network and GIAN. Also, both innovators filed a patent for the machine in the year 2017 with the help of GIAN. It is an eco-friendly manufacturing machine that does not cause any pollution. The innovators have already sold multiple units of the innovative product.', 'https://gian.org/multilingual_data/cow-dung-pot-making-machines-by-gopal-surtia-and-paresh-panchal-gujarat/', 'Ahmedabad, Gujarat', null, 'Ahmedabad , Gujarat', 'India', ARRAY['Ahmedabad, Gujarat']::text[], ARRAY['machine', 'water']::text[], 'https://gian.org/multilingual_data/cow-dung-pot-making-machines-by-gopal-surtia-and-paresh-panchal-gujarat/', 'Gopal Surtia (right) and Paresh Panchal (left)', null, null, null, null, null, null, null, 'Ahmedabad , Gujarat', 'https://gian.org/multilingual_data/cow-dung-pot-making-machines-by-gopal-surtia-and-paresh-panchal-gujarat/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/cow-dung-pot-making-machines-by-gopal-surtia-and-paresh-panchal-gujarat/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Gopalbhai_suritya-imageonline.co-merged.png"]'::jsonb, '["https://www.youtube.com/watch?v=xT__jkmano0"]'::jsonb, 23.0513311, 72.5319491, 1, 'Gopal Surtia (right) and Paresh Panchal (left) The cow dung pot-making machine was innovated by two innovators, Gopal Bhai Surtia and Prakash Bhai Panchal, from Ahmedabad, Gujarat. This eco-friendly, sustainable innovation was successfully developed and marketed with the help of the Honey Bee Network and GIAN. Also, both innovators filed a patent for the machine in the year 2017 with the help of GIAN. It is an eco-friendly manufacturing machine that does not cause any pollution. The innovators have already sold multiple units of the innovative product. Ahmedabad, Gujarat machine water Cow dung pot-making machines by Gopal Surtia and Paresh Panchal (Gujarat) The innovative idea came from Gopal Surtia, who made a crude pot manually. Gopal developed the idea of a cow dung pot machine, and Paresh Panchal was connected with him by the Honey Bee Network to design and modify it. The innovators have used animal manure, locally known as cow dung and wheat flour, in the ratio of 20:1 kg, along with agricultural waste and basic raw materials to prepare eco-friendly pots. Spoiled bajra flowers or shells of caster leaves or neem leaves were used in the mixture to protect the pot from pest attacks, as they have insecticidal properties that prevent termite attacks. The innovation is biodegradable and eco-friendly. The leaching of nutrients is prevented as the water absorption rate of the pot is very slow. It has advantages such as faster growth of the plant as it is made of cow dung, and employment generation is possible through local manufacturing and sourcing of these cow dung pots. This innovation of garden pot-making machines has employed jail inmates. It was successfully incorporated by Dharamshala prison. The forest departments and prisons of many states in India are using it. It won many awards and was showcased at Rashtrapati Bhavan at the festival of innovation by the Honey Bee Network and the National Innovation Foundation.', '{"innovator_name":"Gopal Surtia (right) and Paresh Panchal (left)","location":"Ahmedabad , Gujarat","detail_url":"https://gian.org/multilingual_data/cow-dung-pot-making-machines-by-gopal-surtia-and-paresh-panchal-gujarat/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('prakash-singh-raghuvanshi-varanasi-uttar-pradesh', 'Prakash Singh Raghuvanshi', 'A 49 years old innovator and enterprising farmer from Varanasi, Uttar Pradesh, who believes in promoting self-sustainability, has developed better and high-yielding wheat, paddy, and pigeon pea varieties, supported by the Honey Bee Network and GIAN under MVIF in association with NIF. Prakash’s brother owns a seed company and sells the seeds developed by him. Prakash owns three and a half acres of agricultural land on which he cultivates wheat, paddy, and pigeon peas. Instead of just farming, Prakash works hard to develop an improved variety of crops so that good quality seeds of higher-yielding varieties can benefit farmers and the country.', 'https://gian.org/multilingual_data/improved-varieties-of-wheat-paddy-and-pigeon-pe/', 'Varanasi, Uttar Pradesh', null, 'Varanasi , Uttar Pradesh', 'India', ARRAY['Varanasi, Uttar Pradesh']::text[], ARRAY['agriculture', 'food', 'farmer', 'livelihood']::text[], 'https://gian.org/multilingual_data/improved-varieties-of-wheat-paddy-and-pigeon-pe/', 'Prakash Singh Raghuvanshi', null, null, null, null, null, null, null, 'Varanasi , Uttar Pradesh', 'https://gian.org/multilingual_data/improved-varieties-of-wheat-paddy-and-pigeon-pe/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/improved-varieties-of-wheat-paddy-and-pigeon-pe/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-08-at-12.53.39.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=CxR9PfYZgAA"]'::jsonb, 25.1941606, 82.8532928, 1, 'Prakash Singh Raghuvanshi A 49 years old innovator and enterprising farmer from Varanasi, Uttar Pradesh, who believes in promoting self-sustainability, has developed better and high-yielding wheat, paddy, and pigeon pea varieties, supported by the Honey Bee Network and GIAN under MVIF in association with NIF. Prakash’s brother owns a seed company and sells the seeds developed by him. Prakash owns three and a half acres of agricultural land on which he cultivates wheat, paddy, and pigeon peas. Instead of just farming, Prakash works hard to develop an improved variety of crops so that good quality seeds of higher-yielding varieties can benefit farmers and the country. Varanasi, Uttar Pradesh agriculture food farmer livelihood Improved varieties of wheat, paddy, and pigeon pea by Prakash Singh Raghuvanshi (Uttar Pradesh) Prakash likes to keep himself updated in the field of agriculture, and hence he regularly participates in agricultural fairs and meets scientists and agricultural officers. The inspiration for the innovation came from Dr. Mahatim Singh, former professor at Banaras Hindu University (BHU) and former vice chancellor of GB Pant, University of Agriculture and Technology (GBPUAT). Dr. Singh motivated Prakash to develop varieties that could be useful for other farmers to increase their yield and improve their livelihood.Prakash has developed numerous improved high-yielding wheat, paddy, and pigeon pea varieties with the best disease-resistant seeds and good flavors. Prakash developed all these varieties using the simple selection-based method in which specific characteristic features of the plants are observed. The new, improved variety of wheat, paddy, and pigeon pea gives around 27, 30, and 12 quintals per acre of yield, respectively.He has distributed his variety of seeds to the farmers of almost all the states of India and has received appreciable reports and feedback. He has participated in the National Innovation Foundation’s informal research advisory committee for evaluating technologies for the fourth competition. He has also participated in many agricultural Mila and food festivals that received a great response for his varieties. He was also awarded at the 4th National National Grassroots Innovations and traditional knowledge competition in 2007.', '{"innovator_name":"Prakash Singh Raghuvanshi","location":"Varanasi , Uttar Pradesh","detail_url":"https://gian.org/multilingual_data/improved-varieties-of-wheat-paddy-and-pigeon-pe/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('rai-singh-dahiya-hanumangarh-rajasthan', 'Rai Singh Dahiya', 'An innovator Rai Singh from Hanumangarh, Rajasthan, has created an efficient biomass gasifier system to smooth engine operation and minimize operational costs. The Honey Bee Network and GIAN North under MVIF supported this innovation. With the guidance and support from GIAN, the innovator has been able to manufacture on a large scale and sell more than 50 units of his gasifier. The innovator Rai Singh had no formal education. Still, because of his love for science and machines, he gained knowledge by dismantling and repairing gadgets and listening to science programs on the radio. His dedication and hard work made him successful and the owner of Enersol Biopower private limited.', 'https://gian.org/multilingual_data/biomass-gasifier-system/', 'Hanumangarh, Rajasthan', null, 'Hanumangarh , Rajasthan', 'India', ARRAY['Hanumangarh, Rajasthan']::text[], ARRAY['machine', 'device']::text[], 'https://gian.org/multilingual_data/biomass-gasifier-system/', 'Rai Singh Dahiya', null, null, null, null, null, null, null, 'Hanumangarh , Rajasthan', 'https://gian.org/multilingual_data/biomass-gasifier-system/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/biomass-gasifier-system/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Bio-gasifier-.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=tvEYAO4N4Uk"]'::jsonb, 29.0019411, 74.3587473, 1, 'Rai Singh Dahiya An innovator Rai Singh from Hanumangarh, Rajasthan, has created an efficient biomass gasifier system to smooth engine operation and minimize operational costs. The Honey Bee Network and GIAN North under MVIF supported this innovation. With the guidance and support from GIAN, the innovator has been able to manufacture on a large scale and sell more than 50 units of his gasifier. The innovator Rai Singh had no formal education. Still, because of his love for science and machines, he gained knowledge by dismantling and repairing gadgets and listening to science programs on the radio. His dedication and hard work made him successful and the owner of Enersol Biopower private limited. Hanumangarh, Rajasthan machine device Biomass Gasifier System Back in 1982, Rai Singh had set up a kiln for baking bricks which had a capacity of 12000 bricks. He observed that burning wood and other fuels in the kiln produced some gas that was burning more furiously. In 1991, Singh started his workshop repairing tractors, Jeep trucks, and other engines. After observing the increasing demand and price for diesel engines in the agricultural sector, he decided to modify the diesel engine to operate on an economical LPG. After this LPG engine was successful, he considered making an engine that could run on wood-burning gas. Then after a series of experiments, he successfully developed a device that consists of a gasifier that helps convert biomass into producer gas. The conventional diesel engine was then modified with a spark plug and a fuel pump with a distributor setup. The modified diesel engine was running using the gasifier but for a very short time. Singh found the glitch in the device, and impurities in the producer gas and worked out several mechanisms and filtering sieves to develop a filtering mechanism so that gas could be supplied to the modified engine. He successfully developed his biomass gasifier system, reducing maintenance and increasing the capability to operate for 40 hours continuously. The system is a success as it uses all types of wood waste and fuel. Wood stocks of cotton pulses, coconut shells and palm stocks, maize cobs, branches and twigs, various agricultural residues, certain industrial waste of paper, plywood, etc. The reported fuel consumption of the system is 1 kg/kVA, approximately 30 to 35%, less than conventional gasifiers. Singh’s biomass gasifier system has won many awards for sustainable technological development. He was also honored at Rashtrapati Bhavan by NIF. In 2002, he was honored by the gram panchayat, and in 2004 by the district collector. The innovator has also been awarded a national award in the 5th Biennial annual award function.', '{"innovator_name":"Rai Singh Dahiya","location":"Hanumangarh , Rajasthan","detail_url":"https://gian.org/multilingual_data/biomass-gasifier-system/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('ashikbhai-gani-banaskantha-gujarat', 'Ashikbhai Gani', 'Ashikbhai Gani from Gujarat innovated a farmyard manure distributor in the field, which can be used to spread the farmyard manure in farms without any labor-intensive work. The Honey Bee Network and GIAN supported his innovation to help scale it up. Innovator Ashikbhai is dedicated to his innovation, and today he has set up a company named Greenland agro Enterprise. After launch, Ashikbhai and the team have sold up to 185 units and have 30 machine orders. They have a design patent on the name of their company Greenland agro. Manufacturing is continued, and they keep at least ten machines in stock.', 'https://gian.org/multilingual_data/farmyard-manure-distributor-in-the-field-by-ashikbhai-gani-gujarat/', 'Banaskantha, Gujarat', null, 'Banaskantha , Gujarat', 'India', ARRAY['Banaskantha, Gujarat']::text[], ARRAY['machine', 'farmer']::text[], 'https://gian.org/multilingual_data/farmyard-manure-distributor-in-the-field-by-ashikbhai-gani-gujarat/', 'Ashikbhai Gani', null, null, null, null, null, null, null, 'Banaskantha , Gujarat', 'https://gian.org/multilingual_data/farmyard-manure-distributor-in-the-field-by-ashikbhai-gani-gujarat/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/farmyard-manure-distributor-in-the-field-by-ashikbhai-gani-gujarat/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/TEJS9626-scaled.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=TRBxP0arN6M"]'::jsonb, 24.0858656, 72.36663, 1, 'Ashikbhai Gani Ashikbhai Gani from Gujarat innovated a farmyard manure distributor in the field, which can be used to spread the farmyard manure in farms without any labor-intensive work. The Honey Bee Network and GIAN supported his innovation to help scale it up. Innovator Ashikbhai is dedicated to his innovation, and today he has set up a company named Greenland agro Enterprise. After launch, Ashikbhai and the team have sold up to 185 units and have 30 machine orders. They have a design patent on the name of their company Greenland agro. Manufacturing is continued, and they keep at least ten machines in stock. Banaskantha, Gujarat machine farmer Farmyard manure distributor in the field by Ashikbhai Gani (Gujarat) As an innovator, Ashikbhai noticed that if any farmer wants to spread farm yard manure on their farm, they always have to ask the service provider who will come with their tractor, trolley, and JCB with labor. In this process, the service provider makes piles in the farm by picking them up manually from the farmer’s dump site. Further, these piles had to be spread in the field, which is labor-intensive and time-consuming. The main problem was putting manure on the farm. He saw a foreign machine serving the task, but it was expensive for Indian farmers. So in 2017, he made a design that took three years to develop. The prototype was ready in 2018 for testing. We asked a farmer to give us feedback on the problems faced for one year. We did R&D to solve the problems, and the final model was ready by 2019, which they launched in the market. Many experiments were done on RPM, torque, weight balancing, turning weight optimization, etc., before finalizing the trolley compatible with the conventional tractor arrangement. It is 11ft in length, 6 ft in width, and 2 ft in height. 3,300 kg weight of the machine. This is the standard size. It can hold 4.5 tons of wet manure and 2.5-3 tons of dry manure. This machine is attached to a tractor and is controlled by a remote. Machines do not have many maintenance costs. Ashikbhai conducts feedback sessions with the consumers every week to keep track of the issues and setbacks of the machine, if any. The customers are delighted with the product as well as the services provided by the company. The machine was then able to spread both dry and wet manure on the field. This helps farmers in many ways, such as saving precious time, spreading manure uniformly over the field, and reducing labor expenses. The team has 24 people; they only make the Farmyard Manure Spreader machine and distribute it all over India. The cost of the machine is 6,50,000, with a gross margin of 30% and a net margin of 10%. Ashikbhai has applied for a subsidy, which is in the process; the machine has been tested and approved, so the certificate is in progress. With subsidies, their production will increase by 20%. He has successfully sold this manual spreader to many farmers and is getting queries from far and wide for his farm yard manure spreader', '{"innovator_name":"Ashikbhai Gani","location":"Banaskantha , Gujarat","detail_url":"https://gian.org/multilingual_data/farmyard-manure-distributor-in-the-field-by-ashikbhai-gani-gujarat/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('deepakbhai-patel-kutch-gujarat', 'Deepakbhai Patel', 'A grassroots innovator and an incubator of GIAN Deepakbhai Patel from Bharuch, Gujarat, has innovated a low-cost orchard sprayer for spraying pesticides and insecticides to the orchard plants. His innovation was guided and supported by GIAN and the Honey Bee Network. The innovation of this orchard sprayer is a boon for all the farmers involved in orchard farming. It is an active alternative to conventional techniques, and Deepakbhai has managed to sell his product to multiple cities. He has sold more than 90 units in the market till today and modifies the sprayer pump according to customers’ needs.', 'https://gian.org/multilingual_data/low-cost-orchard-sprayer-by-deepakbhai-patel-gujarat/', 'Kutch, Gujarat', null, 'Kutch , Gujarat', 'India', ARRAY['Kutch, Gujarat']::text[], ARRAY['orchard', 'device', 'farmer']::text[], 'https://gian.org/multilingual_data/low-cost-orchard-sprayer-by-deepakbhai-patel-gujarat/', 'Deepakbhai Patel', null, null, null, null, null, null, null, 'Kutch , Gujarat', 'https://gian.org/multilingual_data/low-cost-orchard-sprayer-by-deepakbhai-patel-gujarat/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/low-cost-orchard-sprayer-by-deepakbhai-patel-gujarat/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2022-03-30-at-18.01.34.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=pVYq30RSkBo"]'::jsonb, 23.368105, 70.1932084, 1, 'Deepakbhai Patel A grassroots innovator and an incubator of GIAN Deepakbhai Patel from Bharuch, Gujarat, has innovated a low-cost orchard sprayer for spraying pesticides and insecticides to the orchard plants. His innovation was guided and supported by GIAN and the Honey Bee Network. The innovation of this orchard sprayer is a boon for all the farmers involved in orchard farming. It is an active alternative to conventional techniques, and Deepakbhai has managed to sell his product to multiple cities. He has sold more than 90 units in the market till today and modifies the sprayer pump according to customers’ needs. Kutch, Gujarat orchard device farmer Low-Cost Orchard Sprayer by Deepakbhai Patel (Gujarat) While working as a technical person at a workshop of rewinding motors, Deepakbhai conversed with local farmers. During this conversation, he learned about farmers’ difficulties spraying pesticides in orchards. Also, it’s done manually by labor and has a high labor cost. He also discovered the unproductive method, shortage of labels, and lack of specialized devices cause high losses to farmers. Looking at these disadvantages, Deepakbhai developed a low-cost tractor-operated hybrid orchard sprayer. First, he made simple pumps, modified them to automatic pumps, and launched them in the market in 2012. The innovator prototyped the sprayer with a tractor of more than 20 HP and 3 HP pressure pumps used for spraying pesticide more efficiently onto the plants at 15 km/h. The drops of pesticides are converted to microparticles using a fan running at 450 to 550 RPM speeds. The range of spray is 1200 ft. The simple spray is 1000 liters, but mostly Anar Spray is more in demand. Simple pumps require ten days, and blower pumps require 15 days to manufacture. They use a high-quality reliance tank and Victor pump in the sprayer. Deepakbhai buys raw materials from Bhuj. This sprayer’s spraying capacity is 1 acre per hour for a specific pomegranate crop, which can vary depending on crop and planting pattern. The innovation was appreciated by many institutions and was used by local municipal corporations for sanitization during the COVID-19 pandemic', '{"innovator_name":"Deepakbhai Patel","location":"Kutch , Gujarat","detail_url":"https://gian.org/multilingual_data/low-cost-orchard-sprayer-by-deepakbhai-patel-gujarat/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mstongbram-bijayashanti-devi-bishnupur-manipur', 'Ms.Tongbram Bijayashanti Devi', 'A young, empowered innovator Bijayashanti Devi from Bishnupur in Manipur, extracts fibers from Lotus stems to make fabric. GIAN and the Honey Bee Network bolstered the innovation of silk from lotus stems under the MVIF scheme. Bijayashanti received aid from GIAN and Honey Bee Network to seek wider markets and online sales.', 'https://gian.org/multilingual_data/sanajing-sana-thambal/', 'Bishnupur, Manipur', null, 'Bishnupur , Manipur', 'India', ARRAY['Bishnupur, Manipur']::text[], ARRAY['weaving', 'health']::text[], 'https://gian.org/multilingual_data/sanajing-sana-thambal/', 'Ms.Tongbram Bijayashanti Devi', null, null, null, null, null, null, null, 'Bishnupur , Manipur', 'https://gian.org/multilingual_data/sanajing-sana-thambal/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/sanajing-sana-thambal/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/1603700382258_BijiyashantiDevi.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=0Ln_XwEbCPQ"]'::jsonb, 24.4528388, 93.8044831, 1, 'Ms.Tongbram Bijayashanti Devi A young, empowered innovator Bijayashanti Devi from Bishnupur in Manipur, extracts fibers from Lotus stems to make fabric. GIAN and the Honey Bee Network bolstered the innovation of silk from lotus stems under the MVIF scheme. Bijayashanti received aid from GIAN and Honey Bee Network to seek wider markets and online sales. Bishnupur, Manipur weaving health Sanajing Sana Thambal by Ms.Tongbram Bijayashanti Devi (Manipur) Talking about her idea and innovation. Bijayashanti Devi said, “in our village, there are no options to do work except fishing and farming. Many women cannot work in this field, so I thought of making textiles from Lotus Stem as it is available in abundance in Loktak lake.” In this process, the innovation breaks the lotus stem at the length of a thumb and pulls and expands the fiber from the lotus stem. Then, the fiber is hand rolled into its desired size using the wooden plank and palms. Using a loin loom, the fiber extracted from the lotus stems and stock is produced as yarns for weaving clothes, neckties, scarves, and mufflers. This innovation can potentially open new avenues in Lotus farming and textile along with female empowerment. Clothes made out of lotus stem fibers have health benefits, but as it is labor-intensive work, it is very costly and hence, highly in demand in foreign countries than in local markets', '{"innovator_name":"Ms.Tongbram Bijayashanti Devi","location":"Bishnupur , Manipur","detail_url":"https://gian.org/multilingual_data/sanajing-sana-thambal/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('janakbhai-rathod-surendranagar-gujarat', 'Janakbhai Rathod', 'Janakbhai Rathod, an enthusiastic farmer and innovator, created a destoner machine to separate the soil and other pebbles attached to the ground nut pods. His innovation was funded and supported during the COVID-19 pandemic by GIAN and the Honey Bee Network under MVIF in assistance with SIDBI.', 'https://gian.org/multilingual_data/destoner-machine-by-janakbhai-rathod-gujarat/', 'Surendranagar, Gujarat', null, 'Surendranagar , Gujarat', 'India', ARRAY['Surendranagar, Gujarat']::text[], ARRAY['machine', 'device', 'farmer']::text[], 'https://gian.org/multilingual_data/destoner-machine-by-janakbhai-rathod-gujarat/', 'Janakbhai Rathod', null, null, null, null, null, null, null, 'Surendranagar , Gujarat', 'https://gian.org/multilingual_data/destoner-machine-by-janakbhai-rathod-gujarat/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/destoner-machine-by-janakbhai-rathod-gujarat/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Ambika-janakbhai-rathod-.png"]'::jsonb, '["https://www.youtube.com/watch?v=hEBL8VZq6VE"]'::jsonb, 22.9403063, 71.1448516, 1, 'Janakbhai Rathod Janakbhai Rathod, an enthusiastic farmer and innovator, created a destoner machine to separate the soil and other pebbles attached to the ground nut pods. His innovation was funded and supported during the COVID-19 pandemic by GIAN and the Honey Bee Network under MVIF in assistance with SIDBI. Surendranagar, Gujarat machine device farmer Destoner Machine by Janakbhai Rathod (Gujarat) At the time of groundnut harvesting, the soil clods, small stones, and other materials from the earth are anchored to the pods. Clearing this manually takes time, and good results are not obtained. To overcome this setback, Janakbhai developed a destoner machine to separate soil and other materials attached to the pods. This device can clean soil from 120 to 140 kg of ground nuts in just 1 hour. It consumes just 2 to 2.5 l of diesel per hour. It does not require any parts replacement and hence has low maintenance. It needs to be greased regularly and can be attached to a tractor. It can also be carried anywhere. This device cleans the pods properly without any damage to the seeds and hence helps farmers to get good rates of ground nuts. Janakbhai has produced and sold many destoner machines so far. His innovation was recognized by many farmers and was appreciated. He also presented his innovation at IIC’s People’s Festival of Innovation through GIAN.', '{"innovator_name":"Janakbhai Rathod","location":"Surendranagar , Gujarat","detail_url":"https://gian.org/multilingual_data/destoner-machine-by-janakbhai-rathod-gujarat/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('bharatbhai-agrawat-junagadh-gujarat', 'Bharatbhai Agrawat', 'Serial innovator Bharatbhai Agrawat from Gujarat has developed a solar weeder and seed drill machine. His innovation was appreciated and supported by GIAN and the Honey Bee Network. This innovation is a boon to many small to medium-scale farmers around the globe, and hence the drill and weeder technology was transferred to Kenya by the Honey Bee Network, GIAN, and SRISTI under the USAID project. Following his father’s footsteps, Bharatbhai has sold many of his solar weeder and sea drills to needy farmers. The innovation is a success. Apart from this, he also prototyped a diesel-operated tractor. Bharatbhai is very motivated and likes to spend most of his time innovating new technologies.', 'https://gian.org/multilingual_data/solar-weeder-and-seed-drill-by-bharatbhai-agrawat-gujarat/', 'Junagadh, Gujarat', null, 'Junagadh , Gujarat', 'India', ARRAY['Junagadh, Gujarat']::text[], ARRAY['solar', 'machine', 'device', 'farmer']::text[], 'https://gian.org/multilingual_data/solar-weeder-and-seed-drill-by-bharatbhai-agrawat-gujarat/', 'Bharatbhai Agrawat', null, null, null, null, null, null, null, 'Junagadh , Gujarat', 'https://gian.org/multilingual_data/solar-weeder-and-seed-drill-by-bharatbhai-agrawat-gujarat/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/solar-weeder-and-seed-drill-by-bharatbhai-agrawat-gujarat/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Solar-Weeder-and-seed-drill-Bharatbhai-Agrawat-1.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=1pk-I2mTp0U"]'::jsonb, 21.1751921, 70.3598758, 1, 'Bharatbhai Agrawat Serial innovator Bharatbhai Agrawat from Gujarat has developed a solar weeder and seed drill machine. His innovation was appreciated and supported by GIAN and the Honey Bee Network. This innovation is a boon to many small to medium-scale farmers around the globe, and hence the drill and weeder technology was transferred to Kenya by the Honey Bee Network, GIAN, and SRISTI under the USAID project. Following his father’s footsteps, Bharatbhai has sold many of his solar weeder and sea drills to needy farmers. The innovation is a success. Apart from this, he also prototyped a diesel-operated tractor. Bharatbhai is very motivated and likes to spend most of his time innovating new technologies. Junagadh, Gujarat solar machine device farmer Solar Weeder and seed drill by Bharatbhai Agrawat (Gujarat) As a farmer, Bharatbhai always had a soft spot for small-scale farmers who struggled due to a lack of high-technology equipment. When he observed that the manual method of seed plantation and weeding resulted in the irregular placement of seeds, efficient spacing, and fatigue for the area sown, he decided to make a seed sowing and weeding machine to reduce the drudgery involved. He made a manual cycle sowing and weeding machine which helps overcome the downsides of manual seeding. He sold more than 6000 units of this manual machine. Then after getting feedback from local farmers who used his product, he decided to attach a battery and solar panel to make the machine auto-operated and an easy-to-use eco-friendly device. In one charging, the machines can work on 2 acres. The labor cost would be Rs 5000; even if a tractor were used, the price would be around 1200. In the battery unit, it takes 2 unit expenses (“Rs 16) with one labor (cost Rs 500). The machine size is small and portable. It is very effective in intercrop farming. He sold a total of 6 battery-operated seed drills and a weeder. All products were made while researching, and he has not started mass production. The hand-operated weeder is sold at Rs 1100, the hand-operated seed driller costs Rs 3000, and the battery-operated seeder/weeder/trolly’s selling price is Rs 38,000. His company also collaborates with Universities and students to make a working model of a prototype. Bharatbhai’s innovative drill and weeder are self-selling; hence, several units of this device have already been sold. Also, the innovator has one community fabrication lab supported by NIFIndia.org. He also displayed his innovation at IIC’s People’s Innovation Festival in Delhi. He has also received the Life Time Achievement Award from Pratibha Patil and Pranab Mukherjee', '{"innovator_name":"Bharatbhai Agrawat","location":"Junagadh , Gujarat","detail_url":"https://gian.org/multilingual_data/solar-weeder-and-seed-drill-by-bharatbhai-agrawat-gujarat/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('rajkumar-rathore-sehore-madhya-pradesh', 'Rajkumar Rathore', 'Rajkumar Rathore, a progressive innovator who studied up to the 12th standard from Sehore Madhya Pradesh, developed a variety of persistent pigeon pea that provides good yield and has bushy growth. The registration application was filed by GIAN on behalf of the innovator under PPV and FRA with the help of NIF. GIAN and the Honey Bee Network helped capitalize on the innovation under MVIF. Rathore owns 18 acres of land, of which one acre is dedicated especially to pigeon pea seed production, and today with his innovation, he managed to help plenty of farmers.', 'https://gian.org/multilingual_data/richa-2000/', 'Sehore, Madhya Pradesh', null, 'Sehore , Madhya Pradesh', 'India', ARRAY['Sehore, Madhya Pradesh']::text[], ARRAY['farmer']::text[], 'https://gian.org/multilingual_data/richa-2000/', 'Rajkumar Rathore', null, null, null, null, null, null, null, 'Sehore , Madhya Pradesh', 'https://gian.org/multilingual_data/richa-2000/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/richa-2000/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/IMG-20231129-WA0012-scaled.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=YYKocc0ep6o"]'::jsonb, 23.1774034, 77.0564464, 1, 'Rajkumar Rathore Rajkumar Rathore, a progressive innovator who studied up to the 12th standard from Sehore Madhya Pradesh, developed a variety of persistent pigeon pea that provides good yield and has bushy growth. The registration application was filed by GIAN on behalf of the innovator under PPV and FRA with the help of NIF. GIAN and the Honey Bee Network helped capitalize on the innovation under MVIF. Rathore owns 18 acres of land, of which one acre is dedicated especially to pigeon pea seed production, and today with his innovation, he managed to help plenty of farmers. Sehore, Madhya Pradesh farmer RICHA 2000 Once when Rathore was on a routine round on his pigeon pea field, one distinctive plant attracted his attention. Features that made this plant unique were: two colored bigger flowers than normal plants, longer leaves, and a lavish green plant that remained greener for a longer period. Observing these unique features, he decided to increase the yield of this plant by optimizing the number of branches and increasing the pod bearings. After inspecting and analyzing the plant, he collected the seeds and harvested them separately the next season to keep note of the growth and distinct characteristics of the plants. Henceforth, the variety of unique pigeon peas was fascinating in 2000. Rathore named his innovation after his daughter ‘Richa 2000’. This distinctive pigeon pea seed is a perennial variety and can be harvested twice a year. It gives more pods per plant and a high 18-24 q/ac yield. They contain more seeds per pod and are disease tolerant. With support from GIAN and the Honey Bee Network, the ‘Richa 2000’ has been disseminated to Gujarat, Madhya Pradesh, Karnataka, Tamil Nadu, Chhattisgarh, Orissa, Telangana, and Andhra Pradesh, and Maharashtra farmers. Rajkumar and his innovation were appreciated at the state and national levels. He was awarded at the 4th National Grassroots Innovation Awards. At different events, our former presidents Dr. A P J Abdul Kalam, Pratibha Patil, and Pranab Mukharji, honored him.', '{"innovator_name":"Rajkumar Rathore","location":"Sehore , Madhya Pradesh","detail_url":"https://gian.org/multilingual_data/richa-2000/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('sundaram-verma-sikar-rajasthan', 'Sundaram Verma', 'Shri Sundaram Verma, an Indian environmentalist from the village of Sikar, Rajasthan, studied dryland farming at the Indian Agricultural Research Institution, New Delhi. After graduation, he innovated a dryland agroforestry technique for arid and semi-arid regions. Using this technique, all kinds of trees can be planted with an 80% survival rate of plants with just 1 l of water throughout the plant’s lifetime. Sundaram Verma has been a dedicated collaborator of GIAN and the Honey Bee Network and has helped scout other grassroots innovators. Using his dryland agroforestry technique, he has planted over 50,000 trees in the arid region of Shekhawati located in Rajasthan.', 'https://gian.org/multilingual_data/dryland-agroforestry/', 'Sikar, Rajasthan', null, 'Sikar , Rajasthan', 'India', ARRAY['Sikar, Rajasthan']::text[], ARRAY['tree', 'water', 'farmer']::text[], 'https://gian.org/multilingual_data/dryland-agroforestry/', 'Sundaram Verma', null, null, null, null, null, null, null, 'Sikar , Rajasthan', 'https://gian.org/multilingual_data/dryland-agroforestry/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/dryland-agroforestry/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/sundaram-varma.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=QN-MJG7WA_8"]'::jsonb, 27.2961064, 75.2245693, 1, 'Sundaram Verma Shri Sundaram Verma, an Indian environmentalist from the village of Sikar, Rajasthan, studied dryland farming at the Indian Agricultural Research Institution, New Delhi. After graduation, he innovated a dryland agroforestry technique for arid and semi-arid regions. Using this technique, all kinds of trees can be planted with an 80% survival rate of plants with just 1 l of water throughout the plant’s lifetime. Sundaram Verma has been a dedicated collaborator of GIAN and the Honey Bee Network and has helped scout other grassroots innovators. Using his dryland agroforestry technique, he has planted over 50,000 trees in the arid region of Shekhawati located in Rajasthan. Sikar, Rajasthan tree water farmer Dryland agroforestry Growing up in an arid region of Rajasthan, Sundaram realized the value of agroforestry plantations. The survival rate in arid and semi-arid regions sapling is just 35%. The agroforestry in the dryland region augments farmers’ income and induces climate resilience. The dryland agroforestry technique by Sundaram Verma involves plowing the field up to one foot deep before the rains. The field is planked and pressed to break the capillaries after the rain. The rainwater has charged the soil, so it cannot evaporate easily. A 6 ft deep pit is made to sow the seeds, which are then covered with soil and water (one liter) in October-November. The idea behind this is that these trees will have to send roots deeper as there is no moisture in the upper layer of soil like in monsoon. This technique utilizes just 1 l of water; it is the best-suited method for water conservation in arid and semi-arid regions, along with avenues of agroforestry landing to land management and revenue generation. Apart from this amazing innovation, he pursued many other advancements in rainwater conservation in farming and evaluating crop varieties from Chili, mung beans, chickpeas, cluster beans, etc. In 2021, he was honored with Padmashree, among countless other awards.', '{"innovator_name":"Sundaram Verma","location":"Sikar , Rajasthan","detail_url":"https://gian.org/multilingual_data/dryland-agroforestry/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('godasu-narsimha-nalgonda-telangana', 'Godasu Narsimha', 'Narsimha, an innovator, a teacher, and a fisherman from Nalgonda, Andhra Pradesh, developed a hyacinth remover machine to help the fishing community and transform the ecosystem. His innovation was supported and directed by GIAN and the Honey Bee Network Narsimha’s innovation is a blessing for the ecosystem and the fishing community; he has sold many machines.', 'https://gian.org/multilingual_data/hyacinth-remover-machine/', 'Nalgonda, Telangana', null, 'Nalgonda , Telangana', 'India', ARRAY['Nalgonda, Telangana']::text[], ARRAY['machine', 'health', 'water']::text[], 'https://gian.org/multilingual_data/hyacinth-remover-machine/', 'Godasu Narsimha', null, null, null, null, null, null, null, 'Nalgonda , Telangana', 'https://gian.org/multilingual_data/hyacinth-remover-machine/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/hyacinth-remover-machine/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Narsinha.png"]'::jsonb, '["https://www.youtube.com/watch?v=D6mgI9k1ucg"]'::jsonb, 17.3413528, 78.8042828, 1, 'Godasu Narsimha Narsimha, an innovator, a teacher, and a fisherman from Nalgonda, Andhra Pradesh, developed a hyacinth remover machine to help the fishing community and transform the ecosystem. His innovation was supported and directed by GIAN and the Honey Bee Network Narsimha’s innovation is a blessing for the ecosystem and the fishing community; he has sold many machines. Nalgonda, Telangana machine health water Hyacinth Remover machine Narsimha, a humble man from the fishing community, noticed the problem and labor involved in removing hyacinth (unwanted weed) from the water. Due to excessive hyacinth growth, the fish’s health is affected, and fishermen need to spend many rupees on the removal; the health of the fishermen involved in removal is also affected. Narsimha used a 5 HP motor and eight cutters to design the hyacinth machine that cuts the hyacinth into small 3 to 4-inch pieces and then flows down with the downstream water. For larger water bodies, he modified the machine by attaching the conveyor belt that transfers the cut pieces of hyacinth to the truck and transports them for disposal. This innovative technology can compel the remover using only 8000 to 10000 rupees and a minimum number of men’s power which is approximately one-third the cost of the manual method. The Hyderabad Municipal Corporation appreciated the innovation and was used to clean its bodies of water. The machine was exported to Lake Victoria through GIAN, the Honey Bee Network, and MEA. Also, Narsimha was able to represent his innovation at various places, including LBSNAA and Rashtrapati Bhavan', '{"innovator_name":"Godasu Narsimha","location":"Nalgonda , Telangana","detail_url":"https://gian.org/multilingual_data/hyacinth-remover-machine/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('amit-doshi-gandhinagar-gujarat', 'Amit Doshi', 'Innovator Amit Doshi from Gandhinagar, Gujarat, was appreciated and supported by GIAN and the Honey Bee Network for entrepreneur development and feedback for improved technology for his rainwater harvesting system. Amit quit his well-paid corporate job in the waste management sector to jump into sustainable technology to make a difference. Today he has a successful startup company YIM NeeRain Pvt. ltd, that saves around 60,000 liters of water by rainwater harvesting.', 'https://gian.org/multilingual_data/neerain-private-limited/', 'Gandhinagar Gujarat', null, 'Gandhinagar Gujarat', 'India', ARRAY['Gandhinagar Gujarat']::text[], ARRAY['device', 'water']::text[], 'https://gian.org/multilingual_data/neerain-private-limited/', 'Amit Doshi', null, null, null, null, null, null, null, 'Gandhinagar Gujarat', 'https://gian.org/multilingual_data/neerain-private-limited/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/neerain-private-limited/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Neerain-Amit-Doshi.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=NWD_hIwS8-w"]'::jsonb, 23.1077747, 72.6397984, 1, 'Amit Doshi Innovator Amit Doshi from Gandhinagar, Gujarat, was appreciated and supported by GIAN and the Honey Bee Network for entrepreneur development and feedback for improved technology for his rainwater harvesting system. Amit quit his well-paid corporate job in the waste management sector to jump into sustainable technology to make a difference. Today he has a successful startup company YIM NeeRain Pvt. ltd, that saves around 60,000 liters of water by rainwater harvesting. Gandhinagar Gujarat device water NeeRain Private Limited After quitting his corporate job, Amit Doshi diligently sought a startup idea. He researched for a while in different fields of sustainable environment, but the only proposal that left an impression on his mind was rainwater harvesting. After learning about the problems the government and local people faced in water conservation, he developed a product that could resolve all the issues and gaps of conventional water harvesting systems. Succeeding in research, creativity, and hard work, Amit closed in with a tangible solution of affordable and maintenance-free Rainwater harvesting. He successfully launched his startup NeeRain Pvt. Ltd in the year 2018. The NeeRain water harvesting device overcomes all the issues related to traditional water harvesting systems, such as simple and easily installable devices, cost-effectiveness, and minimum to no maintenance. The NeeRain system is a portable device that can be attached to the pipes collecting water from the rooftop and further channelizing it to the ground. It is a two-stage filtration process in which fresh, clean, and pure rainwater is collected when it passes out of the filtration system. NeeRain has created awareness about the global water crises and empowered the common people to live water-secure lives. Amit’s NeeRain device has won awards at different levels, including CII’s National Award for Excellence in Water Management in the innovative water-saving product category.', '{"innovator_name":"Amit Doshi","location":"Gandhinagar Gujarat","detail_url":"https://gian.org/multilingual_data/neerain-private-limited/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('subhash-ola-alwar-rajasthan', 'Subhash Ola', 'The innovator, Subhash from Alwar Rajasthan, was scouted by Swabhiman, a volunteer at the Honey Bee Network. Subhash modified a boiler used in conventional mawa-making machines and made it energy-efficient. His innovation was guided and carried forward by GIAN and the Honey Bee Network, who also helped with the marketing and funding, along with NIF. Apart from helping his father with drilling bore wells and farming Subhash was a steam energy enthusiast. In different parts of North India, he sold around 60 machines and started his own startup company. Today, he makes machines with different capacities according to customers’ demands.', 'https://gian.org/multilingual_data/modified-boiler-based-mawa-maker/', 'Alwar, Rajasthan', null, 'Alwar , Rajasthan', 'India', ARRAY['Alwar, Rajasthan']::text[], ARRAY['machine', 'water']::text[], 'https://gian.org/multilingual_data/modified-boiler-based-mawa-maker/', 'Subhash Ola', null, null, null, null, null, null, null, 'Alwar , Rajasthan', 'https://gian.org/multilingual_data/modified-boiler-based-mawa-maker/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/modified-boiler-based-mawa-maker/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/subhash-ola-Modified-boiler-based-mawa-maker.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=Nk8WzkL5h6w"]'::jsonb, 27.5993852, 76.8490328, 1, 'Subhash Ola The innovator, Subhash from Alwar Rajasthan, was scouted by Swabhiman, a volunteer at the Honey Bee Network. Subhash modified a boiler used in conventional mawa-making machines and made it energy-efficient. His innovation was guided and carried forward by GIAN and the Honey Bee Network, who also helped with the marketing and funding, along with NIF. Apart from helping his father with drilling bore wells and farming Subhash was a steam energy enthusiast. In different parts of North India, he sold around 60 machines and started his own startup company. Today, he makes machines with different capacities according to customers’ demands. Alwar, Rajasthan machine water Modified Boiler-based Mawa Maker When Subhash was trying to design an improved boiler, he visited an industry in Jaipur where he saw a boiler-based mawa-making machine. He was flustered after knowing that the amount of wood and water consumed to make mawa is 100 kg and 4000 liters, respectively. This much fuel extracts mawa from 100 lit of milk. It also consumed a hefty amount of electricity, thus making the whole process very costly. Knowing this, he started modifying the boiler design used in mawa making. After ten years of hard work, Subhash successfully developed the enhanced version of a boiler-based machine for making mawa. In this mawa maker, the steam circuit (boiler, kadai, condenser, pipe) is made with a closed leakproof design, improving fuel efficiency and minimal wastage. It is leakproof and hence requires no additional water. It has automated boiler operation and automatic steering operation, reducing wood consumption and labor work. The boiler-based mawa-making machine was awarded at the national level in the 8th National Grassroots Innovation Awards 2015. He won the first prize in the Amazon Sambhav Entrepreneurship Challenge 2022; also, his startup was awarded the Startup of the Year award. He received the 8th Biennial National Grassroots Innovation and Outstanding Traditional Knowledge award in 2015. He was also invited to be a part of the fourth batch of innovation scholars in the residence program of the Rashtrapati Bhavan', '{"innovator_name":"Subhash Ola","location":"Alwar , Rajasthan","detail_url":"https://gian.org/multilingual_data/modified-boiler-based-mawa-maker/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mansukhbhai-jagani-amreli-gujarat', 'Mansukhbhai Jagani', 'A hard-working innovator Mansukhbhai Jagani, who left school early, a native of Amreli, Gujarat, innovated a portable tractor from a Bullet motorcycle that can be used in agriculture for diverse amounts of farm work. He also innovated many different equipment used in farming for assorted work disciplines and started a workshop of his products known today as Jai Khodiyar Welding Works. GIAN and the Honey Bee Network were the key supporters of the innovator. Prof. Anil Gupta helped Mansukhbhai file a patent for his prototype in India and the USA with the help of NIF. GIAN supported the innovation with all the hardships faced in the market. From a small agriculture equipment repair workshop, Mansukhbhai owns the reputed workshop, Jai Khodiyar Welding Works. He has sold more than 1500 Bullet Santi along with his other innovative Agri-devices.', 'https://gian.org/multilingual_data/bullet-santi/', 'Amreli, Gujarat', null, 'Amreli , Gujarat', 'India', ARRAY['Amreli, Gujarat']::text[], ARRAY['agriculture', 'device', 'farmer']::text[], 'https://gian.org/multilingual_data/bullet-santi/', 'Mansukhbhai Jagani', null, null, null, null, null, null, null, 'Amreli , Gujarat', 'https://gian.org/multilingual_data/bullet-santi/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/bullet-santi/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-18.23.40-Copy.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=d7lBF1irqWs"]'::jsonb, 21.8662172, 71.1686168, 1, 'Mansukhbhai Jagani A hard-working innovator Mansukhbhai Jagani, who left school early, a native of Amreli, Gujarat, innovated a portable tractor from a Bullet motorcycle that can be used in agriculture for diverse amounts of farm work. He also innovated many different equipment used in farming for assorted work disciplines and started a workshop of his products known today as Jai Khodiyar Welding Works. GIAN and the Honey Bee Network were the key supporters of the innovator. Prof. Anil Gupta helped Mansukhbhai file a patent for his prototype in India and the USA with the help of NIF. GIAN supported the innovation with all the hardships faced in the market. From a small agriculture equipment repair workshop, Mansukhbhai owns the reputed workshop, Jai Khodiyar Welding Works. He has sold more than 1500 Bullet Santi along with his other innovative Agri-devices. Amreli, Gujarat agriculture device farmer Bullet Santi Jagani belonged to a poor farmer’s family and tried different work at a very young age to fulfil his family’s needs. At last, he started a small workshop in his village and helped farmers by repairing different agricultural equipment. Once there was a drought in his village, and the agriculture and farmers suffered a lot; hence, many farmers sold their bullocks as it was hard to feed them. During all of these, he met one of his friends who sold his bullocks and needed an alternative to continuing his farming. At that time, Mansukhbhai considered converting a Bullet into a farm tractor, bought a second-hand bullet, and converted it into portable agricultural equipment. This was a success for different agricultural activities. The Bullet Santi can plow about 2 acres using one litre of diesel. Also, the distance between the rear wheels can be adjusted per crop spacing. There was a provision for a plow lifting mechanism and reverse gears for easier field operations. It is an all-in-one agricultural device smaller than tillers and tractors but stronger than draft animals. Very few are efficient and easy to handle and operate. It can be dismantled and again reused as a motorbike. As it is lighter than a tractor, it prevents soil compaction. He prototyped equipment such as an adjustable spraying device, seeding device, fertilisers, sprayers, and welding device that can all be attached to the Bullet Santi. After the year 2000, he faced problems in getting bullets to modify, and hence, he developed his automobile from the engine to attachments known as “Sanedo”. Today he manufactures his automobile of different HP capacities from scratch and sells it all over Gujarat and Kenya. “Sanedo” is available in three-wheel and four-wheel configurations as the customer requires. Mansukhbhai’s innovation became popular in India and South Africa, and farmers in South Africa appreciated the device. He was awarded a national award in the 1st National Grassroots Innovation Awards in 2001. He was invited by Jomo Kenyatta University in Kenya and South Africa. His company is government-approved, and soon farmers can access a subsidiary to purchase his product. His new upgraded version of the Bullet Santi, locally known as “Sanedo,” is a patented product, and he has a manufacturing capacity of around 1000 units. Today his innovation helps many farmers continue farming, even if they cannot afford a tractor', '{"innovator_name":"Mansukhbhai Jagani","location":"Amreli , Gujarat","detail_url":"https://gian.org/multilingual_data/bullet-santi/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('arjunbhai-paghdhar-junagadh-gujarat', 'Arjunbhai Paghdhar', 'A 56-year-old farmer turned innovator constructed a modified wood-based, culturally accepted crematorium that can save around 40 acres of forest daily. GIAN and the Honey Bee Network supported the innovation to appreciate people’s environmentally friendly approaches and perspectives. Arjunbhai’s innovation was culturally accepted and was set up in different rural areas of Gujarat. It is an environmentally friendly crematorium service innovated without hurting religious aspirations. This innovation won a state-level award at the 10th National Grassroots Innovation awards 2019. Arjunbhai also received an Outstanding Traditional Knowledge award in 2019. The Gujarat energy development agency funded him to upgrade his model. Also, the government set up his crematorium in Veraval, Gir-Somnath district, Gujarat', 'https://gian.org/multilingual_data/modified-wood-based-culturally-accepted-crematorium/', 'Junagadh Gujarat', null, 'Junagadh Gujarat', 'India', ARRAY['Junagadh Gujarat']::text[], ARRAY['tree', 'farmer']::text[], 'https://gian.org/multilingual_data/modified-wood-based-culturally-accepted-crematorium/', 'Arjunbhai Paghdhar', null, null, null, null, null, null, null, 'Junagadh Gujarat', 'https://gian.org/multilingual_data/modified-wood-based-culturally-accepted-crematorium/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/modified-wood-based-culturally-accepted-crematorium/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-15.14.33.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=EC5nziBHKtI"]'::jsonb, 21.2890443, 70.1693949, 1, 'Arjunbhai Paghdhar A 56-year-old farmer turned innovator constructed a modified wood-based, culturally accepted crematorium that can save around 40 acres of forest daily. GIAN and the Honey Bee Network supported the innovation to appreciate people’s environmentally friendly approaches and perspectives. Arjunbhai’s innovation was culturally accepted and was set up in different rural areas of Gujarat. It is an environmentally friendly crematorium service innovated without hurting religious aspirations. This innovation won a state-level award at the 10th National Grassroots Innovation awards 2019. Arjunbhai also received an Outstanding Traditional Knowledge award in 2019. The Gujarat energy development agency funded him to upgrade his model. Also, the government set up his crematorium in Veraval, Gir-Somnath district, Gujarat Junagadh Gujarat tree farmer Modified Wood-Based, Culturally Accepted Crematorium Arjunbhai Paghdhar belonged to a farmer’s family and is now engaged in the construction and brick-making business. Long ago, when he visited the crematorium, he saw precious wood burned to cremate the body. Through this, an indelible impact was made on the mind of a young tree lover. This inspired him to create something that can save trees and forests from being burned in cremation, as according to the Hindu rituals, the funeral is by cremation, and about 400 kg of wood is used to cremate a single body. The modified wood-based crematorium innovated by Arjunbhai is a biomass gasification-based cremation process. A closed mummy shape is made of refractory bricks to ensure minimum heat loss. At the front and rear ends of the structure, doors are provided to perform Hindu rituals. Cerra wool is used on the top cover’s inner side, which can tolerate high temperatures. Blowers and nozzles are attached to release air to accelerate the cremation process. Along with this, charcoal and caustic soda filters have been provided for air filtration. Also, a chimney is provided for the air exhaust. This innovation takes an average time of 70 to 90 minutes to burn a dead body (approx. 80kg weight) using around 70 to 80 kg of wood, which is approximately 80% less wood than that used in a conventional method.', '{"innovator_name":"Arjunbhai Paghdhar","location":"Junagadh Gujarat","detail_url":"https://gian.org/multilingual_data/modified-wood-based-culturally-accepted-crematorium/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('arvindbhai-patel-ahmedabad-gujarat', 'Arvindbhai Patel', 'Arvindbhai Patel once had a high fever, so his wife repeatedly applied a cold press to his forehead to keep his temperature down. While in the throes of the fever, Patel’s brain clicked with the idea of developing a water cooler using the same principle of temperature to cool water without electricity. Based on the principle of heat exchange, Arvindbhai Patel’s innovation is an energy-efficient, environment-friendly, and low-cost water cooler that cools water naturally without using any non-renewable source. Primitively, the cooler was available in three different capacities that were 5, 10, and 15. Whereas now they manufacture only 100- and 150-liter capacity coolers. He received recognition for his environmentally friendly innovation from Indian Science, Technology, and Innovation. He was also awarded the 7th National Biennial Award in 2013.', 'https://gian.org/multilingual_data/natural-water-cooler/', 'Ahmedabad, Gujarat', null, 'Ahmedabad , Gujarat', 'India', ARRAY['Ahmedabad, Gujarat']::text[], ARRAY['water']::text[], 'https://gian.org/multilingual_data/natural-water-cooler/', 'Arvindbhai Patel', null, null, null, null, null, null, null, 'Ahmedabad , Gujarat', 'https://gian.org/multilingual_data/natural-water-cooler/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/natural-water-cooler/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Arvindbhai-patel-scaled.png"]'::jsonb, '["https://www.youtube.com/watch?v=nAu-PIc5xAU"]'::jsonb, 22.9984497, 72.6111939, 1, 'Arvindbhai Patel Arvindbhai Patel once had a high fever, so his wife repeatedly applied a cold press to his forehead to keep his temperature down. While in the throes of the fever, Patel’s brain clicked with the idea of developing a water cooler using the same principle of temperature to cool water without electricity. Based on the principle of heat exchange, Arvindbhai Patel’s innovation is an energy-efficient, environment-friendly, and low-cost water cooler that cools water naturally without using any non-renewable source. Primitively, the cooler was available in three different capacities that were 5, 10, and 15. Whereas now they manufacture only 100- and 150-liter capacity coolers. He received recognition for his environmentally friendly innovation from Indian Science, Technology, and Innovation. He was also awarded the 7th National Biennial Award in 2013. Ahmedabad, Gujarat water Natural Water Cooler A 57-year-old serial innovator, Arvindbhai Patel, from Vanch Ahmedabad, Gujarat, has many innovations in his name. GIAN and the Honey Bee Network facilitated a few. GIAN guided and supported his innovation of a natural water cooler; he acquired a patent for this innovation which GIAN assisted under the micro venture innovation fund (MVIF) of NIF for the commercialization of the new innovative technology. GIAN West facilitated the technology transfer of this natural cooler to entrepreneurs. Due to financial constraints, Arvindbhai Patel had to cease his formal education after the 10th grade. Still, his passion for innovation took him to the next level. Today, he has innovated a series of amazing prototypes, such as the Auto Air Kick Pump and Auto Compression Sprayer, which also added technology licenses to his name.', '{"innovator_name":"Arvindbhai Patel","location":"Ahmedabad , Gujarat","detail_url":"https://gian.org/multilingual_data/natural-water-cooler/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('smt-santosh-pachar-sikar-rajasthan', 'Smt. Santosh Pachar', 'A female farmer who studied until the 8th standard had a keen interest in farming, leading her to innovate the new carrot variety SPL-101. Today with her hard work and support from GIAN, she sells carrot seeds in 20 different states of India. Smt. Santosh also received inquiries from Nepal and South Africa, where she will start exporting the seeds soon.', 'https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/', 'Sikar, Rajasthan', null, 'Sikar , Rajasthan', 'India', ARRAY['Sikar, Rajasthan']::text[], ARRAY['farmer']::text[], 'https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/', 'Smt. Santosh Pachar', null, null, null, null, null, null, null, 'Sikar , Rajasthan', 'https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Smt.-Santosh-Pachar.png"]'::jsonb, '["https://www.youtube.com/watch?v=Q9kxZDRi8m4"]'::jsonb, 27.6683917, 75.1662121, 1, 'Smt. Santosh Pachar A female farmer who studied until the 8th standard had a keen interest in farming, leading her to innovate the new carrot variety SPL-101. Today with her hard work and support from GIAN, she sells carrot seeds in 20 different states of India. Smt. Santosh also received inquiries from Nepal and South Africa, where she will start exporting the seeds soon. Sikar, Rajasthan farmer Improved variety of carrots (Laxmangarh Selection) Sixteen years ago, Santosh Pachar bought some carrots for home consumption from a farmer named Mahavir from Laxmangarh Tehsil. The forked roots of carrots were very small, and the carrots were very good in appearance and taste. She admired the quality of carrots and wanted to cultivate such improved carrots on her farm. She adopted the route-to-seed methodology of planting at her farm to produce the seeds of the above-mentioned carrot. The selection standard of carrot for seed was sweetness, long route length, vermilion color, and softness. From the first year of the plantation, she collected the seeds, sowed them again in a small area of the field, and continuously adopted the same standard of selection method for 4 to 5 years. This was useful in stabilizing the desirable characteristics of the improvised carrots. Instead of conventional insecticides and pesticides, she used neem oil to control insects, pests, and diseases in her field.Her improved variety of seeds is well adapted to high temperatures. The length of her carrot is up to 1.5 ft, with a very low percentage of forked roots. It takes around 2.5 to 3 months to be completely ready and is resistant to any pest and disease attack. It yields almost 630qt/ha and is less hairy. It’s the best quality carrots containing a sweet taste which fetch high market price due to its quality.Smt. Santosh Pachar received recognition, selection in the residence program of Rashtrapati Bhavan, and a national award at the 7th National Grassroots Innovation Awards.', '{"innovator_name":"Smt. Santosh Pachar","location":"Sikar , Rajasthan","detail_url":"https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('shazia-jan-ananthnag-jammu-kashmir', 'Shazia Jan', 'Young innovator Mrs. Shazia Jan, from Jammu and Kashmir, modified a traditional samovar to a modern gas Samovar, recognized and further supported by GIAN cell Jammu and Kashmir along with the Honey Bee Network. A patent was filed in her name by NIF, and the future optimization and designing, along with safety aspects, was taken care of by GIAN cell Jammu and Kashmir.', 'https://gian.org/multilingual_data/gas-samovar/', 'Ananthnag, Jammu & Kashmir', null, 'Ananthnag , Jammu & Kashmir', 'India', ARRAY['Ananthnag, Jammu & Kashmir']::text[], ARRAY['safety', 'farmer']::text[], 'https://gian.org/multilingual_data/gas-samovar/', 'Shazia Jan', null, null, null, null, null, null, null, 'Ananthnag , Jammu & Kashmir', 'https://gian.org/multilingual_data/gas-samovar/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/gas-samovar/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Shazia-jan-.png"]'::jsonb, '["https://www.youtube.com/watch?v=Eo7cL2vHcNo"]'::jsonb, 33.5375562, 75.1311874, 1, 'Shazia Jan Young innovator Mrs. Shazia Jan, from Jammu and Kashmir, modified a traditional samovar to a modern gas Samovar, recognized and further supported by GIAN cell Jammu and Kashmir along with the Honey Bee Network. A patent was filed in her name by NIF, and the future optimization and designing, along with safety aspects, was taken care of by GIAN cell Jammu and Kashmir. Ananthnag, Jammu & Kashmir safety farmer Gas Samovar A traditional Kashmiri kettle used to boil, brew and serve tea is known as a ‘Samovar’, which uses coal as fuel. As the youngest child in a farmer’s family, Shazia prepared and carried the Samovar to her father and brother in the field. Using it regularly, she realized the problems associated with handling it. It was a lot of effort to get one cup of Namkeen tea. Using coal as fuel in the traditional Samovar is time-consuming, produces a lot of ashes, irritates the eye, causes black patches on hands and clothes, and many other problems.Mrs. Shazia Jan devised a design to use LPG as fuel in a Samovar and proposed her design to her father. There was no one to make modified burners and regulators for the samovar even though the concept and design were ready. Unable to find a suitable vendor, Shazia decided to proceed independently. After numerous attempts, she worked on the burner, developed a curved burner, and successfully designed and modified the traditional samovar with the LPG samovar. The modified LPG Samovar takes only 10 to 15 minutes to make 25 cups of tea, saving precious time and a lot of human effort without producing any eye irritation or ash.Shazia Jan’s innovation has been popularized through various media and received many awards, including the state award in the 8th National Grassroots Innovation Award ceremony.', '{"innovator_name":"Shazia Jan","location":"Ananthnag , Jammu & Kashmir","detail_url":"https://gian.org/multilingual_data/gas-samovar/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('shri-ishwar-singh-kundu-kaithal-haryana', 'Shri Ishwar Singh Kundu', 'The innovator, Shri Ishwar Singh Kundu, 45 years old, a moderately educated farmer, developed a multi-utility herbal formulation aided by GIAN and the Honey Bee Network. It was also financially supported by GIAN in affiliation with MVIF. Shri Ishwar Singh Kundu’s life was full of ups and downs and many hardships from 1988 – 2000. He tried many jobs and work, but it was all in vain. Despite this, he developed a multi-specialty herbal formulation, which is a great success now.', 'https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/', 'Kaithal, Haryana', null, 'Kaithal , Haryana', 'India', ARRAY['Kaithal, Haryana']::text[], ARRAY['health', 'water', 'farmer']::text[], 'https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/', 'Shri Ishwar Singh Kundu', null, null, null, null, null, null, null, 'Kaithal , Haryana', 'https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Screenshot-2024-03-07-163838.png"]'::jsonb, '["https://www.youtube.com/watch?v=LLukDK-uq3c"]'::jsonb, 29.649819, 76.2942507, 1, 'Shri Ishwar Singh Kundu The innovator, Shri Ishwar Singh Kundu, 45 years old, a moderately educated farmer, developed a multi-utility herbal formulation aided by GIAN and the Honey Bee Network. It was also financially supported by GIAN in affiliation with MVIF. Shri Ishwar Singh Kundu’s life was full of ups and downs and many hardships from 1988 – 2000. He tried many jobs and work, but it was all in vain. Despite this, he developed a multi-specialty herbal formulation, which is a great success now. Kaithal, Haryana health water farmer Herbal formulation for pest control: Kamaal 505 It was in October 2001 that Ishwar Singh started working on formulation and experiments on horrible insecticides and pesticides. He used to perform trials on his farm. His perspective was that the conventional formulation was causing air, soil, and water pollution. Also, human health and cattle health was affected by the chemical-based products. Hence, he made herbal products, including fertilizers, pesticides, insecticides, etc. In 2004, one of his friends from a nearby village showed interest in his work and offered support. The hard part for Singh was not the development but explaining and convincing the village farmers about the merits of herbal formulation and the ill effects of conventional pesticides. Somehow, he convinced a few farmers to use his formulations, and the response was very satisfying for farmers. Since then, he has tried many different formulations and has developed a whole herbal farming kit for which he applied for a patent.Many local institutions awarded and recognized the Innovation by Shree Ishwar Singh. He was also awarded the 3rd National Innovation Foundation award.', '{"innovator_name":"Shri Ishwar Singh Kundu","location":"Kaithal , Haryana","detail_url":"https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('dharambir-kambhoj-yamunanagar-haryana', 'Dharambir Kambhoj', 'Dharambir Kambhoj is an amazing innovator who has encountered lots of hardships with a touch of luck. He is a 59-year-old farmer cum innovator from Haryana who has designed a multi-purpose food processing machine guided and supported by GIAN and the Honey Bee Network. GIAN bolstered the innovative design and patenting process in the year 2008. GIAN also supported it under (MVIF) for prototype development and test marketing. Dharambir was the youngest of all five siblings; his father was a farmer and operated a small flour mill and a jaggery processing plant. His mother was a herbalist. Inherited from both of his parents, Dharambir is a farmer, a herbalist, and an innovator. Today he is a successful entrepreneur selling his patented machines to 15 countries.', 'https://gian.org/multilingual_data/multi-purpose-food-processing-machines/', 'Yamunanagar, Haryana', null, 'Yamunanagar , Haryana', 'India', ARRAY['Yamunanagar, Haryana']::text[], ARRAY['fruit', 'machine', 'food', 'processing', 'farmer']::text[], 'https://gian.org/multilingual_data/multi-purpose-food-processing-machines/', 'Dharambir Kambhoj', null, null, null, null, null, null, null, 'Yamunanagar , Haryana', 'https://gian.org/multilingual_data/multi-purpose-food-processing-machines/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/multi-purpose-food-processing-machines/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Dharambir-Khamboj-.png"]'::jsonb, '["https://www.youtube.com/watch?v=KqvcCYtdyOA"]'::jsonb, 30.1014803, 77.2749964, 1, 'Dharambir Kambhoj Dharambir Kambhoj is an amazing innovator who has encountered lots of hardships with a touch of luck. He is a 59-year-old farmer cum innovator from Haryana who has designed a multi-purpose food processing machine guided and supported by GIAN and the Honey Bee Network. GIAN bolstered the innovative design and patenting process in the year 2008. GIAN also supported it under (MVIF) for prototype development and test marketing. Dharambir was the youngest of all five siblings; his father was a farmer and operated a small flour mill and a jaggery processing plant. His mother was a herbalist. Inherited from both of his parents, Dharambir is a farmer, a herbalist, and an innovator. Today he is a successful entrepreneur selling his patented machines to 15 countries. Yamunanagar, Haryana fruit machine food processing farmer Multi-Purpose Food Processing Machines In 2002, Dharambir met a bank manager who visited their village to promote aloe vera farming and discussed the aloe vera gel extractor machine. However, due to the high cost of the machine and the extra high consultation charges, Dharambir decided to develop one of his food processing machines in 2003 and completed the prototype by March 2005.The prototype had a heating problem when minimal material was processed. He could not eliminate the problem in the second prototype. In the third prototype, he introduced the castor oil bath, which could maintain the temperature at 200° c. This third prototype was bought by GIAN and sent to Kenya as a pilot. Based on the feedback received, GIAN asked him to modify and further incorporate the provisions that would make transport easier, including foldable legs; Dharambir managed to design a successful prototype.It is a 125 kg multi-purpose processing machine with only a single-phase motor and can process various herbal plants and fruits. Its motor Speed is 1440 RPM which works at the speed of 360 RPM, and it can extract 1 to 50 kg of juice/gel/extract per hour. It contains two electric heaters, an automatic temperature cut-off, and a starter panel with electricity consumption of 1.5 machines per hour.Dharambir’s innovation has obtained widespread recognition and was awarded by the National Innovation Foundation with the Haryana state award in the 5th National biennial award function.', '{"innovator_name":"Dharambir Kambhoj","location":"Yamunanagar , Haryana","detail_url":"https://gian.org/multilingual_data/multi-purpose-food-processing-machines/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mansukhbhai-prajapati-rajkot-gujarat', 'Mansukhbhai Prajapati', 'In 2003, Mansukhbhai’s wife asked him to bring a non-stick tawa from the market; this was when the innovation journey of Mitticool Creations started. As he inquired about the non-stick pan in the market, he found out that it cost a minimum of rupees 200, and the coating wears off quite soon. Teflon-coated cookware does not retain the food’s natural taste and harms stomach health. This inspired him to make the non-stick tawa out of clay which retains the natural taste of food and is not harmful if the coating wears off. He also innovated a refrigerator made out of clay which does not need any external energy source for the cooling effect. Today Mitticool Creations has a whole variety of products made out of clay and is a successful company. Mitticool Creations won many awards, including a national award for most innovative products by the Ministry of Rural Development, a true scientist by the past president of India, Dr. APJ Abdul Kalam, in the fourth national award function in Delhi, a state award from Narendra Modi Chief Minister of Gujarat, an award by India Book of Records as an innovator of the year, and an award for global clay products innovator by Global Records. Also, Mitticool Creation was the first grassroots innovator to receive ISO certification recognition.', 'https://gian.org/multilingual_data/mitticool-clay-creation/', 'Rajkot, Gujarat', null, 'Rajkot , Gujarat', 'India', ARRAY['Rajkot, Gujarat']::text[], ARRAY['food', 'health']::text[], 'https://gian.org/multilingual_data/mitticool-clay-creation/', 'Mansukhbhai Prajapati', null, null, null, null, null, null, null, 'Rajkot , Gujarat', 'https://gian.org/multilingual_data/mitticool-clay-creation/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/mitticool-clay-creation/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2024/11/Mansukhbhai-mitticool_upscayl_4x_ultrasharp.png"]'::jsonb, '["https://www.youtube.com/watch?v=u3f-8WvYyKY"]'::jsonb, 22.66043656, 70.95025339, 1, 'Mansukhbhai Prajapati In 2003, Mansukhbhai’s wife asked him to bring a non-stick tawa from the market; this was when the innovation journey of Mitticool Creations started. As he inquired about the non-stick pan in the market, he found out that it cost a minimum of rupees 200, and the coating wears off quite soon. Teflon-coated cookware does not retain the food’s natural taste and harms stomach health. This inspired him to make the non-stick tawa out of clay which retains the natural taste of food and is not harmful if the coating wears off. He also innovated a refrigerator made out of clay which does not need any external energy source for the cooling effect. Today Mitticool Creations has a whole variety of products made out of clay and is a successful company. Mitticool Creations won many awards, including a national award for most innovative products by the Ministry of Rural Development, a true scientist by the past president of India, Dr. APJ Abdul Kalam, in the fourth national award function in Delhi, a state award from Narendra Modi Chief Minister of Gujarat, an award by India Book of Records as an innovator of the year, and an award for global clay products innovator by Global Records. Also, Mitticool Creation was the first grassroots innovator to receive ISO certification recognition. Rajkot, Gujarat food health Mitticool Clay Creation Mansukhbhai Prajapati, a 48-year-old innovator from Wankaner village, Rajkot, Gujarat, was supported and financially aided by angel investor Prof. Anil Gupta, professor at IIM Ahmedabad, founder of the Honey Bee Network and vice chairman of the National Innovation Foundation. GIAN was a helping hand in establishing a company named Clay Creation in 2008. GIAN also assisted Mansukhbhai in developing the online retail portal www.mitticool.in. GIAN also added value to the original innovations of Mansukhbhai by suggesting small but beneficial ideas and helping him design the packaging material. Mansukh Bhai offered his heartfelt gratitude towards GIAN and Prof. Anil Gupta.Mansukhbhai Prajapati belonged to a poor potter family, studied till 10th std, and started working at a tea stall. He moved from the tea stall to work at a factory. His father and boss were cautious about the risk of starting his own business, but Mansukhbhai started working on his dream. After the 2001 Bhuj earthquake, his journey of innovation started, and today Mitticool Creation sells more than 250 clay products and is ISO certified.', '{"innovator_name":"Mansukhbhai Prajapati","location":"Rajkot , Gujarat","detail_url":"https://gian.org/multilingual_data/mitticool-clay-creation/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-mushtaq-ahmad-dar-jammu-and-kashmir', 'Mr. Mushtaq Ahmad Dar', 'Mushtaq Ahmad Dar (28), a young innovator from Kashmir, innovated a foldable cylinder carrier. A ‘full-time’ innovator, Mushtaq also helps his brothers in running the family business and managing the household. Knowing Mushtaq’s creative nature, in 2005, his friend, Zahoor Ahmed Shah brought him to Ahmedabad for NIF’s Third National Innovation Award Function. Mushtaq was intrigued to see and meet so many people from different parts of the country who were not trained or aided but had created so many innovative solutions based on their observation skills, ingenuity, effort and hard work. He was immediately reminded of his troubled home state, which was plagued with unemployment and unrest. He imagined an innovation that, apart from solving a persistent technological problem, would also help in generating employment.', 'https://gian.org/multilingual_data/foldable-cylinder-carrier/', 'Jammu and Kashmir', null, 'Jammu and Kashmir', 'India', ARRAY['Jammu and Kashmir']::text[], ARRAY[]::text[], 'https://gian.org/multilingual_data/foldable-cylinder-carrier/', 'Mr. Mushtaq Ahmad Dar', null, null, null, null, null, null, null, 'Jammu and Kashmir', 'https://gian.org/multilingual_data/foldable-cylinder-carrier/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/foldable-cylinder-carrier/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image048.png"]'::jsonb, '["https://www.youtube.com/watch?v=E2rGd7Fldo0"]'::jsonb, 33.6241452, 75.2128996, 1, 'Mr. Mushtaq Ahmad Dar Mushtaq Ahmad Dar (28), a young innovator from Kashmir, innovated a foldable cylinder carrier. A ‘full-time’ innovator, Mushtaq also helps his brothers in running the family business and managing the household. Knowing Mushtaq’s creative nature, in 2005, his friend, Zahoor Ahmed Shah brought him to Ahmedabad for NIF’s Third National Innovation Award Function. Mushtaq was intrigued to see and meet so many people from different parts of the country who were not trained or aided but had created so many innovative solutions based on their observation skills, ingenuity, effort and hard work. He was immediately reminded of his troubled home state, which was plagued with unemployment and unrest. He imagined an innovation that, apart from solving a persistent technological problem, would also help in generating employment. Jammu and Kashmir Foldable Cylinder Carrier Innovation Description: Mr. Mushtaq Ahmad Dar made a foldable gas carrier which can be used to carry gas cylinders. This makes it easy for a person to carry the cylinder from one place to another. The carrier is foldable, easy to use for even women and children, and has a loading capacity up to 60 kg. Its production cost is Rs.350/- per unit and selling price is 500/- per unit (excluding GST 18%). Its expected sale is 1000 units per year. Mushtaq’s innovation got financial support from MVIF under GIAN and SIDBI for marketing. It was also awarded in 5th National Grassroots Innovation Awards 2009.', '{"innovator_name":"Mr. Mushtaq Ahmad Dar","location":"Jammu and Kashmir","detail_url":"https://gian.org/multilingual_data/foldable-cylinder-carrier/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('gangaram-chauhan-gorakhpur-uttar-pradesh', 'Gangaram Chauhan', 'Gangaram Chauhan, 50, holds a bachelor’s degree in commerce. It was about 20 years ago that he started experimenting and in the year 2000, came up with his first innovate product, a rickshaw, which he is improving ever since.', 'https://gian.org/multilingual_data/cycle-operated-aatachakki/', 'Gorakhpur Uttar Pradesh', null, 'Gorakhpur Uttar Pradesh', 'India', ARRAY['Gorakhpur Uttar Pradesh']::text[], ARRAY['machine', 'device', 'farmer']::text[], 'https://gian.org/multilingual_data/cycle-operated-aatachakki/', 'Gangaram Chauhan', null, null, null, null, null, null, null, 'Gorakhpur Uttar Pradesh', 'https://gian.org/multilingual_data/cycle-operated-aatachakki/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/cycle-operated-aatachakki/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image040.png"]'::jsonb, '["https://www.youtube.com/watch?v=Nd5GnUOx8fg"]'::jsonb, 26.7918114, 83.3041061, 1, 'Gangaram Chauhan Gangaram Chauhan, 50, holds a bachelor’s degree in commerce. It was about 20 years ago that he started experimenting and in the year 2000, came up with his first innovate product, a rickshaw, which he is improving ever since. Gorakhpur Uttar Pradesh machine device farmer Cycle Operated Aatachakki Gangaram, a rickshaw repairer and a resident of Ramjanaki Nagar, in Uttar Pradesh, built a cycling mill to grind wheat. During the COVID-19-induced lockdown, he found it very difficult to go to the market to grind the flour and this motivated him to come up with a cycle-operated attachakki. Gangara had to invest Rs 10,000 from his pocket to create this device. He was assisted in his ‘native juggad’ by Gopal Vishwakarma, a teacher teaching mechanical engineering in a college, and Arun Kumar Singh, also a teacher, teaching drawing to polytechnics’ students. Together, it took them two months to come up with the unique cycle-operated attachakki. This innovative floor mill can grind about 8 kg of wheat and other grains in an hour. The machine is easy to use and can be operated by both women and children. Grains are poured in the upper part of the machine, which then flow down to a millstone through a pipe to the bottom compartment for grinding. The cycle-operated attachakki can grind wheat, rice, and other coarse grains with no loss to their nutritional value. The device has attracted much interest with people flocking to see the innovation and also place orders. Gangaram received marketing and prototype development support under MVIF by GIAN and SIDBI in the year 2021. As of now, he has sold two units of his cycle chakki. He also received the innovative farmer award in 2020.', '{"innovator_name":"Gangaram Chauhan","location":"Gorakhpur Uttar Pradesh","detail_url":"https://gian.org/multilingual_data/cycle-operated-aatachakki/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('abdul-kareem-k-a-kerala', 'Abdul Kareem K A', 'Abdul Kareem, 57, attributes his latest innovation inspiration to the lockdown that happened to control the COVID 19 pandemic. He has been running his own company — Excellent, in Kochi for the past 40 years, “I have been making products such as boilers, and many industrial materials. During the lockdown period, I thought what if electricity and LPG supply stopped one day? What alternative can I use to cook food? Even though traditional stoves are available in Kerala, many people hesitate to use them due to the thick smoke they give out. That’s when I started work on my rocket stove,” he says.', 'https://gian.org/multilingual_data/rocket-stove/', 'Kerala', null, 'Kerala', 'India', ARRAY['Kerala']::text[], ARRAY['food']::text[], 'https://gian.org/multilingual_data/rocket-stove/', 'Abdul Kareem K A', null, null, null, null, null, null, null, 'Kerala', 'https://gian.org/multilingual_data/rocket-stove/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/rocket-stove/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image031.png"]'::jsonb, '["https://youtu.be/atXpd2RdUbI"]'::jsonb, 10.047943, 76.3695167, 1, 'Abdul Kareem K A Abdul Kareem, 57, attributes his latest innovation inspiration to the lockdown that happened to control the COVID 19 pandemic. He has been running his own company — Excellent, in Kochi for the past 40 years, “I have been making products such as boilers, and many industrial materials. During the lockdown period, I thought what if electricity and LPG supply stopped one day? What alternative can I use to cook food? Even though traditional stoves are available in Kerala, many people hesitate to use them due to the thick smoke they give out. That’s when I started work on my rocket stove,” he says. Kerala food Rocket Stove The rocket stove is based on a concept developed by the British in the 1850s that comprised an insulated vertical chimney. He had seen this stove in many hotels in Kodaikanal and Munnar. The stove is constructed in a way to ensure complete combustion before the flames reach the cooking surface. Abdul conducted some more research on the British stove before making his own version. His version of the stove uses 4 mm mild steel sheets and stainless steel sheets to make the oven chamber. The raw material is easily available both in his company and the market. He tested the stove outside his house using firewood as fuel. The stove attracted the attention of his relatives, neighbors, and friends who also wanted it for their use. Orders began to pour in and he began commercial manufacturing in his existing facility. The stove requires firewood, coconut shells, and waste paper as fuel and cuts down smoke by 80 percent. Available in four models, the rocket stove is easily portable. The premium model costs Rs 20,000 and weighs 60 kilos. The regular model has two options for cooking and grilling, costs Rs 6,500, and weighs 35 kilos. The basic model has only the cooking option, costs Rs 5,000, and weighs 30 kilos. Abdul also has a fourth kind, which he calls a ‘tour package stove’, intended for cooking on the go. This portable stove costs Rs 7,000 and weighs 20 kilos. “I have four decades of experience in making furnaces, boilers, kitchens and other industrial materials. The rocket stove was developed out of curiosity. Thanks to Covid-19-induced lockdown, I managed to finalize the design about six months ago and now have also started the production,” he says.', '{"innovator_name":"Abdul Kareem K A","location":"Kerala","detail_url":"https://gian.org/multilingual_data/rocket-stove/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-aabid-rehman-dar-jammu-kashmir', 'Mr. Aabid Rehman Dar', 'Aabid Rehman Dar hails from Anantnag, in Kashmir. He is currently pursuing Civil Engineering from a college affiliated to Gujarat Technological University. He is 23-year-old and currently in his final year.', 'https://gian.org/multilingual_data/snow-remover/', 'Jammu & Kashmir', null, 'Jammu & Kashmir', 'India', ARRAY['Jammu & Kashmir']::text[], ARRAY['agriculture', 'machine', 'device', 'snow']::text[], 'https://gian.org/multilingual_data/snow-remover/', 'Mr. Aabid Rehman Dar', null, null, null, null, null, null, null, 'Jammu & Kashmir', 'https://gian.org/multilingual_data/snow-remover/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/snow-remover/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image028.png"]'::jsonb, '["https://www.youtube.com/watch?v=tEMI3Kn55Ds"]'::jsonb, 33.7448467, 75.3062326, 1, 'Mr. Aabid Rehman Dar Aabid Rehman Dar hails from Anantnag, in Kashmir. He is currently pursuing Civil Engineering from a college affiliated to Gujarat Technological University. He is 23-year-old and currently in his final year. Jammu & Kashmir agriculture machine device snow Snow Remover The Kashmir valley witnesses heavy snow along with snowfall during the winter months from December to February, closing major roads and bringing mobility to a halt. Heavy snow cutter machines/vehicles are used to clean the roads, and depending on the level of snow, the process can take around 2 to 3 days. While it is easier to clean the arterial roads, the narrow paths are left with snow, which reduces mobility and sometimes even leads to people falling and getting fractures. Locals usually clean out these paths with spades; however, this is a cumbersome task and would be better performed with a mini-machine. However, with no such solution available in the market, Aabid Rehman Dar came up with the idea of a mini snow remover. Agriculture comes to a close in Kashmir during the winter months and the mini tiller machines used to plough the fields remain idle. Aabid decided to modify the tillers and use them as snow remover machines. To do this, he added an attachment to the tiller that could plough the snow from the roads. The attachment is fitted in the front of the tiller and is detachable – it can be attached or detached using 2 bolts, taking upto 2 minutes. The device comprises of a curved shovel blade having 48 inches of curved width. It can clean the snow from 36 inches of snow from the surface of in just one go. The whole device remains unchanged in its design & operational activity which adds novelty to this innovation.', '{"innovator_name":"Mr. Aabid Rehman Dar","location":"Jammu & Kashmir","detail_url":"https://gian.org/multilingual_data/snow-remover/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-senthil-duraisamy-tamil-nadu', 'Mr. Senthil Duraisamy', 'M. Senthil Kumar (42) is a professor of mechanical engineering and principal of a college affiliated to Anna University. He has studied uptil class VIII and has more than 20 years of work experience to his credit. He began his inning working in an automobile company, after which he set up his own welding company.', 'https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/', 'Tamil Nadu', null, 'Tamil Nadu', 'India', ARRAY['Tamil Nadu']::text[], ARRAY['tree', 'machine', 'food']::text[], 'https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/', 'Mr. Senthil Duraisamy', null, null, null, null, null, null, null, 'Tamil Nadu', 'https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image025.png"]'::jsonb, '["https://www.youtube.com/watch?v=npVMWAUKdQI"]'::jsonb, 9.9980277, 78.3500875, 1, 'Mr. Senthil Duraisamy M. Senthil Kumar (42) is a professor of mechanical engineering and principal of a college affiliated to Anna University. He has studied uptil class VIII and has more than 20 years of work experience to his credit. He began his inning working in an automobile company, after which he set up his own welding company. Tamil Nadu tree machine food Groundnut Separator And Coconut Cutting Machine Senthil had observed people take out coconuts from the whole nuts harvested from the coconut trees using a crowbar. He developed an iron cutter that could split the whole nut into two halves to extract oil for culinary purposes. At present, the motor is fitted with 1/2 hp or 1 hp to mechanize the cutting of the nuts. He also advocates that instead of harvesting nuts from the tree people should just collect the ones that have fallen. This is because these nuts are fully mature and contain more oil to extract. Further, he also advocates storing these nuts for four and half months before extracting the oil from the kernels. Normally, nuts are stored for two months after the harvest. Duraisamy’s method of harvesting and storing can increase kernel’s weight and oil content considerably. From one quintal of kernels, 71/2kg of extra oil can be obtained and from one quintal of nuts 15 kg of kernels can be obtained instead of the normal 10 kg form the normally practiced method. Senthil also uses this cutter to extract oil from palmyrah nuts. The mechanized version of this cutter (that is, connecting to 1/2 hp or 1 hp motor) can break 8,000 nuts at a time. As an added benefit, the cutter helps to save labor cost. On an average, in one minute, 25 nuts can be broken manually. The machines currently in use are typically large and consume as much as 5,000 watt. Senthil’s machine, designed as part of an incubation project, is 46 per cent smaller in volume and consumes around 2,100 watt. “Our machine can be easily customised according to the shape and size of the product to be manufactured. We have made thermoformed pieces using our machine with a cycle time of 3.5 seconds,” says Senthil. The machine is priced at Rs. 1 lakh as against the existing products in the market, which cost around Rs. 8 lakh to 10 lakh. The cost of running the machine is low, which naturally lowers thethe product cost. The machine requires just one person to operate. “It would be a boon for food packaging, toiletries, pharmaceuticals and electronics industries as these thermoformed products can prevent odour, moisture and gases from damaging the products that are packed” Mr. Senthil Kumar adds.', '{"innovator_name":"Mr. Senthil Duraisamy","location":"Tamil Nadu","detail_url":"https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-saravana-muthu-tamil-nadu', 'Mr. Saravana Muthu', 'Saravana Muthu (40) owns an engineering workshop. Son of a car mechanic, he started tinkering with car parts early in his life and later started repairing and modifying them. He now helps students in his area in machining and fabrication work related to their projects. Unfortunately, his wife became temporarily bedridden after an operation and needed help to go to the toilet. This made her highly uncomfortable to the extent she would rather control than seek help, which further added to her woes. This motivated Saravana Muthu to design a bed with an attached toilet pot, which she could use to relieve herself without assistance.', 'https://gian.org/multilingual_data/toilet-attached-cot/', 'Tamil Nadu', null, 'Tamil Nadu', 'India', ARRAY['Tamil Nadu']::text[], ARRAY[]::text[], 'https://gian.org/multilingual_data/toilet-attached-cot/', 'Mr. Saravana Muthu', null, null, null, null, null, null, null, 'Tamil Nadu', 'https://gian.org/multilingual_data/toilet-attached-cot/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/toilet-attached-cot/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image023.png"]'::jsonb, '["https://youtu.be/wB6iR4pdYAc"]'::jsonb, 8.1665445, 77.4085149, 1, 'Mr. Saravana Muthu Saravana Muthu (40) owns an engineering workshop. Son of a car mechanic, he started tinkering with car parts early in his life and later started repairing and modifying them. He now helps students in his area in machining and fabrication work related to their projects. Unfortunately, his wife became temporarily bedridden after an operation and needed help to go to the toilet. This made her highly uncomfortable to the extent she would rather control than seek help, which further added to her woes. This motivated Saravana Muthu to design a bed with an attached toilet pot, which she could use to relieve herself without assistance. Tamil Nadu Toilet-Attached Cot S. Saravana Muthu invented a remote-control toilet bed for his wife that won him the National Innovation Prize. His wife felt awkward about seeking help, a situation which many bedridden people can identify with. Saravana decided to make a bed that had an attached toilet and ease her life.He designed a cot fitted with a 12 V battery to operate two gear motors to move the attached toilet pot vertically and sideways. He also incorporated a remote-controlled flushing system, making it easy for the user to clean the pot after use. The innovation includes a flush tank, a closet and a pipe connected to the septic tank. The patient can operate the toilet with the help of a remote. The buttons can be used to open the shutter and the closet, and as well as flush the toilet. His invention attracted the attention of a regional newspaper, enabling Saravana Muthu to receive his first order in 2015 from a man in Chennai whose mother had been bedridden for six years. Gradually, word spread and Sarvana began receiving request for the innovative bed. His innovation is supported under MVIF by GIAN and SIDBI for prototype development and marketing. He received a trophy, a certificate and Rs 2 lakh from President Ram Nath Kovind along with a reimbursement of Rs 35,000 he had used to make the prototype. He says, “I have two goals – make a fuel-free car and become a role model for my children.” Saravana Muthu has already started working on making an emission-less car and hopes to complete his project soon. He has a message for other innovators: “For the people who never thought that idea or creation is insignificant, my advice would be never to give up. I failed multiple times before making the right prototype for my wife. Had I given up because of external factors, my wife would have continued to be embarrassed. There is no alternative to hard work.” says Saravanmuthu', '{"innovator_name":"Mr. Saravana Muthu","location":"Tamil Nadu","detail_url":"https://gian.org/multilingual_data/toilet-attached-cot/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-murugesan-tamil-nadu', 'Mr. Murugesan', 'Mr. Murugesan is a school dropout who hails from the village of Melakkal in Madurai, Tamil Nadu. Family hardships and the need for sustainable development motivated him to identify means to put banana waste to use. He finally discovered a way to weave the waste into ropes that could be used to make waste bags and baskets. According to The Better India, an Indian digital media platform, Murugesan set up his own MS Ropes Production Center to create these products, an innovation that has won him many awards and accolades. However, his journey has been far from easy.', 'https://gian.org/multilingual_data/banana-fiber-products/', 'Tamil Nadu', null, 'Tamil Nadu', 'India', ARRAY['Tamil Nadu']::text[], ARRAY['agriculture', 'machine', 'device', 'processing', 'farmer']::text[], 'https://gian.org/multilingual_data/banana-fiber-products/', 'Mr. Murugesan', null, null, null, null, null, null, null, 'Tamil Nadu', 'https://gian.org/multilingual_data/banana-fiber-products/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/banana-fiber-products/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image019.png"]'::jsonb, '["https://youtube.com/shorts/tn0LdTUTfOk","https://keyword-plus.com/s/?q=bicycle"]'::jsonb, 9.984969, 77.98529, 1, 'Mr. Murugesan Mr. Murugesan is a school dropout who hails from the village of Melakkal in Madurai, Tamil Nadu. Family hardships and the need for sustainable development motivated him to identify means to put banana waste to use. He finally discovered a way to weave the waste into ropes that could be used to make waste bags and baskets. According to The Better India, an Indian digital media platform, Murugesan set up his own MS Ropes Production Center to create these products, an innovation that has won him many awards and accolades. However, his journey has been far from easy. Tamil Nadu agriculture machine device processing farmer Banana Fiber Products Murugesan came up with his idea of a rope when he witnessed thread made from the banana plant being used to weave flowers into a garland. However, it was easier thought than done. Initially, the rope would simply split up. Also, there was no machine available that could split the banana fiber. He experimented with machines used to process coconut husk but with no success. In his native area, Murugesan says some machines are used to process coconut husk into ropes, and he first tried processing the banana fibre using the same technique but with no success. He then thought of inventing his own machine. After many attempts, he developed a spinning machine using bicycle wheel rims and pulleys. He further invested Rs 1.5 lakh to improve the device and patent it. In 2017, Murugesan was finally able to develop an automated rope-making machine. The initial hand-wheel mechanism to make rope from the banana sheath would use five people per wheel for the process, with each wheel yielding only around 2,500 metres of rope. With the new machine, the production capacity rose to an average of 15,000 metres, utilizing one machine and four people in all. The company initially started with 10 people and now employs over 350, mostly women. The turnover is 1.5 crore annually. Nilesh was facilitated at the 15th FGI Awards for Excellence, 2018 where he received the Best innovative work award in the field of agriculture development, His innovation got financial support for marketing and prototype development under MVIF from GIAN and SIDBI. Murugesan has received the PMEGP (Prime Minister’s Employment Generation Programme) Award from Khadi and Village Industries Commission under the Ministry of Micro, Small and Medium Enterprises; National Farmer Scientist Award from Union Ministry for Agriculture; and Best Entrepreneur Award from Krishi Vigyan Kendra at Jabalpur. “What we do is braid the strands together to achieve a good tensile strength. We had to make sure that the products that we were making out of this are worth the money,” he said.', '{"innovator_name":"Mr. Murugesan","location":"Tamil Nadu","detail_url":"https://gian.org/multilingual_data/banana-fiber-products/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-mohd-rafiq-ahanger-jammu-and-kashmir', 'Mr. Mohd Rafiq Ahanger', 'Mohd Rafiq Ahanger, 42 years old, is a blacksmith involved in fabrication work since the last 25 years. His claim to fame is the development of a multipurpose tool, which can be used as an axe, hammer, chisel, blade, screwdriver driver for domestic or other carpentry tasks. Born in the family of blacksmiths, Rafiq did not have an easy childhood due to financial problems. It was tough for his father to raise eight children – two sons and six daughters. He recalls that though they come from a lower income background, he was cushioned from the shocks of poverty by his supportive parents, who went the extra mile to provide for their children. Since childhood, he had access to blacksmith tools, iron and steel, which he loved to play around with. He would use them to repair old gadgets, and make toys or small replicas. He studied till class ten and then took up odd jobs before finally settling into his father’s workshop.', 'https://gian.org/multilingual_data/folded-ladder/', 'Jammu and Kashmir', null, 'Jammu and Kashmir', 'India', ARRAY['Jammu and Kashmir']::text[], ARRAY['horticulture', 'tool', 'device']::text[], 'https://gian.org/multilingual_data/folded-ladder/', 'Mr. Mohd Rafiq Ahanger', null, null, null, null, null, null, null, 'Jammu and Kashmir', 'https://gian.org/multilingual_data/folded-ladder/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/folded-ladder/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image012.png"]'::jsonb, '["https://www.youtube.com/watch?v=Es-qc9zUcg0"]'::jsonb, 33.8987336, 75.2245693, 1, 'Mr. Mohd Rafiq Ahanger Mohd Rafiq Ahanger, 42 years old, is a blacksmith involved in fabrication work since the last 25 years. His claim to fame is the development of a multipurpose tool, which can be used as an axe, hammer, chisel, blade, screwdriver driver for domestic or other carpentry tasks. Born in the family of blacksmiths, Rafiq did not have an easy childhood due to financial problems. It was tough for his father to raise eight children – two sons and six daughters. He recalls that though they come from a lower income background, he was cushioned from the shocks of poverty by his supportive parents, who went the extra mile to provide for their children. Since childhood, he had access to blacksmith tools, iron and steel, which he loved to play around with. He would use them to repair old gadgets, and make toys or small replicas. He studied till class ten and then took up odd jobs before finally settling into his father’s workshop. Jammu and Kashmir horticulture tool device Folded Ladder In 1995, at the age of 20, he set up his own workshop to make grill gates, different iron structures for household use, and do motor repairing work. Born and brought up in a rural area, it was easy for Rafiq to identify with the problems people face in their daily lives, a fact that finds reflection in the products he designs. Given the poor condition of electricity in the region, he was in dire need of an electricity generator for his workshop. However, he did not have the funds to make a purchase. This prompted him to design a pressure generator for producing electricity. Rafiq claims to have developed a generator, which can produce 40W electricity. His innovation won him a lot of admiration in the district as also an invitation to the Islamic University of Science and Technology to demonstrate his device. Rafiq devotes most of his time working on his innovations and developing new prototypes. His wife is very considerate and supportive of his efforts and majorly shoulders the responsibility of the family, giving him the much-needed time to follow his passion. She hopes that one day her husband’s persistence pays off – ‘Mehnat tas Chu fal’, she says, implying hard work secures reward. This iron ladder has a multipurpose use in horticulture during harvesting and branch cuttingand is more secure than those that currently exist in the market. It is designed like a tripodwith a full height of up to 12 feet. Its wide pillar length ensures that a person can stand on itsecurely without losing balance. A basket can be pulled up and down by means of a ropepulley attached to the supporting pillar, which can be adjusted by hand without the need foran additional tool. This ladder can be folded to half its size and used as a 6 feet ladder whenopen. It is portable and ideal for both indoor and outdoor use. The ladder is made of strong material which can hold up to 100 kgs of weight. The producthas yet to go to the market. However, it is safe and secure and easy to carry, making it apotential winner. The ladder gained recognition and was awarded during the 9th NationalBiennial Grassroots Innovation Awards 2017, held on March 4th, 2017 at RashtrapatiBhavan, New Delhi.', '{"innovator_name":"Mr. Mohd Rafiq Ahanger","location":"Jammu and Kashmir","detail_url":"https://gian.org/multilingual_data/folded-ladder/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('mr-sanjaybhai-tilva-gujarat', 'Mr. Sanjaybhai Tilva', 'Sanjay Tilwa (31), a farmer and a manufacturer of agriculture implements, has developed a groundnut digger to dig out, uproot and clean ground nuts. His father is a retired school teacher and mother a housewife. Other members in his family include his wife, son, brother and sister. Talking about his childhood, Sanjay recalls that he did not do well in studies primarily due to lack of proper guidance. He later went to Junagadh where he completed his B. Com, taking on occasional jobs to take care of his expenses. In 2003, after his graduation, he returned to his village and engaged himself in farming. However, his dream was to deal in agricultural machinery. Later, with financial support from a relative, he set up his firm, Akshar Agro Engineering, in Rajkot. Sanjay Tilwa (31), a farmer and a manufacturer of agriculture implements, has developed a groundnut digger to dig out, uproot and clean ground nuts. His father is a retired school teacher and mother a housewife. Other members in his family include his wife, son, brother and sister. Talking about his childhood, Sanjay recalls that he did not do well in studies primarily due to lack of proper guidance. He later went to Junagadh where he completed his B. Com, taking on occasional jobs to take care of his expenses. In 2003, after his graduation, he returned to his village and engaged himself in farming. However, his dream was to deal in agricultural machinery. Later, with financial support from a relative, he set up his firm, Akshar Agro Engineering, in Rajkot.', 'https://gian.org/multilingual_data/groundnut-digger-turmeric-digger-garlic-digger/', 'Gujarat', null, 'Gujarat', 'India', ARRAY['Gujarat']::text[], ARRAY['agriculture', 'tool', 'machine', 'device', 'farmer']::text[], 'https://gian.org/multilingual_data/groundnut-digger-turmeric-digger-garlic-digger/', 'Mr. Sanjaybhai Tilva', null, null, null, null, null, null, null, 'Gujarat', 'https://gian.org/multilingual_data/groundnut-digger-turmeric-digger-garlic-digger/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/groundnut-digger-turmeric-digger-garlic-digger/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image009.png"]'::jsonb, '["https://www.youtube.com/watch?v=Ky0p3BUd2pc"]'::jsonb, 22.152786, 70.8833434, 1, 'Mr. Sanjaybhai Tilva Sanjay Tilwa (31), a farmer and a manufacturer of agriculture implements, has developed a groundnut digger to dig out, uproot and clean ground nuts. His father is a retired school teacher and mother a housewife. Other members in his family include his wife, son, brother and sister. Talking about his childhood, Sanjay recalls that he did not do well in studies primarily due to lack of proper guidance. He later went to Junagadh where he completed his B. Com, taking on occasional jobs to take care of his expenses. In 2003, after his graduation, he returned to his village and engaged himself in farming. However, his dream was to deal in agricultural machinery. Later, with financial support from a relative, he set up his firm, Akshar Agro Engineering, in Rajkot. Sanjay Tilwa (31), a farmer and a manufacturer of agriculture implements, has developed a groundnut digger to dig out, uproot and clean ground nuts. His father is a retired school teacher and mother a housewife. Other members in his family include his wife, son, brother and sister. Talking about his childhood, Sanjay recalls that he did not do well in studies primarily due to lack of proper guidance. He later went to Junagadh where he completed his B. Com, taking on occasional jobs to take care of his expenses. In 2003, after his graduation, he returned to his village and engaged himself in farming. However, his dream was to deal in agricultural machinery. Later, with financial support from a relative, he set up his firm, Akshar Agro Engineering, in Rajkot. Gujarat agriculture tool machine device farmer Groundnut Digger/Turmeric Digger/Garlic Digger Sanjay has five acres of cultivable land where he primarily grows groundnut. Working in the field, he realized how difficult and time-consuming it was to dig up the groundnuts. He discussed the issue with other farmers who also said that they had to incur losses due to the high cost and limited availability of labor to dig out the groundnuts. It was sometime in the year 2007 that Sanjay decided to come up with a solution. Initially, he developed a hand-operated plough; however, its efficiency was low and the device itself was labor-intensive. He then went on to develop a tractor-operated plough; however, this too had its limitation in that the groundnut pods either got broken or left in the ground. Working persistently, he was finally able to develop a prototype in 2009, which he modified to add two wheels under the conveyor for vibration. Finally, the machine was able to do what it was designed to. Sanjay recalls that the entire period of experimentation was a trying one and that he had to constantly swim against the tide to successfully culminate his journey. He also acknowledges the support of his elder brother and one of his friends in motivating him towards a successful solution. Sanjay’s innovation is a tractor-mounted, PTO-powered machine with a telescopic propeller shaft, suitable for tractors of 35 HP and above. It can dig out and uproot groundnuts from the soil. The harvesting blade (V shaped) of the machine is used to uproot the groundnuts. The blade is hardened by treating in oil at a very high temperature to make it suitable for work in different kinds of soil. It has an adjustable width and with variable penetration angle. Once uprooted, the conveyer belt conveys the groundnuts from the ground level to a higher level. During the process, the belt keeps vibrating, as a result of which the pods get cleaned of the attached soil. The collection box then opens to form the bed for groundnuts to dry. As the machine is heavy, wheels are provided at the rear to reduce the load on the tractor. Though the productivity of the machine depends on the type of soil, on an average, it can harvest about 3 to 4 Veega (0.4 Acre) per hour. In comparison to other alternatives, this machine not only mechanizes the digging but also undertakes cleaning and drying as well. Other alternatives commonly used are single offset beam digger and manual labor. In the latter case, three to five persons are required to pull out the plants, which have already been dug, and then clean the groundnuts, that is, remove soil from the plants. With the single offset digger, digging is done mechanically and subsequently, the pods are collected manually. This machine saves considerable labor, operating time and cost of operation compared to conventional methods. Moreover, this machine can be used in different kinds of soil. The testing of the device was done at CAET, Junagadh Agricultural University, Junagadh and the results were found to be appreciable. The price of the machine is Rs. 95,000 – (Ex-factory India packaging). The price does not include transportation cost, taxes etc. NIF felicitated the innovator with a National award in the Seventh Biennial Award Function of National Innovation Foundation. In 2019, Sanjay received marketing support from GIAN and SIDBI under MVIF (Micro Venture Innovation Fund). Technical Specifications Fuel Consumption – 1 lit/h Prime mover – 35 HP PTO Tractor Weight of Device – 374 kg Digging Efficiency – 98% Effective Width of cutting – 1250 mm Effective Depth of cutting – 100 – 120 mm Status of Innovation: Mr. Sanjay Tilwa has managed to sell a few units of his groundnut digger. The product has received appreciation from both experts and farmers, pointing to a good potential in the market. While working on the ground digger, Sanjay realized that he would have to diversify as this machine had a season-based demand. Accordingly, he developed another innovative tool – the reversible ploughs, which are also attached to the tractor. There are different variations of the plough, including manual, machine, hydraulic operated and a few more. He began selling these a few months back and has managed decent sales. Presently, Sanjay is actively engaged in fabricating and improving the digging machine, which he plans to make suitable for multiple crops.', '{"innovator_name":"Mr. Sanjaybhai Tilva","location":"Gujarat","detail_url":"https://gian.org/multilingual_data/groundnut-digger-turmeric-digger-garlic-digger/"}'::jsonb, now(), now());
insert into public.gian_innovators (portal_vendor_id, vendor_name, about_vendor, website_details, location_text, city, state, country, service_locations, tags, portal_vendor_link, portal_contact_name, portal_email, portal_phone, website_email, website_phone, website_address, final_contact_email, final_contact_phone, final_contact_address, contact_source_url, website_status, legacy_products_links, contact_notes, innovator_image_urls, innovator_media_urls, latitude, longitude, products_count, search_text, raw_vendor, synced_at, updated_at) values ('akash-singh-uttar-pradesh', 'Akash Singh', 'In school, Akash was an average student, a bit averse to studies. However, class IX proved to be a turning point, when a science project he created was selected for a school science exhibition conducted by the Central Board of Secondary Education, the national level board of education in India for public and private schools, controlled and managed by Union Government of India. The selection ushered in several accolades, further stimulating his interest in science and prompting him to experiment and even hold science festivals in his village to showcase his innovations. He went on to study Civil Engineering in a prestigious government polytechnic education society, Manesar, Gurgaon, while also getting actively involved in the Electrical and Mechanical Departments. Post-college, he set up his own venture by the name of Energine Innovations. The company, apart from manufacturing a self-irrigation sprinkler and a self-power generating walking stick, also creates sculptures and idols from waste material. Over the years, the company has witnessed its share of ups and downs but always managed to evolve and tell an inspiring tale. Committed to social welfare, Akash also came up with the idea to upskill prisoners to create handicrafts, helping them to course correct and make a decent living. Not surprisingly, his idea met with resistance; however, he persisted and today he is helping the prisoners work for a better tomorrow.', 'https://gian.org/multilingual_data/smart-walking-stick/', 'Uttar Pradesh', null, 'Uttar Pradesh', 'India', ARRAY['Uttar Pradesh']::text[], ARRAY['device']::text[], 'https://gian.org/multilingual_data/smart-walking-stick/', 'Akash Singh', null, null, null, null, null, null, null, 'Uttar Pradesh', 'https://gian.org/multilingual_data/smart-walking-stick/', 'Imported from one-time local GIAN scrape', 'https://gian.org/multilingual_data/smart-walking-stick/', 'Initial local scrape import. Contact enrichment can be added in a later pass.', '["https://gian.org/wp-content/uploads/2023/06/image004.png"]'::jsonb, '["https://www.youtube.com/watch?v=IZy65AKRThQ"]'::jsonb, 28.1249021, 77.5390127, 1, 'Akash Singh In school, Akash was an average student, a bit averse to studies. However, class IX proved to be a turning point, when a science project he created was selected for a school science exhibition conducted by the Central Board of Secondary Education, the national level board of education in India for public and private schools, controlled and managed by Union Government of India. The selection ushered in several accolades, further stimulating his interest in science and prompting him to experiment and even hold science festivals in his village to showcase his innovations. He went on to study Civil Engineering in a prestigious government polytechnic education society, Manesar, Gurgaon, while also getting actively involved in the Electrical and Mechanical Departments. Post-college, he set up his own venture by the name of Energine Innovations. The company, apart from manufacturing a self-irrigation sprinkler and a self-power generating walking stick, also creates sculptures and idols from waste material. Over the years, the company has witnessed its share of ups and downs but always managed to evolve and tell an inspiring tale. Committed to social welfare, Akash also came up with the idea to upskill prisoners to create handicrafts, helping them to course correct and make a decent living. Not surprisingly, his idea met with resistance; however, he persisted and today he is helping the prisoners work for a better tomorrow. Uttar Pradesh device Smart Walking Stick “My septuagenarian grandfather always carries a walking stick with him for his morning walks. The stick did give him the support he needed; however, it also tired him out as it was heavy to lift. That’s when I thought of a walking stick that would enable easier mobility and be lightweight at the same time,” he says. Akash had watched his grandfather use a walking stick, which while giving him the support to walk also inadvertently, tired him out. This prompted him to come up with his innovative walking stick equipped with a wheel fitted with a power-braking system. The device has an internal power-generating mechanism, which can also be used as a mobile charger. Besides, it also has an alarm, torch, and compass. It took Akash almost a year to formalize the concept and develop a working model. He had to spend an equal measure of time to develop its mechanical and electrical aspects, and then another four months to turn his idea into reality. The wheel makes the stick light to use and is useful not only to the elderly but also to people with physical disabilities. The alarm can be set off as an alert during an emergency. “The entire cost of assembling the apparatus works out to ₹1500. So, the stick is high on functionality and also easy on the pocket.” – Akash Adding feathers in his cap, Akash has won praise from the PMO and received an award from the Chief Minister of Haryana, and appreciation from the Ministry of Environment and Climate Change. He has also been selected for the first global edition of Ashoka Young Changemaker from India and is currently Incubated in Atal Incubation Center BIMTECH. He is deeply committed to social and environmental welfare. Amongst his several plans for the future, he wishes to upskill women inmates in prison, offering them a means to take up meaningful employment. Also, he aims to adopt more than 500 temples and lakes to make them more environment-friendly, and thereby, reduce their carbon imprints. According to Akash, “Age is just a number, be passionate and keep following your dreams.” Further, “Challenges are inevitable. At some point in time, every individual faces challenges in accomplishing their goals. I faced some too. My parents have been really supportive.”', '{"innovator_name":"Akash Singh","location":"Uttar Pradesh","detail_url":"https://gian.org/multilingual_data/smart-walking-stick/"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('the-clipper-fruit-tree-safety-holder', 'md-ishfaq-ahmed-wani-anantnag-jammu-and-kashmir', 'Md. Ishfaq Ahmed Wani', 'The Clipper (Fruit tree safety holder)', 'Farmers faced a persistent challenge—trees overloaded with ripening fruits often had their branches snap under pressure, while strong winds, heavy rain, and snowfall further damaged their orchards. This led to significant fruit loss, reducing their overall yield and income. The Mechanical Safety Holder emerged as a game-changer, designed to support and balance multiple branches against external forces. This durable, adjustable clipper prevented breakage, reduced wastage, and even allowed farmers to shape their trees conveniently. With its use, they saved 4-5 extra boxes of fruit per tree, leading to higher earnings. With 3,000 units already sold and three new designs under testing, the impact of this innovation continues to grow. By strengthening trees and protecting harvests, the device is transforming farming, ensuring greater stability, less waste, and a more secure future for fruit growers.', 'https://gian.org/multilingual_data/the-clipper-fruit-tree-safety-holder/', 'https://gian.org/wp-content/uploads/2024/12/Ishfaq-22-768x1024.jpg', '["https://gian.org/wp-content/uploads/2024/12/Ishfaq-22-768x1024.jpg","https://gian.org/wp-content/uploads/2024/12/Ishfaq-22-scaled.jpg"]'::jsonb, '["https://youtu.be/JV4RARcjzhM"]'::jsonb, 'Anantnag , Jammu and Kashmir', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Md. Ishfaq Ahmed Wani"},{"key":"Location","value":"Anantnag , Jammu and Kashmir"},{"key":"Details of Innovation","value":"Farmers faced a persi