insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('natural-water-cooler', 'arvindbhai-patel-ahmedabad-gujarat', 'Arvindbhai Patel', 'Natural Water Cooler', 'A 57-year-old serial innovator, Arvindbhai Patel, from Vanch Ahmedabad, Gujarat, has many innovations in his name. GIAN and the Honey Bee Network facilitated a few. GIAN guided and supported his innovation of a natural water cooler; he acquired a patent for this innovation which GIAN assisted under the micro venture innovation fund (MVIF) of NIF for the commercialization of the new innovative technology. GIAN West facilitated the technology transfer of this natural cooler to entrepreneurs. Due to financial constraints, Arvindbhai Patel had to cease his formal education after the 10th grade. Still, his passion for innovation took him to the next level. Today, he has innovated a series of amazing prototypes, such as the Auto Air Kick Pump and Auto Compression Sprayer, which also added technology licenses to his name.', 'https://gian.org/multilingual_data/natural-water-cooler/', 'https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-14.44.12.jpeg', '["https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-14.44.12.jpeg","https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-14.44.122.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=nAu-PIc5xAU"]'::jsonb, 'Ahmedabad , Gujarat', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Arvindbhai Patel"},{"key":"Location","value":"Ahmedabad , Gujarat"},{"key":"Details of Innovation","value":"A 57-year-old serial innovator, Arvindbhai Patel, from Vanch Ahmedabad, Gujarat, has many innovations in his name. GIAN and the Honey Bee Network facilitated a few. GIAN guided and supported his innovation of a natural water cooler; he acquired a patent for this innovation which GIAN assisted under the micro venture innovation fund (MVIF) of NIF for the commercialization of the new innovative technology. GIAN West facilitated the technology transfer of this natural cooler to entrepreneurs. Due to financial constraints, Arvindbhai Patel had to cease his formal education after the 10th grade. Still, his passion for innovation took him to the next level. Today, he has innovated a series of amazing prototypes, such as the Auto Air Kick Pump and Auto Compression Sprayer, which also added technology licenses to his name."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=nAu-PIc5xAU"}]'::jsonb, ARRAY['water']::text[], 'Natural Water Cooler Arvindbhai Patel Ahmedabad , Gujarat Arvindbhai Patel once had a high fever, so his wife repeatedly applied a cold press to his forehead to keep his temperature down. While in the throes of the fever, Patel’s brain clicked with the idea of developing a water cooler using the same principle of temperature to cool water without electricity. Based on the principle of heat exchange, Arvindbhai Patel’s innovation is an energy-efficient, environment-friendly, and low-cost water cooler that cools water naturally without using any non-renewable source. Primitively, the cooler was available in three different capacities that were 5, 10, and 15. Whereas now they manufacture only 100- and 150-liter capacity coolers. He received recognition for his environmentally friendly innovation from Indian Science, Technology, and Innovation. He was also awarded the 7th National Biennial Award in 2013. A 57-year-old serial innovator, Arvindbhai Patel, from Vanch Ahmedabad, Gujarat, has many innovations in his name. GIAN and the Honey Bee Network facilitated a few. GIAN guided and supported his innovation of a natural water cooler; he acquired a patent for this innovation which GIAN assisted under the micro venture innovation fund (MVIF) of NIF for the commercialization of the new innovative technology. GIAN West facilitated the technology transfer of this natural cooler to entrepreneurs. Due to financial constraints, Arvindbhai Patel had to cease his formal education after the 10th grade. Still, his passion for innovation took him to the next level. Today, he has innovated a series of amazing prototypes, such as the Auto Air Kick Pump and Auto Compression Sprayer, which also added technology licenses to his name. water https://www.youtube.com/watch?v=nAu-PIc5xAU', '{"innovation_slug":"natural-water-cooler","detail_url":"https://gian.org/multilingual_data/natural-water-cooler/","innovation_title":"Natural Water Cooler","innovator_name":"Arvindbhai Patel","location":"Ahmedabad , Gujarat","innovator_bio":"Arvindbhai Patel once had a high fever, so his wife repeatedly applied a cold press to his forehead to keep his temperature down. While in the throes of the fever, Patel’s brain clicked with the idea of developing a water cooler using the same principle of temperature to cool water without electricity. Based on the principle of heat exchange, Arvindbhai Patel’s innovation is an energy-efficient, environment-friendly, and low-cost water cooler that cools water naturally without using any non-renewable source. Primitively, the cooler was available in three different capacities that were 5, 10, and 15. Whereas now they manufacture only 100- and 150-liter capacity coolers. He received recognition for his environmentally friendly innovation from Indian Science, Technology, and Innovation. He was also awarded the 7th National Biennial Award in 2013.","innovation_details":"A 57-year-old serial innovator, Arvindbhai Patel, from Vanch Ahmedabad, Gujarat, has many innovations in his name. GIAN and the Honey Bee Network facilitated a few. GIAN guided and supported his innovation of a natural water cooler; he acquired a patent for this innovation which GIAN assisted under the micro venture innovation fund (MVIF) of NIF for the commercialization of the new innovative technology. GIAN West facilitated the technology transfer of this natural cooler to entrepreneurs. Due to financial constraints, Arvindbhai Patel had to cease his formal education after the 10th grade. Still, his passion for innovation took him to the next level. Today, he has innovated a series of amazing prototypes, such as the Auto Air Kick Pump and Auto Compression Sprayer, which also added technology licenses to his name.","innovator_images":["https://gian.org/wp-content/uploads/2024/11/Arvindbhai-patel-scaled.png"],"innovation_images":["https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-14.44.12.jpeg","https://gian.org/wp-content/uploads/2024/11/WhatsApp-Image-2023-04-18-at-14.44.122.jpeg"],"multimedia_links":["https://www.youtube.com/watch?v=nAu-PIc5xAU"],"tags":["water"],"latitude":22.9984497,"longitude":72.6111939,"listing_excerpt":"Natural Water Cooler by Arvindbhai Patel"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('improved-variety-of-carrots-laxmangarh-selection', 'smt-santosh-pachar-sikar-rajasthan', 'Smt. Santosh Pachar', 'Improved variety of carrots (Laxmangarh Selection)', 'Sixteen years ago, Santosh Pachar bought some carrots for home consumption from a farmer named Mahavir from Laxmangarh Tehsil. The forked roots of carrots were very small, and the carrots were very good in appearance and taste. She admired the quality of carrots and wanted to cultivate such improved carrots on her farm. She adopted the route-to-seed methodology of planting at her farm to produce the seeds of the above-mentioned carrot. The selection standard of carrot for seed was sweetness, long route length, vermilion color, and softness. From the first year of the plantation, she collected the seeds, sowed them again in a small area of the field, and continuously adopted the same standard of selection method for 4 to 5 years. This was useful in stabilizing the desirable characteristics of the improvised carrots. Instead of conventional insecticides and pesticides, she used neem oil to control insects, pests, and diseases in her field.Her improved variety of seeds is well adapted to high temperatures. The length of her carrot is up to 1.5 ft, with a very low percentage of forked roots. It takes around 2.5 to 3 months to be completely ready and is resistant to any pest and disease attack. It yields almost 630qt/ha and is less hairy. It’s the best quality carrots containing a sweet taste which fetch high market price due to its quality.Smt. Santosh Pachar received recognition, selection in the residence program of Rashtrapati Bhavan, and a national award at the 7th National Grassroots Innovation Awards.', 'https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/', 'https://gian.org/wp-content/uploads/2024/11/santosh-pachar_rj-1-transformed.jpeg', '["https://gian.org/wp-content/uploads/2024/11/santosh-pachar_rj-1-transformed.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=Q9kxZDRi8m4"]'::jsonb, 'Sikar , Rajasthan', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Smt. Santosh Pachar"},{"key":"Location","value":"Sikar , Rajasthan"},{"key":"Details of Innovation","value":"Sixteen years ago, Santosh Pachar bought some carrots for home consumption from a farmer named Mahavir from Laxmangarh Tehsil. The forked roots of carrots were very small, and the carrots were very good in appearance and taste. She admired the quality of carrots and wanted to cultivate such improved carrots on her farm. She adopted the route-to-seed methodology of planting at her farm to produce the seeds of the above-mentioned carrot. The selection standard of carrot for seed was sweetness, long route length, vermilion color, and softness. From the first year of the plantation, she collected the seeds, sowed them again in a small area of the field, and continuously adopted the same standard of selection method for 4 to 5 years. This was useful in stabilizing the desirable characteristics of the improvised carrots. Instead of conventional insecticides and pesticides, she used neem oil to control insects, pests, and diseases in her field.Her improved variety of seeds is well adapted to high temperatures. The length of her carrot is up to 1.5 ft, with a very low percentage of forked roots. It takes around 2.5 to 3 months to be completely ready and is resistant to any pest and disease attack. It yields almost 630qt/ha and is less hairy. It’s the best quality carrots containing a sweet taste which fetch high market price due to its quality.Smt. Santosh Pachar received recognition, selection in the residence program of Rashtrapati Bhavan, and a national award at the 7th National Grassroots Innovation Awards."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=Q9kxZDRi8m4"}]'::jsonb, ARRAY['farmer']::text[], 'Improved variety of carrots (Laxmangarh Selection) Smt. Santosh Pachar Sikar , Rajasthan A female farmer who studied until the 8th standard had a keen interest in farming, leading her to innovate the new carrot variety SPL-101. Today with her hard work and support from GIAN, she sells carrot seeds in 20 different states of India. Smt. Santosh also received inquiries from Nepal and South Africa, where she will start exporting the seeds soon. Sixteen years ago, Santosh Pachar bought some carrots for home consumption from a farmer named Mahavir from Laxmangarh Tehsil. The forked roots of carrots were very small, and the carrots were very good in appearance and taste. She admired the quality of carrots and wanted to cultivate such improved carrots on her farm. She adopted the route-to-seed methodology of planting at her farm to produce the seeds of the above-mentioned carrot. The selection standard of carrot for seed was sweetness, long route length, vermilion color, and softness. From the first year of the plantation, she collected the seeds, sowed them again in a small area of the field, and continuously adopted the same standard of selection method for 4 to 5 years. This was useful in stabilizing the desirable characteristics of the improvised carrots. Instead of conventional insecticides and pesticides, she used neem oil to control insects, pests, and diseases in her field.Her improved variety of seeds is well adapted to high temperatures. The length of her carrot is up to 1.5 ft, with a very low percentage of forked roots. It takes around 2.5 to 3 months to be completely ready and is resistant to any pest and disease attack. It yields almost 630qt/ha and is less hairy. It’s the best quality carrots containing a sweet taste which fetch high market price due to its quality.Smt. Santosh Pachar received recognition, selection in the residence program of Rashtrapati Bhavan, and a national award at the 7th National Grassroots Innovation Awards. farmer https://www.youtube.com/watch?v=Q9kxZDRi8m4', '{"innovation_slug":"improved-variety-of-carrots-laxmangarh-selection","detail_url":"https://gian.org/multilingual_data/improved-variety-of-carrots-laxmangarh-selection/","innovation_title":"Improved variety of carrots (Laxmangarh Selection)","innovator_name":"Smt. Santosh Pachar","location":"Sikar , Rajasthan","innovator_bio":"A female farmer who studied until the 8th standard had a keen interest in farming, leading her to innovate the new carrot variety SPL-101. Today with her hard work and support from GIAN, she sells carrot seeds in 20 different states of India. Smt. Santosh also received inquiries from Nepal and South Africa, where she will start exporting the seeds soon.","innovation_details":"Sixteen years ago, Santosh Pachar bought some carrots for home consumption from a farmer named Mahavir from Laxmangarh Tehsil. The forked roots of carrots were very small, and the carrots were very good in appearance and taste. She admired the quality of carrots and wanted to cultivate such improved carrots on her farm. She adopted the route-to-seed methodology of planting at her farm to produce the seeds of the above-mentioned carrot. The selection standard of carrot for seed was sweetness, long route length, vermilion color, and softness. From the first year of the plantation, she collected the seeds, sowed them again in a small area of the field, and continuously adopted the same standard of selection method for 4 to 5 years. This was useful in stabilizing the desirable characteristics of the improvised carrots. Instead of conventional insecticides and pesticides, she used neem oil to control insects, pests, and diseases in her field.Her improved variety of seeds is well adapted to high temperatures. The length of her carrot is up to 1.5 ft, with a very low percentage of forked roots. It takes around 2.5 to 3 months to be completely ready and is resistant to any pest and disease attack. It yields almost 630qt/ha and is less hairy. It’s the best quality carrots containing a sweet taste which fetch high market price due to its quality.Smt. Santosh Pachar received recognition, selection in the residence program of Rashtrapati Bhavan, and a national award at the 7th National Grassroots Innovation Awards.","innovator_images":["https://gian.org/wp-content/uploads/2024/11/Smt.-Santosh-Pachar.png"],"innovation_images":["https://gian.org/wp-content/uploads/2024/11/santosh-pachar_rj-1-transformed.jpeg"],"multimedia_links":["https://www.youtube.com/watch?v=Q9kxZDRi8m4"],"tags":["farmer"],"latitude":27.6683917,"longitude":75.1662121,"listing_excerpt":"Smt. Santosh Pachar"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('gas-samovar', 'shazia-jan-ananthnag-jammu-kashmir', 'Shazia Jan', 'Gas Samovar', 'A traditional Kashmiri kettle used to boil, brew and serve tea is known as a ‘Samovar’, which uses coal as fuel. As the youngest child in a farmer’s family, Shazia prepared and carried the Samovar to her father and brother in the field. Using it regularly, she realized the problems associated with handling it. It was a lot of effort to get one cup of Namkeen tea. Using coal as fuel in the traditional Samovar is time-consuming, produces a lot of ashes, irritates the eye, causes black patches on hands and clothes, and many other problems.Mrs. Shazia Jan devised a design to use LPG as fuel in a Samovar and proposed her design to her father. There was no one to make modified burners and regulators for the samovar even though the concept and design were ready. Unable to find a suitable vendor, Shazia decided to proceed independently. After numerous attempts, she worked on the burner, developed a curved burner, and successfully designed and modified the traditional samovar with the LPG samovar. The modified LPG Samovar takes only 10 to 15 minutes to make 25 cups of tea, saving precious time and a lot of human effort without producing any eye irritation or ash.Shazia Jan’s innovation has been popularized through various media and received many awards, including the state award in the 8th National Grassroots Innovation Award ceremony.', 'https://gian.org/multilingual_data/gas-samovar/', 'https://gian.org/wp-content/uploads/2024/11/Gas-Samovar.jpeg', '["https://gian.org/wp-content/uploads/2024/11/Gas-Samovar.jpeg"]'::jsonb, '["https://www.youtube.com/watch?v=Eo7cL2vHcNo"]'::jsonb, 'Ananthnag , Jammu & Kashmir', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Shazia Jan"},{"key":"Location","value":"Ananthnag , Jammu & Kashmir"},{"key":"Details of Innovation","value":"A traditional Kashmiri kettle used to boil, brew and serve tea is known as a ‘Samovar’, which uses coal as fuel. As the youngest child in a farmer’s family, Shazia prepared and carried the Samovar to her father and brother in the field. Using it regularly, she realized the problems associated with handling it. It was a lot of effort to get one cup of Namkeen tea. Using coal as fuel in the traditional Samovar is time-consuming, produces a lot of ashes, irritates the eye, causes black patches on hands and clothes, and many other problems.Mrs. Shazia Jan devised a design to use LPG as fuel in a Samovar and proposed her design to her father. There was no one to make modified burners and regulators for the samovar even though the concept and design were ready. Unable to find a suitable vendor, Shazia decided to proceed independently. After numerous attempts, she worked on the burner, developed a curved burner, and successfully designed and modified the traditional samovar with the LPG samovar. The modified LPG Samovar takes only 10 to 15 minutes to make 25 cups of tea, saving precious time and a lot of human effort without producing any eye irritation or ash.Shazia Jan’s innovation has been popularized through various media and received many awards, including the state award in the 8th National Grassroots Innovation Award ceremony."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=Eo7cL2vHcNo"}]'::jsonb, ARRAY['safety', 'farmer']::text[], 'Gas Samovar Shazia Jan Ananthnag , Jammu & Kashmir Young innovator Mrs. Shazia Jan, from Jammu and Kashmir, modified a traditional samovar to a modern gas Samovar, recognized and further supported by GIAN cell Jammu and Kashmir along with the Honey Bee Network. A patent was filed in her name by NIF, and the future optimization and designing, along with safety aspects, was taken care of by GIAN cell Jammu and Kashmir. A traditional Kashmiri kettle used to boil, brew and serve tea is known as a ‘Samovar’, which uses coal as fuel. As the youngest child in a farmer’s family, Shazia prepared and carried the Samovar to her father and brother in the field. Using it regularly, she realized the problems associated with handling it. It was a lot of effort to get one cup of Namkeen tea. Using coal as fuel in the traditional Samovar is time-consuming, produces a lot of ashes, irritates the eye, causes black patches on hands and clothes, and many other problems.Mrs. Shazia Jan devised a design to use LPG as fuel in a Samovar and proposed her design to her father. There was no one to make modified burners and regulators for the samovar even though the concept and design were ready. Unable to find a suitable vendor, Shazia decided to proceed independently. After numerous attempts, she worked on the burner, developed a curved burner, and successfully designed and modified the traditional samovar with the LPG samovar. The modified LPG Samovar takes only 10 to 15 minutes to make 25 cups of tea, saving precious time and a lot of human effort without producing any eye irritation or ash.Shazia Jan’s innovation has been popularized through various media and received many awards, including the state award in the 8th National Grassroots Innovation Award ceremony. safety farmer https://www.youtube.com/watch?v=Eo7cL2vHcNo', '{"innovation_slug":"gas-samovar","detail_url":"https://gian.org/multilingual_data/gas-samovar/","innovation_title":"Gas Samovar","innovator_name":"Shazia Jan","location":"Ananthnag , Jammu & Kashmir","innovator_bio":"Young innovator Mrs. Shazia Jan, from Jammu and Kashmir, modified a traditional samovar to a modern gas Samovar, recognized and further supported by GIAN cell Jammu and Kashmir along with the Honey Bee Network. A patent was filed in her name by NIF, and the future optimization and designing, along with safety aspects, was taken care of by GIAN cell Jammu and Kashmir.","innovation_details":"A traditional Kashmiri kettle used to boil, brew and serve tea is known as a ‘Samovar’, which uses coal as fuel. As the youngest child in a farmer’s family, Shazia prepared and carried the Samovar to her father and brother in the field. Using it regularly, she realized the problems associated with handling it. It was a lot of effort to get one cup of Namkeen tea. Using coal as fuel in the traditional Samovar is time-consuming, produces a lot of ashes, irritates the eye, causes black patches on hands and clothes, and many other problems.Mrs. Shazia Jan devised a design to use LPG as fuel in a Samovar and proposed her design to her father. There was no one to make modified burners and regulators for the samovar even though the concept and design were ready. Unable to find a suitable vendor, Shazia decided to proceed independently. After numerous attempts, she worked on the burner, developed a curved burner, and successfully designed and modified the traditional samovar with the LPG samovar. The modified LPG Samovar takes only 10 to 15 minutes to make 25 cups of tea, saving precious time and a lot of human effort without producing any eye irritation or ash.Shazia Jan’s innovation has been popularized through various media and received many awards, including the state award in the 8th National Grassroots Innovation Award ceremony.","innovator_images":["https://gian.org/wp-content/uploads/2024/11/Shazia-jan-.png"],"innovation_images":["https://gian.org/wp-content/uploads/2024/11/Gas-Samovar.jpeg"],"multimedia_links":["https://www.youtube.com/watch?v=Eo7cL2vHcNo"],"tags":["safety","farmer"],"latitude":33.5375562,"longitude":75.1311874,"listing_excerpt":"Shazia Jan"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('herbal-formulation-for-pest-control-kamaal-505', 'shri-ishwar-singh-kundu-kaithal-haryana', 'Shri Ishwar Singh Kundu', 'Herbal formulation for pest control: Kamaal 505', 'It was in October 2001 that Ishwar Singh started working on formulation and experiments on horrible insecticides and pesticides. He used to perform trials on his farm. His perspective was that the conventional formulation was causing air, soil, and water pollution. Also, human health and cattle health was affected by the chemical-based products. Hence, he made herbal products, including fertilizers, pesticides, insecticides, etc. In 2004, one of his friends from a nearby village showed interest in his work and offered support. The hard part for Singh was not the development but explaining and convincing the village farmers about the merits of herbal formulation and the ill effects of conventional pesticides. Somehow, he convinced a few farmers to use his formulations, and the response was very satisfying for farmers. Since then, he has tried many different formulations and has developed a whole herbal farming kit for which he applied for a patent.Many local institutions awarded and recognized the Innovation by Shree Ishwar Singh. He was also awarded the 3rd National Innovation Foundation award.', 'https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/', 'https://gian.org/wp-content/uploads/2024/11/Screenshot-2024-03-07-164529.png', '["https://gian.org/wp-content/uploads/2024/11/Screenshot-2024-03-07-164529.png"]'::jsonb, '["https://www.youtube.com/watch?v=LLukDK-uq3c"]'::jsonb, 'Kaithal , Haryana', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Shri Ishwar Singh Kundu"},{"key":"Location","value":"Kaithal , Haryana"},{"key":"Details of Innovation","value":"It was in October 2001 that Ishwar Singh started working on formulation and experiments on horrible insecticides and pesticides. He used to perform trials on his farm. His perspective was that the conventional formulation was causing air, soil, and water pollution. Also, human health and cattle health was affected by the chemical-based products. Hence, he made herbal products, including fertilizers, pesticides, insecticides, etc. In 2004, one of his friends from a nearby village showed interest in his work and offered support. The hard part for Singh was not the development but explaining and convincing the village farmers about the merits of herbal formulation and the ill effects of conventional pesticides. Somehow, he convinced a few farmers to use his formulations, and the response was very satisfying for farmers. Since then, he has tried many different formulations and has developed a whole herbal farming kit for which he applied for a patent.Many local institutions awarded and recognized the Innovation by Shree Ishwar Singh. He was also awarded the 3rd National Innovation Foundation award."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=LLukDK-uq3c"}]'::jsonb, ARRAY['health', 'water', 'farmer']::text[], 'Herbal formulation for pest control: Kamaal 505 Shri Ishwar Singh Kundu Kaithal , Haryana The innovator, Shri Ishwar Singh Kundu, 45 years old, a moderately educated farmer, developed a multi-utility herbal formulation aided by GIAN and the Honey Bee Network. It was also financially supported by GIAN in affiliation with MVIF. Shri Ishwar Singh Kundu’s life was full of ups and downs and many hardships from 1988 – 2000. He tried many jobs and work, but it was all in vain. Despite this, he developed a multi-specialty herbal formulation, which is a great success now. It was in October 2001 that Ishwar Singh started working on formulation and experiments on horrible insecticides and pesticides. He used to perform trials on his farm. His perspective was that the conventional formulation was causing air, soil, and water pollution. Also, human health and cattle health was affected by the chemical-based products. Hence, he made herbal products, including fertilizers, pesticides, insecticides, etc. In 2004, one of his friends from a nearby village showed interest in his work and offered support. The hard part for Singh was not the development but explaining and convincing the village farmers about the merits of herbal formulation and the ill effects of conventional pesticides. Somehow, he convinced a few farmers to use his formulations, and the response was very satisfying for farmers. Since then, he has tried many different formulations and has developed a whole herbal farming kit for which he applied for a patent.Many local institutions awarded and recognized the Innovation by Shree Ishwar Singh. He was also awarded the 3rd National Innovation Foundation award. health water farmer https://www.youtube.com/watch?v=LLukDK-uq3c', '{"innovation_slug":"herbal-formulation-for-pest-control-kamaal-505","detail_url":"https://gian.org/multilingual_data/herbal-formulation-for-pest-control-kamaal-505/","innovation_title":"Herbal formulation for pest control: Kamaal 505","innovator_name":"Shri Ishwar Singh Kundu","location":"Kaithal , Haryana","innovator_bio":"The innovator, Shri Ishwar Singh Kundu, 45 years old, a moderately educated farmer, developed a multi-utility herbal formulation aided by GIAN and the Honey Bee Network. It was also financially supported by GIAN in affiliation with MVIF. Shri Ishwar Singh Kundu’s life was full of ups and downs and many hardships from 1988 – 2000. He tried many jobs and work, but it was all in vain. Despite this, he developed a multi-specialty herbal formulation, which is a great success now.","innovation_details":"It was in October 2001 that Ishwar Singh started working on formulation and experiments on horrible insecticides and pesticides. He used to perform trials on his farm. His perspective was that the conventional formulation was causing air, soil, and water pollution. Also, human health and cattle health was affected by the chemical-based products. Hence, he made herbal products, including fertilizers, pesticides, insecticides, etc. In 2004, one of his friends from a nearby village showed interest in his work and offered support. The hard part for Singh was not the development but explaining and convincing the village farmers about the merits of herbal formulation and the ill effects of conventional pesticides. Somehow, he convinced a few farmers to use his formulations, and the response was very satisfying for farmers. Since then, he has tried many different formulations and has developed a whole herbal farming kit for which he applied for a patent.Many local institutions awarded and recognized the Innovation by Shree Ishwar Singh. He was also awarded the 3rd National Innovation Foundation award.","innovator_images":["https://gian.org/wp-content/uploads/2024/11/Screenshot-2024-03-07-163838.png"],"innovation_images":["https://gian.org/wp-content/uploads/2024/11/Screenshot-2024-03-07-164529.png"],"multimedia_links":["https://www.youtube.com/watch?v=LLukDK-uq3c"],"tags":["health","water","farmer"],"latitude":29.649819,"longitude":76.2942507,"listing_excerpt":"Ishwar Singh Kundu"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('multi-purpose-food-processing-machines', 'dharambir-kambhoj-yamunanagar-haryana', 'Dharambir Kambhoj', 'Multi-Purpose Food Processing Machines', 'In 2002, Dharambir met a bank manager who visited their village to promote aloe vera farming and discussed the aloe vera gel extractor machine. However, due to the high cost of the machine and the extra high consultation charges, Dharambir decided to develop one of his food processing machines in 2003 and completed the prototype by March 2005.The prototype had a heating problem when minimal material was processed. He could not eliminate the problem in the second prototype. In the third prototype, he introduced the castor oil bath, which could maintain the temperature at 200° c. This third prototype was bought by GIAN and sent to Kenya as a pilot. Based on the feedback received, GIAN asked him to modify and further incorporate the provisions that would make transport easier, including foldable legs; Dharambir managed to design a successful prototype.It is a 125 kg multi-purpose processing machine with only a single-phase motor and can process various herbal plants and fruits. Its motor Speed is 1440 RPM which works at the speed of 360 RPM, and it can extract 1 to 50 kg of juice/gel/extract per hour. It contains two electric heaters, an automatic temperature cut-off, and a starter panel with electricity consumption of 1.5 machines per hour.Dharambir’s innovation has obtained widespread recognition and was awarded by the National Innovation Foundation with the Haryana state award in the 5th National biennial award function.', 'https://gian.org/multilingual_data/multi-purpose-food-processing-machines/', 'https://gian.org/wp-content/uploads/2024/11/Food-processing-machine.png', '["https://gian.org/wp-content/uploads/2024/11/Food-processing-machine.png","https://gian.org/wp-content/uploads/2024/11/food-processing-machine-1-1.png"]'::jsonb, '["https://www.youtube.com/watch?v=KqvcCYtdyOA"]'::jsonb, 'Yamunanagar , Haryana', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Dharambir Kambhoj"},{"key":"Location","value":"Yamunanagar , Haryana"},{"key":"Details of Innovation","value":"In 2002, Dharambir met a bank manager who visited their village to promote aloe vera farming and discussed the aloe vera gel extractor machine. However, due to the high cost of the machine and the extra high consultation charges, Dharambir decided to develop one of his food processing machines in 2003 and completed the prototype by March 2005.The prototype had a heating problem when minimal material was processed. He could not eliminate the problem in the second prototype. In the third prototype, he introduced the castor oil bath, which could maintain the temperature at 200° c. This third prototype was bought by GIAN and sent to Kenya as a pilot. Based on the feedback received, GIAN asked him to modify and further incorporate the provisions that would make transport easier, including foldable legs; Dharambir managed to design a successful prototype.It is a 125 kg multi-purpose processing machine with only a single-phase motor and can process various herbal plants and fruits. Its motor Speed is 1440 RPM which works at the speed of 360 RPM, and it can extract 1 to 50 kg of juice/gel/extract per hour. It contains two electric heaters, an automatic temperature cut-off, and a starter panel with electricity consumption of 1.5 machines per hour.Dharambir’s innovation has obtained widespread recognition and was awarded by the National Innovation Foundation with the Haryana state award in the 5th National biennial award function."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=KqvcCYtdyOA"}]'::jsonb, ARRAY['fruit', 'machine', 'food', 'processing', 'farmer']::text[], 'Multi-Purpose Food Processing Machines Dharambir Kambhoj Yamunanagar , Haryana Dharambir Kambhoj is an amazing innovator who has encountered lots of hardships with a touch of luck. He is a 59-year-old farmer cum innovator from Haryana who has designed a multi-purpose food processing machine guided and supported by GIAN and the Honey Bee Network. GIAN bolstered the innovative design and patenting process in the year 2008. GIAN also supported it under (MVIF) for prototype development and test marketing. Dharambir was the youngest of all five siblings; his father was a farmer and operated a small flour mill and a jaggery processing plant. His mother was a herbalist. Inherited from both of his parents, Dharambir is a farmer, a herbalist, and an innovator. Today he is a successful entrepreneur selling his patented machines to 15 countries. In 2002, Dharambir met a bank manager who visited their village to promote aloe vera farming and discussed the aloe vera gel extractor machine. However, due to the high cost of the machine and the extra high consultation charges, Dharambir decided to develop one of his food processing machines in 2003 and completed the prototype by March 2005.The prototype had a heating problem when minimal material was processed. He could not eliminate the problem in the second prototype. In the third prototype, he introduced the castor oil bath, which could maintain the temperature at 200° c. This third prototype was bought by GIAN and sent to Kenya as a pilot. Based on the feedback received, GIAN asked him to modify and further incorporate the provisions that would make transport easier, including foldable legs; Dharambir managed to design a successful prototype.It is a 125 kg multi-purpose processing machine with only a single-phase motor and can process various herbal plants and fruits. Its motor Speed is 1440 RPM which works at the speed of 360 RPM, and it can extract 1 to 50 kg of juice/gel/extract per hour. It contains two electric heaters, an automatic temperature cut-off, and a starter panel with electricity consumption of 1.5 machines per hour.Dharambir’s innovation has obtained widespread recognition and was awarded by the National Innovation Foundation with the Haryana state award in the 5th National biennial award function. fruit machine food processing farmer https://www.youtube.com/watch?v=KqvcCYtdyOA', '{"innovation_slug":"multi-purpose-food-processing-machines","detail_url":"https://gian.org/multilingual_data/multi-purpose-food-processing-machines/","innovation_title":"Multi-Purpose Food Processing Machines","innovator_name":"Dharambir Kambhoj","location":"Yamunanagar , Haryana","innovator_bio":"Dharambir Kambhoj is an amazing innovator who has encountered lots of hardships with a touch of luck. He is a 59-year-old farmer cum innovator from Haryana who has designed a multi-purpose food processing machine guided and supported by GIAN and the Honey Bee Network. GIAN bolstered the innovative design and patenting process in the year 2008. GIAN also supported it under (MVIF) for prototype development and test marketing. Dharambir was the youngest of all five siblings; his father was a farmer and operated a small flour mill and a jaggery processing plant. His mother was a herbalist. Inherited from both of his parents, Dharambir is a farmer, a herbalist, and an innovator. Today he is a successful entrepreneur selling his patented machines to 15 countries.","innovation_details":"In 2002, Dharambir met a bank manager who visited their village to promote aloe vera farming and discussed the aloe vera gel extractor machine. However, due to the high cost of the machine and the extra high consultation charges, Dharambir decided to develop one of his food processing machines in 2003 and completed the prototype by March 2005.The prototype had a heating problem when minimal material was processed. He could not eliminate the problem in the second prototype. In the third prototype, he introduced the castor oil bath, which could maintain the temperature at 200° c. This third prototype was bought by GIAN and sent to Kenya as a pilot. Based on the feedback received, GIAN asked him to modify and further incorporate the provisions that would make transport easier, including foldable legs; Dharambir managed to design a successful prototype.It is a 125 kg multi-purpose processing machine with only a single-phase motor and can process various herbal plants and fruits. Its motor Speed is 1440 RPM which works at the speed of 360 RPM, and it can extract 1 to 50 kg of juice/gel/extract per hour. It contains two electric heaters, an automatic temperature cut-off, and a starter panel with electricity consumption of 1.5 machines per hour.Dharambir’s innovation has obtained widespread recognition and was awarded by the National Innovation Foundation with the Haryana state award in the 5th National biennial award function.","innovator_images":["https://gian.org/wp-content/uploads/2024/11/Dharambir-Khamboj-.png"],"innovation_images":["https://gian.org/wp-content/uploads/2024/11/Food-processing-machine.png","https://gian.org/wp-content/uploads/2024/11/food-processing-machine-1-1.png"],"multimedia_links":["https://www.youtube.com/watch?v=KqvcCYtdyOA"],"tags":["fruit","machine","food","processing","farmer"],"latitude":30.1014803,"longitude":77.2749964,"listing_excerpt":"Multi-Purpose Food Processing Machine by Dharambir Kambhoj"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('mitticool-clay-creation', 'mansukhbhai-prajapati-rajkot-gujarat', 'Mansukhbhai Prajapati', 'Mitticool Clay Creation', 'Mansukhbhai Prajapati, a 48-year-old innovator from Wankaner village, Rajkot, Gujarat, was supported and financially aided by angel investor Prof. Anil Gupta, professor at IIM Ahmedabad, founder of the Honey Bee Network and vice chairman of the National Innovation Foundation. GIAN was a helping hand in establishing a company named Clay Creation in 2008. GIAN also assisted Mansukhbhai in developing the online retail portal www.mitticool.in. GIAN also added value to the original innovations of Mansukhbhai by suggesting small but beneficial ideas and helping him design the packaging material. Mansukh Bhai offered his heartfelt gratitude towards GIAN and Prof. Anil Gupta.Mansukhbhai Prajapati belonged to a poor potter family, studied till 10th std, and started working at a tea stall. He moved from the tea stall to work at a factory. His father and boss were cautious about the risk of starting his own business, but Mansukhbhai started working on his dream. After the 2001 Bhuj earthquake, his journey of innovation started, and today Mitticool Creation sells more than 250 clay products and is ISO certified.', 'https://gian.org/multilingual_data/mitticool-clay-creation/', 'https://gian.org/wp-content/uploads/2024/11/mitticool-678x1024.jpg', '["https://gian.org/wp-content/uploads/2024/11/mitticool-678x1024.jpg","https://gian.org/wp-content/uploads/2024/11/mitticool-scaled.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=u3f-8WvYyKY"]'::jsonb, 'Rajkot , Gujarat', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mansukhbhai Prajapati"},{"key":"Location","value":"Rajkot , Gujarat"},{"key":"Details of Innovation","value":"Mansukhbhai Prajapati, a 48-year-old innovator from Wankaner village, Rajkot, Gujarat, was supported and financially aided by angel investor Prof. Anil Gupta, professor at IIM Ahmedabad, founder of the Honey Bee Network and vice chairman of the National Innovation Foundation. GIAN was a helping hand in establishing a company named Clay Creation in 2008. GIAN also assisted Mansukhbhai in developing the online retail portal www.mitticool.in. GIAN also added value to the original innovations of Mansukhbhai by suggesting small but beneficial ideas and helping him design the packaging material. Mansukh Bhai offered his heartfelt gratitude towards GIAN and Prof. Anil Gupta.Mansukhbhai Prajapati belonged to a poor potter family, studied till 10th std, and started working at a tea stall. He moved from the tea stall to work at a factory. His father and boss were cautious about the risk of starting his own business, but Mansukhbhai started working on his dream. After the 2001 Bhuj earthquake, his journey of innovation started, and today Mitticool Creation sells more than 250 clay products and is ISO certified."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=u3f-8WvYyKY"}]'::jsonb, ARRAY['food', 'health']::text[], 'Mitticool Clay Creation Mansukhbhai Prajapati Rajkot , Gujarat In 2003, Mansukhbhai’s wife asked him to bring a non-stick tawa from the market; this was when the innovation journey of Mitticool Creations started. As he inquired about the non-stick pan in the market, he found out that it cost a minimum of rupees 200, and the coating wears off quite soon. Teflon-coated cookware does not retain the food’s natural taste and harms stomach health. This inspired him to make the non-stick tawa out of clay which retains the natural taste of food and is not harmful if the coating wears off. He also innovated a refrigerator made out of clay which does not need any external energy source for the cooling effect. Today Mitticool Creations has a whole variety of products made out of clay and is a successful company. Mitticool Creations won many awards, including a national award for most innovative products by the Ministry of Rural Development, a true scientist by the past president of India, Dr. APJ Abdul Kalam, in the fourth national award function in Delhi, a state award from Narendra Modi Chief Minister of Gujarat, an award by India Book of Records as an innovator of the year, and an award for global clay products innovator by Global Records. Also, Mitticool Creation was the first grassroots innovator to receive ISO certification recognition. Mansukhbhai Prajapati, a 48-year-old innovator from Wankaner village, Rajkot, Gujarat, was supported and financially aided by angel investor Prof. Anil Gupta, professor at IIM Ahmedabad, founder of the Honey Bee Network and vice chairman of the National Innovation Foundation. GIAN was a helping hand in establishing a company named Clay Creation in 2008. GIAN also assisted Mansukhbhai in developing the online retail portal www.mitticool.in. GIAN also added value to the original innovations of Mansukhbhai by suggesting small but beneficial ideas and helping him design the packaging material. Mansukh Bhai offered his heartfelt gratitude towards GIAN and Prof. Anil Gupta.Mansukhbhai Prajapati belonged to a poor potter family, studied till 10th std, and started working at a tea stall. He moved from the tea stall to work at a factory. His father and boss were cautious about the risk of starting his own business, but Mansukhbhai started working on his dream. After the 2001 Bhuj earthquake, his journey of innovation started, and today Mitticool Creation sells more than 250 clay products and is ISO certified. food health https://www.youtube.com/watch?v=u3f-8WvYyKY', '{"innovation_slug":"mitticool-clay-creation","detail_url":"https://gian.org/multilingual_data/mitticool-clay-creation/","innovation_title":"Mitticool Clay Creation","innovator_name":"Mansukhbhai Prajapati","location":"Rajkot , Gujarat","innovator_bio":"In 2003, Mansukhbhai’s wife asked him to bring a non-stick tawa from the market; this was when the innovation journey of Mitticool Creations started. As he inquired about the non-stick pan in the market, he found out that it cost a minimum of rupees 200, and the coating wears off quite soon. Teflon-coated cookware does not retain the food’s natural taste and harms stomach health. This inspired him to make the non-stick tawa out of clay which retains the natural taste of food and is not harmful if the coating wears off. He also innovated a refrigerator made out of clay which does not need any external energy source for the cooling effect. Today Mitticool Creations has a whole variety of products made out of clay and is a successful company. Mitticool Creations won many awards, including a national award for most innovative products by the Ministry of Rural Development, a true scientist by the past president of India, Dr. APJ Abdul Kalam, in the fourth national award function in Delhi, a state award from Narendra Modi Chief Minister of Gujarat, an award by India Book of Records as an innovator of the year, and an award for global clay products innovator by Global Records. Also, Mitticool Creation was the first grassroots innovator to receive ISO certification recognition.","innovation_details":"Mansukhbhai Prajapati, a 48-year-old innovator from Wankaner village, Rajkot, Gujarat, was supported and financially aided by angel investor Prof. Anil Gupta, professor at IIM Ahmedabad, founder of the Honey Bee Network and vice chairman of the National Innovation Foundation. GIAN was a helping hand in establishing a company named Clay Creation in 2008. GIAN also assisted Mansukhbhai in developing the online retail portal www.mitticool.in. GIAN also added value to the original innovations of Mansukhbhai by suggesting small but beneficial ideas and helping him design the packaging material. Mansukh Bhai offered his heartfelt gratitude towards GIAN and Prof. Anil Gupta.Mansukhbhai Prajapati belonged to a poor potter family, studied till 10th std, and started working at a tea stall. He moved from the tea stall to work at a factory. His father and boss were cautious about the risk of starting his own business, but Mansukhbhai started working on his dream. After the 2001 Bhuj earthquake, his journey of innovation started, and today Mitticool Creation sells more than 250 clay products and is ISO certified.","innovator_images":["https://gian.org/wp-content/uploads/2024/11/Mansukhbhai-mitticool_upscayl_4x_ultrasharp.png"],"innovation_images":["https://gian.org/wp-content/uploads/2024/11/mitticool-678x1024.jpg","https://gian.org/wp-content/uploads/2024/11/mitticool-scaled.jpg"],"multimedia_links":["https://www.youtube.com/watch?v=u3f-8WvYyKY"],"tags":["food","health"],"latitude":22.66043656,"longitude":70.95025339,"listing_excerpt":"Mansukhbhai Prajapati, a 48-year-old innovator from Wankaner village, Rajkot, Gujarat, was supported and financially aided by angel investor Prof. Anil Gupta, professor at IIM Ahmedabad,"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('foldable-cylinder-carrier', 'mr-mushtaq-ahmad-dar-jammu-and-kashmir', 'Mr. Mushtaq Ahmad Dar', 'Foldable Cylinder Carrier', 'Innovation Description: Mr. Mushtaq Ahmad Dar made a foldable gas carrier which can be used to carry gas cylinders. This makes it easy for a person to carry the cylinder from one place to another. The carrier is foldable, easy to use for even women and children, and has a loading capacity up to 60 kg. Its production cost is Rs.350/- per unit and selling price is 500/- per unit (excluding GST 18%). Its expected sale is 1000 units per year. Mushtaq’s innovation got financial support from MVIF under GIAN and SIDBI for marketing. It was also awarded in 5th National Grassroots Innovation Awards 2009.', 'https://gian.org/multilingual_data/foldable-cylinder-carrier/', 'https://gian.org/wp-content/uploads/2023/06/image049.jpg', '["https://gian.org/wp-content/uploads/2023/06/image049.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=E2rGd7Fldo0"]'::jsonb, 'Jammu and Kashmir', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Mushtaq Ahmad Dar"},{"key":"Location","value":"Jammu and Kashmir"},{"key":"Details of Innovation","value":"Innovation Description: Mr. Mushtaq Ahmad Dar made a foldable gas carrier which can be used to carry gas cylinders. This makes it easy for a person to carry the cylinder from one place to another. The carrier is foldable, easy to use for even women and children, and has a loading capacity up to 60 kg. Its production cost is Rs.350/- per unit and selling price is 500/- per unit (excluding GST 18%). Its expected sale is 1000 units per year. Mushtaq’s innovation got financial support from MVIF under GIAN and SIDBI for marketing. It was also awarded in 5th National Grassroots Innovation Awards 2009."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=E2rGd7Fldo0"}]'::jsonb, ARRAY[]::text[], 'Foldable Cylinder Carrier Mr. Mushtaq Ahmad Dar Jammu and Kashmir Mushtaq Ahmad Dar (28), a young innovator from Kashmir, innovated a foldable cylinder carrier. A ‘full-time’ innovator, Mushtaq also helps his brothers in running the family business and managing the household. Knowing Mushtaq’s creative nature, in 2005, his friend, Zahoor Ahmed Shah brought him to Ahmedabad for NIF’s Third National Innovation Award Function. Mushtaq was intrigued to see and meet so many people from different parts of the country who were not trained or aided but had created so many innovative solutions based on their observation skills, ingenuity, effort and hard work. He was immediately reminded of his troubled home state, which was plagued with unemployment and unrest. He imagined an innovation that, apart from solving a persistent technological problem, would also help in generating employment. Innovation Description: Mr. Mushtaq Ahmad Dar made a foldable gas carrier which can be used to carry gas cylinders. This makes it easy for a person to carry the cylinder from one place to another. The carrier is foldable, easy to use for even women and children, and has a loading capacity up to 60 kg. Its production cost is Rs.350/- per unit and selling price is 500/- per unit (excluding GST 18%). Its expected sale is 1000 units per year. Mushtaq’s innovation got financial support from MVIF under GIAN and SIDBI for marketing. It was also awarded in 5th National Grassroots Innovation Awards 2009. https://www.youtube.com/watch?v=E2rGd7Fldo0', '{"innovation_slug":"foldable-cylinder-carrier","detail_url":"https://gian.org/multilingual_data/foldable-cylinder-carrier/","innovation_title":"Foldable Cylinder Carrier","innovator_name":"Mr. Mushtaq Ahmad Dar","location":"Jammu and Kashmir","innovator_bio":"Mushtaq Ahmad Dar (28), a young innovator from Kashmir, innovated a foldable cylinder carrier. A ‘full-time’ innovator, Mushtaq also helps his brothers in running the family business and managing the household. Knowing Mushtaq’s creative nature, in 2005, his friend, Zahoor Ahmed Shah brought him to Ahmedabad for NIF’s Third National Innovation Award Function. Mushtaq was intrigued to see and meet so many people from different parts of the country who were not trained or aided but had created so many innovative solutions based on their observation skills, ingenuity, effort and hard work. He was immediately reminded of his troubled home state, which was plagued with unemployment and unrest. He imagined an innovation that, apart from solving a persistent technological problem, would also help in generating employment.","innovation_details":"Innovation Description: Mr. Mushtaq Ahmad Dar made a foldable gas carrier which can be used to carry gas cylinders. This makes it easy for a person to carry the cylinder from one place to another. The carrier is foldable, easy to use for even women and children, and has a loading capacity up to 60 kg. Its production cost is Rs.350/- per unit and selling price is 500/- per unit (excluding GST 18%). Its expected sale is 1000 units per year. Mushtaq’s innovation got financial support from MVIF under GIAN and SIDBI for marketing. It was also awarded in 5th National Grassroots Innovation Awards 2009.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image048.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image049.jpg"],"multimedia_links":["https://www.youtube.com/watch?v=E2rGd7Fldo0"],"tags":[],"latitude":33.6241452,"longitude":75.2128996,"listing_excerpt":"Mr. Mushtaq Ahmad Dar"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('cycle-operated-aatachakki', 'gangaram-chauhan-gorakhpur-uttar-pradesh', 'Gangaram Chauhan', 'Cycle Operated Aatachakki', 'Gangaram, a rickshaw repairer and a resident of Ramjanaki Nagar, in Uttar Pradesh, built a cycling mill to grind wheat. During the COVID-19-induced lockdown, he found it very difficult to go to the market to grind the flour and this motivated him to come up with a cycle-operated attachakki. Gangara had to invest Rs 10,000 from his pocket to create this device. He was assisted in his ‘native juggad’ by Gopal Vishwakarma, a teacher teaching mechanical engineering in a college, and Arun Kumar Singh, also a teacher, teaching drawing to polytechnics’ students. Together, it took them two months to come up with the unique cycle-operated attachakki. This innovative floor mill can grind about 8 kg of wheat and other grains in an hour. The machine is easy to use and can be operated by both women and children. Grains are poured in the upper part of the machine, which then flow down to a millstone through a pipe to the bottom compartment for grinding. The cycle-operated attachakki can grind wheat, rice, and other coarse grains with no loss to their nutritional value. The device has attracted much interest with people flocking to see the innovation and also place orders. Gangaram received marketing and prototype development support under MVIF by GIAN and SIDBI in the year 2021. As of now, he has sold two units of his cycle chakki. He also received the innovative farmer award in 2020.', 'https://gian.org/multilingual_data/cycle-operated-aatachakki/', 'https://gian.org/wp-content/uploads/2023/06/image041-768x1024.jpg', '["https://gian.org/wp-content/uploads/2023/06/image041-768x1024.jpg","https://gian.org/wp-content/uploads/2023/06/image041.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=Nd5GnUOx8fg"]'::jsonb, 'Gorakhpur Uttar Pradesh', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Gangaram Chauhan"},{"key":"Location","value":"Gorakhpur Uttar Pradesh"},{"key":"Details of Innovation","value":"Gangaram, a rickshaw repairer and a resident of Ramjanaki Nagar, in Uttar Pradesh, built a cycling mill to grind wheat. During the COVID-19-induced lockdown, he found it very difficult to go to the market to grind the flour and this motivated him to come up with a cycle-operated attachakki. Gangara had to invest Rs 10,000 from his pocket to create this device. He was assisted in his ‘native juggad’ by Gopal Vishwakarma, a teacher teaching mechanical engineering in a college, and Arun Kumar Singh, also a teacher, teaching drawing to polytechnics’ students. Together, it took them two months to come up with the unique cycle-operated attachakki. This innovative floor mill can grind about 8 kg of wheat and other grains in an hour. The machine is easy to use and can be operated by both women and children. Grains are poured in the upper part of the machine, which then flow down to a millstone through a pipe to the bottom compartment for grinding. The cycle-operated attachakki can grind wheat, rice, and other coarse grains with no loss to their nutritional value. The device has attracted much interest with people flocking to see the innovation and also place orders. Gangaram received marketing and prototype development support under MVIF by GIAN and SIDBI in the year 2021. As of now, he has sold two units of his cycle chakki. He also received the innovative farmer award in 2020."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=Nd5GnUOx8fg"}]'::jsonb, ARRAY['machine', 'device', 'farmer']::text[], 'Cycle Operated Aatachakki Gangaram Chauhan Gorakhpur Uttar Pradesh Gangaram Chauhan, 50, holds a bachelor’s degree in commerce. It was about 20 years ago that he started experimenting and in the year 2000, came up with his first innovate product, a rickshaw, which he is improving ever since. Gangaram, a rickshaw repairer and a resident of Ramjanaki Nagar, in Uttar Pradesh, built a cycling mill to grind wheat. During the COVID-19-induced lockdown, he found it very difficult to go to the market to grind the flour and this motivated him to come up with a cycle-operated attachakki. Gangara had to invest Rs 10,000 from his pocket to create this device. He was assisted in his ‘native juggad’ by Gopal Vishwakarma, a teacher teaching mechanical engineering in a college, and Arun Kumar Singh, also a teacher, teaching drawing to polytechnics’ students. Together, it took them two months to come up with the unique cycle-operated attachakki. This innovative floor mill can grind about 8 kg of wheat and other grains in an hour. The machine is easy to use and can be operated by both women and children. Grains are poured in the upper part of the machine, which then flow down to a millstone through a pipe to the bottom compartment for grinding. The cycle-operated attachakki can grind wheat, rice, and other coarse grains with no loss to their nutritional value. The device has attracted much interest with people flocking to see the innovation and also place orders. Gangaram received marketing and prototype development support under MVIF by GIAN and SIDBI in the year 2021. As of now, he has sold two units of his cycle chakki. He also received the innovative farmer award in 2020. machine device farmer https://www.youtube.com/watch?v=Nd5GnUOx8fg', '{"innovation_slug":"cycle-operated-aatachakki","detail_url":"https://gian.org/multilingual_data/cycle-operated-aatachakki/","innovation_title":"Cycle Operated Aatachakki","innovator_name":"Gangaram Chauhan","location":"Gorakhpur Uttar Pradesh","innovator_bio":"Gangaram Chauhan, 50, holds a bachelor’s degree in commerce. It was about 20 years ago that he started experimenting and in the year 2000, came up with his first innovate product, a rickshaw, which he is improving ever since.","innovation_details":"Gangaram, a rickshaw repairer and a resident of Ramjanaki Nagar, in Uttar Pradesh, built a cycling mill to grind wheat. During the COVID-19-induced lockdown, he found it very difficult to go to the market to grind the flour and this motivated him to come up with a cycle-operated attachakki. Gangara had to invest Rs 10,000 from his pocket to create this device. He was assisted in his ‘native juggad’ by Gopal Vishwakarma, a teacher teaching mechanical engineering in a college, and Arun Kumar Singh, also a teacher, teaching drawing to polytechnics’ students. Together, it took them two months to come up with the unique cycle-operated attachakki. This innovative floor mill can grind about 8 kg of wheat and other grains in an hour. The machine is easy to use and can be operated by both women and children. Grains are poured in the upper part of the machine, which then flow down to a millstone through a pipe to the bottom compartment for grinding. The cycle-operated attachakki can grind wheat, rice, and other coarse grains with no loss to their nutritional value. The device has attracted much interest with people flocking to see the innovation and also place orders. Gangaram received marketing and prototype development support under MVIF by GIAN and SIDBI in the year 2021. As of now, he has sold two units of his cycle chakki. He also received the innovative farmer award in 2020.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image040.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image041-768x1024.jpg","https://gian.org/wp-content/uploads/2023/06/image041.jpg"],"multimedia_links":["https://www.youtube.com/watch?v=Nd5GnUOx8fg"],"tags":["machine","device","farmer"],"latitude":26.7918114,"longitude":83.3041061,"listing_excerpt":"Gangaram Chauhan"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('rocket-stove', 'abdul-kareem-k-a-kerala', 'Abdul Kareem K A', 'Rocket Stove', 'The rocket stove is based on a concept developed by the British in the 1850s that comprised an insulated vertical chimney. He had seen this stove in many hotels in Kodaikanal and Munnar. The stove is constructed in a way to ensure complete combustion before the flames reach the cooking surface. Abdul conducted some more research on the British stove before making his own version. His version of the stove uses 4 mm mild steel sheets and stainless steel sheets to make the oven chamber. The raw material is easily available both in his company and the market. He tested the stove outside his house using firewood as fuel. The stove attracted the attention of his relatives, neighbors, and friends who also wanted it for their use. Orders began to pour in and he began commercial manufacturing in his existing facility. The stove requires firewood, coconut shells, and waste paper as fuel and cuts down smoke by 80 percent. Available in four models, the rocket stove is easily portable. The premium model costs Rs 20,000 and weighs 60 kilos. The regular model has two options for cooking and grilling, costs Rs 6,500, and weighs 35 kilos. The basic model has only the cooking option, costs Rs 5,000, and weighs 30 kilos. Abdul also has a fourth kind, which he calls a ‘tour package stove’, intended for cooking on the go. This portable stove costs Rs 7,000 and weighs 20 kilos. “I have four decades of experience in making furnaces, boilers, kitchens and other industrial materials. The rocket stove was developed out of curiosity. Thanks to Covid-19-induced lockdown, I managed to finalize the design about six months ago and now have also started the production,” he says.', 'https://gian.org/multilingual_data/rocket-stove/', 'https://gian.org/wp-content/uploads/2023/06/image032-1024x768.jpg', '["https://gian.org/wp-content/uploads/2023/06/image032-1024x768.jpg","https://gian.org/wp-content/uploads/2023/06/image032.jpg"]'::jsonb, '["https://youtu.be/atXpd2RdUbI"]'::jsonb, 'Kerala', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Abdul Kareem K A"},{"key":"Location","value":"Kerala"},{"key":"Details of Innovation","value":"The rocket stove is based on a concept developed by the British in the 1850s that comprised an insulated vertical chimney. He had seen this stove in many hotels in Kodaikanal and Munnar. The stove is constructed in a way to ensure complete combustion before the flames reach the cooking surface. Abdul conducted some more research on the British stove before making his own version. His version of the stove uses 4 mm mild steel sheets and stainless steel sheets to make the oven chamber. The raw material is easily available both in his company and the market. He tested the stove outside his house using firewood as fuel. The stove attracted the attention of his relatives, neighbors, and friends who also wanted it for their use. Orders began to pour in and he began commercial manufacturing in his existing facility. The stove requires firewood, coconut shells, and waste paper as fuel and cuts down smoke by 80 percent. Available in four models, the rocket stove is easily portable. The premium model costs Rs 20,000 and weighs 60 kilos. The regular model has two options for cooking and grilling, costs Rs 6,500, and weighs 35 kilos. The basic model has only the cooking option, costs Rs 5,000, and weighs 30 kilos. Abdul also has a fourth kind, which he calls a ‘tour package stove’, intended for cooking on the go. This portable stove costs Rs 7,000 and weighs 20 kilos. “I have four decades of experience in making furnaces, boilers, kitchens and other industrial materials. The rocket stove was developed out of curiosity. Thanks to Covid-19-induced lockdown, I managed to finalize the design about six months ago and now have also started the production,” he says."},{"key":"Multimedia Links","value":"https://youtu.be/atXpd2RdUbI"}]'::jsonb, ARRAY['food']::text[], 'Rocket Stove Abdul Kareem K A Kerala Abdul Kareem, 57, attributes his latest innovation inspiration to the lockdown that happened to control the COVID 19 pandemic. He has been running his own company — Excellent, in Kochi for the past 40 years, “I have been making products such as boilers, and many industrial materials. During the lockdown period, I thought what if electricity and LPG supply stopped one day? What alternative can I use to cook food? Even though traditional stoves are available in Kerala, many people hesitate to use them due to the thick smoke they give out. That’s when I started work on my rocket stove,” he says. The rocket stove is based on a concept developed by the British in the 1850s that comprised an insulated vertical chimney. He had seen this stove in many hotels in Kodaikanal and Munnar. The stove is constructed in a way to ensure complete combustion before the flames reach the cooking surface. Abdul conducted some more research on the British stove before making his own version. His version of the stove uses 4 mm mild steel sheets and stainless steel sheets to make the oven chamber. The raw material is easily available both in his company and the market. He tested the stove outside his house using firewood as fuel. The stove attracted the attention of his relatives, neighbors, and friends who also wanted it for their use. Orders began to pour in and he began commercial manufacturing in his existing facility. The stove requires firewood, coconut shells, and waste paper as fuel and cuts down smoke by 80 percent. Available in four models, the rocket stove is easily portable. The premium model costs Rs 20,000 and weighs 60 kilos. The regular model has two options for cooking and grilling, costs Rs 6,500, and weighs 35 kilos. The basic model has only the cooking option, costs Rs 5,000, and weighs 30 kilos. Abdul also has a fourth kind, which he calls a ‘tour package stove’, intended for cooking on the go. This portable stove costs Rs 7,000 and weighs 20 kilos. “I have four decades of experience in making furnaces, boilers, kitchens and other industrial materials. The rocket stove was developed out of curiosity. Thanks to Covid-19-induced lockdown, I managed to finalize the design about six months ago and now have also started the production,” he says. food https://youtu.be/atXpd2RdUbI', '{"innovation_slug":"rocket-stove","detail_url":"https://gian.org/multilingual_data/rocket-stove/","innovation_title":"Rocket Stove","innovator_name":"Abdul Kareem K A","location":"Kerala","innovator_bio":"Abdul Kareem, 57, attributes his latest innovation inspiration to the lockdown that happened to control the COVID 19 pandemic. He has been running his own company — Excellent, in Kochi for the past 40 years, “I have been making products such as boilers, and many industrial materials. During the lockdown period, I thought what if electricity and LPG supply stopped one day? What alternative can I use to cook food? Even though traditional stoves are available in Kerala, many people hesitate to use them due to the thick smoke they give out. That’s when I started work on my rocket stove,” he says.","innovation_details":"The rocket stove is based on a concept developed by the British in the 1850s that comprised an insulated vertical chimney. He had seen this stove in many hotels in Kodaikanal and Munnar. The stove is constructed in a way to ensure complete combustion before the flames reach the cooking surface. Abdul conducted some more research on the British stove before making his own version. His version of the stove uses 4 mm mild steel sheets and stainless steel sheets to make the oven chamber. The raw material is easily available both in his company and the market. He tested the stove outside his house using firewood as fuel. The stove attracted the attention of his relatives, neighbors, and friends who also wanted it for their use. Orders began to pour in and he began commercial manufacturing in his existing facility. The stove requires firewood, coconut shells, and waste paper as fuel and cuts down smoke by 80 percent. Available in four models, the rocket stove is easily portable. The premium model costs Rs 20,000 and weighs 60 kilos. The regular model has two options for cooking and grilling, costs Rs 6,500, and weighs 35 kilos. The basic model has only the cooking option, costs Rs 5,000, and weighs 30 kilos. Abdul also has a fourth kind, which he calls a ‘tour package stove’, intended for cooking on the go. This portable stove costs Rs 7,000 and weighs 20 kilos. “I have four decades of experience in making furnaces, boilers, kitchens and other industrial materials. The rocket stove was developed out of curiosity. Thanks to Covid-19-induced lockdown, I managed to finalize the design about six months ago and now have also started the production,” he says.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image031.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image032-1024x768.jpg","https://gian.org/wp-content/uploads/2023/06/image032.jpg"],"multimedia_links":["https://youtu.be/atXpd2RdUbI"],"tags":["food"],"latitude":10.047943,"longitude":76.3695167,"listing_excerpt":"Rocket Stove by Abdul Kareem K A"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('snow-remover', 'mr-aabid-rehman-dar-jammu-kashmir', 'Mr. Aabid Rehman Dar', 'Snow Remover', 'The Kashmir valley witnesses heavy snow along with snowfall during the winter months from December to February, closing major roads and bringing mobility to a halt. Heavy snow cutter machines/vehicles are used to clean the roads, and depending on the level of snow, the process can take around 2 to 3 days. While it is easier to clean the arterial roads, the narrow paths are left with snow, which reduces mobility and sometimes even leads to people falling and getting fractures. Locals usually clean out these paths with spades; however, this is a cumbersome task and would be better performed with a mini-machine. However, with no such solution available in the market, Aabid Rehman Dar came up with the idea of a mini snow remover. Agriculture comes to a close in Kashmir during the winter months and the mini tiller machines used to plough the fields remain idle. Aabid decided to modify the tillers and use them as snow remover machines. To do this, he added an attachment to the tiller that could plough the snow from the roads. The attachment is fitted in the front of the tiller and is detachable – it can be attached or detached using 2 bolts, taking upto 2 minutes. The device comprises of a curved shovel blade having 48 inches of curved width. It can clean the snow from 36 inches of snow from the surface of in just one go. The whole device remains unchanged in its design & operational activity which adds novelty to this innovation.', 'https://gian.org/multilingual_data/snow-remover/', 'https://gian.org/wp-content/uploads/2023/06/image030.jpg', '["https://gian.org/wp-content/uploads/2023/06/image030.jpg","https://gian.org/wp-content/uploads/2023/06/image029.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=tEMI3Kn55Ds"]'::jsonb, 'Jammu & Kashmir', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Aabid Rehman Dar"},{"key":"Location","value":"Jammu & Kashmir"},{"key":"Details of Innovation","value":"The Kashmir valley witnesses heavy snow along with snowfall during the winter months from December to February, closing major roads and bringing mobility to a halt. Heavy snow cutter machines/vehicles are used to clean the roads, and depending on the level of snow, the process can take around 2 to 3 days. While it is easier to clean the arterial roads, the narrow paths are left with snow, which reduces mobility and sometimes even leads to people falling and getting fractures. Locals usually clean out these paths with spades; however, this is a cumbersome task and would be better performed with a mini-machine. However, with no such solution available in the market, Aabid Rehman Dar came up with the idea of a mini snow remover. Agriculture comes to a close in Kashmir during the winter months and the mini tiller machines used to plough the fields remain idle. Aabid decided to modify the tillers and use them as snow remover machines. To do this, he added an attachment to the tiller that could plough the snow from the roads. The attachment is fitted in the front of the tiller and is detachable – it can be attached or detached using 2 bolts, taking upto 2 minutes. The device comprises of a curved shovel blade having 48 inches of curved width. It can clean the snow from 36 inches of snow from the surface of in just one go. The whole device remains unchanged in its design & operational activity which adds novelty to this innovation."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=tEMI3Kn55Ds"}]'::jsonb, ARRAY['agriculture', 'machine', 'device', 'snow']::text[], 'Snow Remover Mr. Aabid Rehman Dar Jammu & Kashmir Aabid Rehman Dar hails from Anantnag, in Kashmir. He is currently pursuing Civil Engineering from a college affiliated to Gujarat Technological University. He is 23-year-old and currently in his final year. The Kashmir valley witnesses heavy snow along with snowfall during the winter months from December to February, closing major roads and bringing mobility to a halt. Heavy snow cutter machines/vehicles are used to clean the roads, and depending on the level of snow, the process can take around 2 to 3 days. While it is easier to clean the arterial roads, the narrow paths are left with snow, which reduces mobility and sometimes even leads to people falling and getting fractures. Locals usually clean out these paths with spades; however, this is a cumbersome task and would be better performed with a mini-machine. However, with no such solution available in the market, Aabid Rehman Dar came up with the idea of a mini snow remover. Agriculture comes to a close in Kashmir during the winter months and the mini tiller machines used to plough the fields remain idle. Aabid decided to modify the tillers and use them as snow remover machines. To do this, he added an attachment to the tiller that could plough the snow from the roads. The attachment is fitted in the front of the tiller and is detachable – it can be attached or detached using 2 bolts, taking upto 2 minutes. The device comprises of a curved shovel blade having 48 inches of curved width. It can clean the snow from 36 inches of snow from the surface of in just one go. The whole device remains unchanged in its design & operational activity which adds novelty to this innovation. agriculture machine device snow https://www.youtube.com/watch?v=tEMI3Kn55Ds', '{"innovation_slug":"snow-remover","detail_url":"https://gian.org/multilingual_data/snow-remover/","innovation_title":"Snow Remover","innovator_name":"Mr. Aabid Rehman Dar","location":"Jammu & Kashmir","innovator_bio":"Aabid Rehman Dar hails from Anantnag, in Kashmir. He is currently pursuing Civil Engineering from a college affiliated to Gujarat Technological University. He is 23-year-old and currently in his final year.","innovation_details":"The Kashmir valley witnesses heavy snow along with snowfall during the winter months from December to February, closing major roads and bringing mobility to a halt. Heavy snow cutter machines/vehicles are used to clean the roads, and depending on the level of snow, the process can take around 2 to 3 days. While it is easier to clean the arterial roads, the narrow paths are left with snow, which reduces mobility and sometimes even leads to people falling and getting fractures. Locals usually clean out these paths with spades; however, this is a cumbersome task and would be better performed with a mini-machine. However, with no such solution available in the market, Aabid Rehman Dar came up with the idea of a mini snow remover. Agriculture comes to a close in Kashmir during the winter months and the mini tiller machines used to plough the fields remain idle. Aabid decided to modify the tillers and use them as snow remover machines. To do this, he added an attachment to the tiller that could plough the snow from the roads. The attachment is fitted in the front of the tiller and is detachable – it can be attached or detached using 2 bolts, taking upto 2 minutes. The device comprises of a curved shovel blade having 48 inches of curved width. It can clean the snow from 36 inches of snow from the surface of in just one go. The whole device remains unchanged in its design & operational activity which adds novelty to this innovation.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image028.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image030.jpg","https://gian.org/wp-content/uploads/2023/06/image029.jpg"],"multimedia_links":["https://www.youtube.com/watch?v=tEMI3Kn55Ds"],"tags":["agriculture","machine","device","snow"],"latitude":33.7448467,"longitude":75.3062326,"listing_excerpt":"Snow Remover by Mr. Aabid Rehman Dar"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('groundnut-separator-and-coconut-cutting-machine', 'mr-senthil-duraisamy-tamil-nadu', 'Mr. Senthil Duraisamy', 'Groundnut Separator And Coconut Cutting Machine', 'Senthil had observed people take out coconuts from the whole nuts harvested from the coconut trees using a crowbar. He developed an iron cutter that could split the whole nut into two halves to extract oil for culinary purposes. At present, the motor is fitted with 1/2 hp or 1 hp to mechanize the cutting of the nuts. He also advocates that instead of harvesting nuts from the tree people should just collect the ones that have fallen. This is because these nuts are fully mature and contain more oil to extract. Further, he also advocates storing these nuts for four and half months before extracting the oil from the kernels. Normally, nuts are stored for two months after the harvest. Duraisamy’s method of harvesting and storing can increase kernel’s weight and oil content considerably. From one quintal of kernels, 71/2kg of extra oil can be obtained and from one quintal of nuts 15 kg of kernels can be obtained instead of the normal 10 kg form the normally practiced method. Senthil also uses this cutter to extract oil from palmyrah nuts. The mechanized version of this cutter (that is, connecting to 1/2 hp or 1 hp motor) can break 8,000 nuts at a time. As an added benefit, the cutter helps to save labor cost. On an average, in one minute, 25 nuts can be broken manually. The machines currently in use are typically large and consume as much as 5,000 watt. Senthil’s machine, designed as part of an incubation project, is 46 per cent smaller in volume and consumes around 2,100 watt. “Our machine can be easily customised according to the shape and size of the product to be manufactured. We have made thermoformed pieces using our machine with a cycle time of 3.5 seconds,” says Senthil. The machine is priced at Rs. 1 lakh as against the existing products in the market, which cost around Rs. 8 lakh to 10 lakh. The cost of running the machine is low, which naturally lowers thethe product cost. The machine requires just one person to operate. “It would be a boon for food packaging, toiletries, pharmaceuticals and electronics industries as these thermoformed products can prevent odour, moisture and gases from damaging the products that are packed” Mr. Senthil Kumar adds.', 'https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/', 'https://gian.org/wp-content/uploads/2023/06/image027.png', '["https://gian.org/wp-content/uploads/2023/06/image027.png","https://gian.org/wp-content/uploads/2023/06/image026.png"]'::jsonb, '["https://www.youtube.com/watch?v=npVMWAUKdQI"]'::jsonb, 'Tamil Nadu', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Senthil Duraisamy"},{"key":"Location","value":"Tamil Nadu"},{"key":"Details of Innovation","value":"Senthil had observed people take out coconuts from the whole nuts harvested from the coconut trees using a crowbar. He developed an iron cutter that could split the whole nut into two halves to extract oil for culinary purposes. At present, the motor is fitted with 1/2 hp or 1 hp to mechanize the cutting of the nuts. He also advocates that instead of harvesting nuts from the tree people should just collect the ones that have fallen. This is because these nuts are fully mature and contain more oil to extract. Further, he also advocates storing these nuts for four and half months before extracting the oil from the kernels. Normally, nuts are stored for two months after the harvest. Duraisamy’s method of harvesting and storing can increase kernel’s weight and oil content considerably. From one quintal of kernels, 71/2kg of extra oil can be obtained and from one quintal of nuts 15 kg of kernels can be obtained instead of the normal 10 kg form the normally practiced method. Senthil also uses this cutter to extract oil from palmyrah nuts. The mechanized version of this cutter (that is, connecting to 1/2 hp or 1 hp motor) can break 8,000 nuts at a time. As an added benefit, the cutter helps to save labor cost. On an average, in one minute, 25 nuts can be broken manually. The machines currently in use are typically large and consume as much as 5,000 watt. Senthil’s machine, designed as part of an incubation project, is 46 per cent smaller in volume and consumes around 2,100 watt. “Our machine can be easily customised according to the shape and size of the product to be manufactured. We have made thermoformed pieces using our machine with a cycle time of 3.5 seconds,” says Senthil. The machine is priced at Rs. 1 lakh as against the existing products in the market, which cost around Rs. 8 lakh to 10 lakh. The cost of running the machine is low, which naturally lowers thethe product cost. The machine requires just one person to operate. “It would be a boon for food packaging, toiletries, pharmaceuticals and electronics industries as these thermoformed products can prevent odour, moisture and gases from damaging the products that are packed” Mr. Senthil Kumar adds."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=npVMWAUKdQI"}]'::jsonb, ARRAY['tree', 'machine', 'food']::text[], 'Groundnut Separator And Coconut Cutting Machine Mr. Senthil Duraisamy Tamil Nadu M. Senthil Kumar (42) is a professor of mechanical engineering and principal of a college affiliated to Anna University. He has studied uptil class VIII and has more than 20 years of work experience to his credit. He began his inning working in an automobile company, after which he set up his own welding company. Senthil had observed people take out coconuts from the whole nuts harvested from the coconut trees using a crowbar. He developed an iron cutter that could split the whole nut into two halves to extract oil for culinary purposes. At present, the motor is fitted with 1/2 hp or 1 hp to mechanize the cutting of the nuts. He also advocates that instead of harvesting nuts from the tree people should just collect the ones that have fallen. This is because these nuts are fully mature and contain more oil to extract. Further, he also advocates storing these nuts for four and half months before extracting the oil from the kernels. Normally, nuts are stored for two months after the harvest. Duraisamy’s method of harvesting and storing can increase kernel’s weight and oil content considerably. From one quintal of kernels, 71/2kg of extra oil can be obtained and from one quintal of nuts 15 kg of kernels can be obtained instead of the normal 10 kg form the normally practiced method. Senthil also uses this cutter to extract oil from palmyrah nuts. The mechanized version of this cutter (that is, connecting to 1/2 hp or 1 hp motor) can break 8,000 nuts at a time. As an added benefit, the cutter helps to save labor cost. On an average, in one minute, 25 nuts can be broken manually. The machines currently in use are typically large and consume as much as 5,000 watt. Senthil’s machine, designed as part of an incubation project, is 46 per cent smaller in volume and consumes around 2,100 watt. “Our machine can be easily customised according to the shape and size of the product to be manufactured. We have made thermoformed pieces using our machine with a cycle time of 3.5 seconds,” says Senthil. The machine is priced at Rs. 1 lakh as against the existing products in the market, which cost around Rs. 8 lakh to 10 lakh. The cost of running the machine is low, which naturally lowers thethe product cost. The machine requires just one person to operate. “It would be a boon for food packaging, toiletries, pharmaceuticals and electronics industries as these thermoformed products can prevent odour, moisture and gases from damaging the products that are packed” Mr. Senthil Kumar adds. tree machine food https://www.youtube.com/watch?v=npVMWAUKdQI', '{"innovation_slug":"groundnut-separator-and-coconut-cutting-machine","detail_url":"https://gian.org/multilingual_data/groundnut-separator-and-coconut-cutting-machine/","innovation_title":"Groundnut Separator And Coconut Cutting Machine","innovator_name":"Mr. Senthil Duraisamy","location":"Tamil Nadu","innovator_bio":"M. Senthil Kumar (42) is a professor of mechanical engineering and principal of a college affiliated to Anna University. He has studied uptil class VIII and has more than 20 years of work experience to his credit. He began his inning working in an automobile company, after which he set up his own welding company.","innovation_details":"Senthil had observed people take out coconuts from the whole nuts harvested from the coconut trees using a crowbar. He developed an iron cutter that could split the whole nut into two halves to extract oil for culinary purposes. At present, the motor is fitted with 1/2 hp or 1 hp to mechanize the cutting of the nuts. He also advocates that instead of harvesting nuts from the tree people should just collect the ones that have fallen. This is because these nuts are fully mature and contain more oil to extract. Further, he also advocates storing these nuts for four and half months before extracting the oil from the kernels. Normally, nuts are stored for two months after the harvest. Duraisamy’s method of harvesting and storing can increase kernel’s weight and oil content considerably. From one quintal of kernels, 71/2kg of extra oil can be obtained and from one quintal of nuts 15 kg of kernels can be obtained instead of the normal 10 kg form the normally practiced method. Senthil also uses this cutter to extract oil from palmyrah nuts. The mechanized version of this cutter (that is, connecting to 1/2 hp or 1 hp motor) can break 8,000 nuts at a time. As an added benefit, the cutter helps to save labor cost. On an average, in one minute, 25 nuts can be broken manually. The machines currently in use are typically large and consume as much as 5,000 watt. Senthil’s machine, designed as part of an incubation project, is 46 per cent smaller in volume and consumes around 2,100 watt. “Our machine can be easily customised according to the shape and size of the product to be manufactured. We have made thermoformed pieces using our machine with a cycle time of 3.5 seconds,” says Senthil. The machine is priced at Rs. 1 lakh as against the existing products in the market, which cost around Rs. 8 lakh to 10 lakh. The cost of running the machine is low, which naturally lowers thethe product cost. The machine requires just one person to operate. “It would be a boon for food packaging, toiletries, pharmaceuticals and electronics industries as these thermoformed products can prevent odour, moisture and gases from damaging the products that are packed” Mr. Senthil Kumar adds.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image025.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image027.png","https://gian.org/wp-content/uploads/2023/06/image026.png"],"multimedia_links":["https://www.youtube.com/watch?v=npVMWAUKdQI"],"tags":["tree","machine","food"],"latitude":9.9980277,"longitude":78.3500875,"listing_excerpt":"Mr. Senthil Duraisamy"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('toilet-attached-cot', 'mr-saravana-muthu-tamil-nadu', 'Mr. Saravana Muthu', 'Toilet-Attached Cot', 'S. Saravana Muthu invented a remote-control toilet bed for his wife that won him the National Innovation Prize. His wife felt awkward about seeking help, a situation which many bedridden people can identify with. Saravana decided to make a bed that had an attached toilet and ease her life.He designed a cot fitted with a 12 V battery to operate two gear motors to move the attached toilet pot vertically and sideways. He also incorporated a remote-controlled flushing system, making it easy for the user to clean the pot after use. The innovation includes a flush tank, a closet and a pipe connected to the septic tank. The patient can operate the toilet with the help of a remote. The buttons can be used to open the shutter and the closet, and as well as flush the toilet. His invention attracted the attention of a regional newspaper, enabling Saravana Muthu to receive his first order in 2015 from a man in Chennai whose mother had been bedridden for six years. Gradually, word spread and Sarvana began receiving request for the innovative bed. His innovation is supported under MVIF by GIAN and SIDBI for prototype development and marketing. He received a trophy, a certificate and Rs 2 lakh from President Ram Nath Kovind along with a reimbursement of Rs 35,000 he had used to make the prototype. He says, “I have two goals – make a fuel-free car and become a role model for my children.” Saravana Muthu has already started working on making an emission-less car and hopes to complete his project soon. He has a message for other innovators: “For the people who never thought that idea or creation is insignificant, my advice would be never to give up. I failed multiple times before making the right prototype for my wife. Had I given up because of external factors, my wife would have continued to be embarrassed. There is no alternative to hard work.” says Saravanmuthu', 'https://gian.org/multilingual_data/toilet-attached-cot/', 'https://gian.org/wp-content/uploads/2023/06/image024.jpg', '["https://gian.org/wp-content/uploads/2023/06/image024.jpg"]'::jsonb, '["https://youtu.be/wB6iR4pdYAc"]'::jsonb, 'Tamil Nadu', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Saravana Muthu"},{"key":"Location","value":"Tamil Nadu"},{"key":"Details of Innovation","value":"S. Saravana Muthu invented a remote-control toilet bed for his wife that won him the National Innovation Prize. His wife felt awkward about seeking help, a situation which many bedridden people can identify with. Saravana decided to make a bed that had an attached toilet and ease her life.He designed a cot fitted with a 12 V battery to operate two gear motors to move the attached toilet pot vertically and sideways. He also incorporated a remote-controlled flushing system, making it easy for the user to clean the pot after use. The innovation includes a flush tank, a closet and a pipe connected to the septic tank. The patient can operate the toilet with the help of a remote. The buttons can be used to open the shutter and the closet, and as well as flush the toilet. His invention attracted the attention of a regional newspaper, enabling Saravana Muthu to receive his first order in 2015 from a man in Chennai whose mother had been bedridden for six years. Gradually, word spread and Sarvana began receiving request for the innovative bed. His innovation is supported under MVIF by GIAN and SIDBI for prototype development and marketing. He received a trophy, a certificate and Rs 2 lakh from President Ram Nath Kovind along with a reimbursement of Rs 35,000 he had used to make the prototype. He says, “I have two goals – make a fuel-free car and become a role model for my children.” Saravana Muthu has already started working on making an emission-less car and hopes to complete his project soon. He has a message for other innovators: “For the people who never thought that idea or creation is insignificant, my advice would be never to give up. I failed multiple times before making the right prototype for my wife. Had I given up because of external factors, my wife would have continued to be embarrassed. There is no alternative to hard work.” says Saravanmuthu"},{"key":"Multimedia Links","value":"https://youtu.be/wB6iR4pdYAc"}]'::jsonb, ARRAY[]::text[], 'Toilet-Attached Cot Mr. Saravana Muthu Tamil Nadu Saravana Muthu (40) owns an engineering workshop. Son of a car mechanic, he started tinkering with car parts early in his life and later started repairing and modifying them. He now helps students in his area in machining and fabrication work related to their projects. Unfortunately, his wife became temporarily bedridden after an operation and needed help to go to the toilet. This made her highly uncomfortable to the extent she would rather control than seek help, which further added to her woes. This motivated Saravana Muthu to design a bed with an attached toilet pot, which she could use to relieve herself without assistance. S. Saravana Muthu invented a remote-control toilet bed for his wife that won him the National Innovation Prize. His wife felt awkward about seeking help, a situation which many bedridden people can identify with. Saravana decided to make a bed that had an attached toilet and ease her life.He designed a cot fitted with a 12 V battery to operate two gear motors to move the attached toilet pot vertically and sideways. He also incorporated a remote-controlled flushing system, making it easy for the user to clean the pot after use. The innovation includes a flush tank, a closet and a pipe connected to the septic tank. The patient can operate the toilet with the help of a remote. The buttons can be used to open the shutter and the closet, and as well as flush the toilet. His invention attracted the attention of a regional newspaper, enabling Saravana Muthu to receive his first order in 2015 from a man in Chennai whose mother had been bedridden for six years. Gradually, word spread and Sarvana began receiving request for the innovative bed. His innovation is supported under MVIF by GIAN and SIDBI for prototype development and marketing. He received a trophy, a certificate and Rs 2 lakh from President Ram Nath Kovind along with a reimbursement of Rs 35,000 he had used to make the prototype. He says, “I have two goals – make a fuel-free car and become a role model for my children.” Saravana Muthu has already started working on making an emission-less car and hopes to complete his project soon. He has a message for other innovators: “For the people who never thought that idea or creation is insignificant, my advice would be never to give up. I failed multiple times before making the right prototype for my wife. Had I given up because of external factors, my wife would have continued to be embarrassed. There is no alternative to hard work.” says Saravanmuthu https://youtu.be/wB6iR4pdYAc', '{"innovation_slug":"toilet-attached-cot","detail_url":"https://gian.org/multilingual_data/toilet-attached-cot/","innovation_title":"Toilet-Attached Cot","innovator_name":"Mr. Saravana Muthu","location":"Tamil Nadu","innovator_bio":"Saravana Muthu (40) owns an engineering workshop. Son of a car mechanic, he started tinkering with car parts early in his life and later started repairing and modifying them. He now helps students in his area in machining and fabrication work related to their projects. Unfortunately, his wife became temporarily bedridden after an operation and needed help to go to the toilet. This made her highly uncomfortable to the extent she would rather control than seek help, which further added to her woes. This motivated Saravana Muthu to design a bed with an attached toilet pot, which she could use to relieve herself without assistance.","innovation_details":"S. Saravana Muthu invented a remote-control toilet bed for his wife that won him the National Innovation Prize. His wife felt awkward about seeking help, a situation which many bedridden people can identify with. Saravana decided to make a bed that had an attached toilet and ease her life.He designed a cot fitted with a 12 V battery to operate two gear motors to move the attached toilet pot vertically and sideways. He also incorporated a remote-controlled flushing system, making it easy for the user to clean the pot after use. The innovation includes a flush tank, a closet and a pipe connected to the septic tank. The patient can operate the toilet with the help of a remote. The buttons can be used to open the shutter and the closet, and as well as flush the toilet. His invention attracted the attention of a regional newspaper, enabling Saravana Muthu to receive his first order in 2015 from a man in Chennai whose mother had been bedridden for six years. Gradually, word spread and Sarvana began receiving request for the innovative bed. His innovation is supported under MVIF by GIAN and SIDBI for prototype development and marketing. He received a trophy, a certificate and Rs 2 lakh from President Ram Nath Kovind along with a reimbursement of Rs 35,000 he had used to make the prototype. He says, “I have two goals – make a fuel-free car and become a role model for my children.” Saravana Muthu has already started working on making an emission-less car and hopes to complete his project soon. He has a message for other innovators: “For the people who never thought that idea or creation is insignificant, my advice would be never to give up. I failed multiple times before making the right prototype for my wife. Had I given up because of external factors, my wife would have continued to be embarrassed. There is no alternative to hard work.” says Saravanmuthu","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image023.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image024.jpg"],"multimedia_links":["https://youtu.be/wB6iR4pdYAc"],"tags":[],"latitude":8.1665445,"longitude":77.4085149,"listing_excerpt":"Mr. Saravana Muthu"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('banana-fiber-products', 'mr-murugesan-tamil-nadu', 'Mr. Murugesan', 'Banana Fiber Products', 'Murugesan came up with his idea of a rope when he witnessed thread made from the banana plant being used to weave flowers into a garland. However, it was easier thought than done. Initially, the rope would simply split up. Also, there was no machine available that could split the banana fiber. He experimented with machines used to process coconut husk but with no success. In his native area, Murugesan says some machines are used to process coconut husk into ropes, and he first tried processing the banana fibre using the same technique but with no success. He then thought of inventing his own machine. After many attempts, he developed a spinning machine using bicycle wheel rims and pulleys. He further invested Rs 1.5 lakh to improve the device and patent it. In 2017, Murugesan was finally able to develop an automated rope-making machine. The initial hand-wheel mechanism to make rope from the banana sheath would use five people per wheel for the process, with each wheel yielding only around 2,500 metres of rope. With the new machine, the production capacity rose to an average of 15,000 metres, utilizing one machine and four people in all. The company initially started with 10 people and now employs over 350, mostly women. The turnover is 1.5 crore annually. Nilesh was facilitated at the 15th FGI Awards for Excellence, 2018 where he received the Best innovative work award in the field of agriculture development, His innovation got financial support for marketing and prototype development under MVIF from GIAN and SIDBI. Murugesan has received the PMEGP (Prime Minister’s Employment Generation Programme) Award from Khadi and Village Industries Commission under the Ministry of Micro, Small and Medium Enterprises; National Farmer Scientist Award from Union Ministry for Agriculture; and Best Entrepreneur Award from Krishi Vigyan Kendra at Jabalpur. “What we do is braid the strands together to achieve a good tensile strength. We had to make sure that the products that we were making out of this are worth the money,” he said.', 'https://gian.org/multilingual_data/banana-fiber-products/', 'https://gian.org/wp-content/uploads/2023/06/image020.jpg', '["https://gian.org/wp-content/uploads/2023/06/image020.jpg","https://gian.org/wp-content/uploads/2023/06/image021.jpg","https://gian.org/wp-content/uploads/2023/06/image022.jpg"]'::jsonb, '["https://youtube.com/shorts/tn0LdTUTfOk","https://keyword-plus.com/s/?q=bicycle"]'::jsonb, 'Tamil Nadu', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Murugesan"},{"key":"Location","value":"Tamil Nadu"},{"key":"Details of Innovation","value":"Murugesan came up with his idea of a rope when he witnessed thread made from the banana plant being used to weave flowers into a garland. However, it was easier thought than done. Initially, the rope would simply split up. Also, there was no machine available that could split the banana fiber. He experimented with machines used to process coconut husk but with no success. In his native area, Murugesan says some machines are used to process coconut husk into ropes, and he first tried processing the banana fibre using the same technique but with no success. He then thought of inventing his own machine. After many attempts, he developed a spinning machine using bicycle wheel rims and pulleys. He further invested Rs 1.5 lakh to improve the device and patent it. In 2017, Murugesan was finally able to develop an automated rope-making machine. The initial hand-wheel mechanism to make rope from the banana sheath would use five people per wheel for the process, with each wheel yielding only around 2,500 metres of rope. With the new machine, the production capacity rose to an average of 15,000 metres, utilizing one machine and four people in all. The company initially started with 10 people and now employs over 350, mostly women. The turnover is 1.5 crore annually. Nilesh was facilitated at the 15th FGI Awards for Excellence, 2018 where he received the Best innovative work award in the field of agriculture development, His innovation got financial support for marketing and prototype development under MVIF from GIAN and SIDBI. Murugesan has received the PMEGP (Prime Minister’s Employment Generation Programme) Award from Khadi and Village Industries Commission under the Ministry of Micro, Small and Medium Enterprises; National Farmer Scientist Award from Union Ministry for Agriculture; and Best Entrepreneur Award from Krishi Vigyan Kendra at Jabalpur. “What we do is braid the strands together to achieve a good tensile strength. We had to make sure that the products that we were making out of this are worth the money,” he said."},{"key":"Multimedia Links","value":"https://youtube.com/shorts/tn0LdTUTfOk | https://keyword-plus.com/s/?q=bicycle"}]'::jsonb, ARRAY['agriculture', 'machine', 'device', 'processing', 'farmer']::text[], 'Banana Fiber Products Mr. Murugesan Tamil Nadu Mr. Murugesan is a school dropout who hails from the village of Melakkal in Madurai, Tamil Nadu. Family hardships and the need for sustainable development motivated him to identify means to put banana waste to use. He finally discovered a way to weave the waste into ropes that could be used to make waste bags and baskets. According to The Better India, an Indian digital media platform, Murugesan set up his own MS Ropes Production Center to create these products, an innovation that has won him many awards and accolades. However, his journey has been far from easy. Murugesan came up with his idea of a rope when he witnessed thread made from the banana plant being used to weave flowers into a garland. However, it was easier thought than done. Initially, the rope would simply split up. Also, there was no machine available that could split the banana fiber. He experimented with machines used to process coconut husk but with no success. In his native area, Murugesan says some machines are used to process coconut husk into ropes, and he first tried processing the banana fibre using the same technique but with no success. He then thought of inventing his own machine. After many attempts, he developed a spinning machine using bicycle wheel rims and pulleys. He further invested Rs 1.5 lakh to improve the device and patent it. In 2017, Murugesan was finally able to develop an automated rope-making machine. The initial hand-wheel mechanism to make rope from the banana sheath would use five people per wheel for the process, with each wheel yielding only around 2,500 metres of rope. With the new machine, the production capacity rose to an average of 15,000 metres, utilizing one machine and four people in all. The company initially started with 10 people and now employs over 350, mostly women. The turnover is 1.5 crore annually. Nilesh was facilitated at the 15th FGI Awards for Excellence, 2018 where he received the Best innovative work award in the field of agriculture development, His innovation got financial support for marketing and prototype development under MVIF from GIAN and SIDBI. Murugesan has received the PMEGP (Prime Minister’s Employment Generation Programme) Award from Khadi and Village Industries Commission under the Ministry of Micro, Small and Medium Enterprises; National Farmer Scientist Award from Union Ministry for Agriculture; and Best Entrepreneur Award from Krishi Vigyan Kendra at Jabalpur. “What we do is braid the strands together to achieve a good tensile strength. We had to make sure that the products that we were making out of this are worth the money,” he said. agriculture machine device processing farmer https://youtube.com/shorts/tn0LdTUTfOk https://keyword-plus.com/s/?q=bicycle', '{"innovation_slug":"banana-fiber-products","detail_url":"https://gian.org/multilingual_data/banana-fiber-products/","innovation_title":"Banana Fiber Products","innovator_name":"Mr. Murugesan","location":"Tamil Nadu","innovator_bio":"Mr. Murugesan is a school dropout who hails from the village of Melakkal in Madurai, Tamil Nadu. Family hardships and the need for sustainable development motivated him to identify means to put banana waste to use. He finally discovered a way to weave the waste into ropes that could be used to make waste bags and baskets. According to The Better India, an Indian digital media platform, Murugesan set up his own MS Ropes Production Center to create these products, an innovation that has won him many awards and accolades. However, his journey has been far from easy.","innovation_details":"Murugesan came up with his idea of a rope when he witnessed thread made from the banana plant being used to weave flowers into a garland. However, it was easier thought than done. Initially, the rope would simply split up. Also, there was no machine available that could split the banana fiber. He experimented with machines used to process coconut husk but with no success. In his native area, Murugesan says some machines are used to process coconut husk into ropes, and he first tried processing the banana fibre using the same technique but with no success. He then thought of inventing his own machine. After many attempts, he developed a spinning machine using bicycle wheel rims and pulleys. He further invested Rs 1.5 lakh to improve the device and patent it. In 2017, Murugesan was finally able to develop an automated rope-making machine. The initial hand-wheel mechanism to make rope from the banana sheath would use five people per wheel for the process, with each wheel yielding only around 2,500 metres of rope. With the new machine, the production capacity rose to an average of 15,000 metres, utilizing one machine and four people in all. The company initially started with 10 people and now employs over 350, mostly women. The turnover is 1.5 crore annually. Nilesh was facilitated at the 15th FGI Awards for Excellence, 2018 where he received the Best innovative work award in the field of agriculture development, His innovation got financial support for marketing and prototype development under MVIF from GIAN and SIDBI. Murugesan has received the PMEGP (Prime Minister’s Employment Generation Programme) Award from Khadi and Village Industries Commission under the Ministry of Micro, Small and Medium Enterprises; National Farmer Scientist Award from Union Ministry for Agriculture; and Best Entrepreneur Award from Krishi Vigyan Kendra at Jabalpur. “What we do is braid the strands together to achieve a good tensile strength. We had to make sure that the products that we were making out of this are worth the money,” he said.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image019.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image020.jpg","https://gian.org/wp-content/uploads/2023/06/image021.jpg","https://gian.org/wp-content/uploads/2023/06/image022.jpg"],"multimedia_links":["https://youtube.com/shorts/tn0LdTUTfOk","https://keyword-plus.com/s/?q=bicycle"],"tags":["agriculture","machine","device","processing","farmer"],"latitude":9.984969,"longitude":77.98529,"listing_excerpt":"Mr. Murugesan"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('folded-ladder', 'mr-mohd-rafiq-ahanger-jammu-and-kashmir', 'Mr. Mohd Rafiq Ahanger', 'Folded Ladder', 'In 1995, at the age of 20, he set up his own workshop to make grill gates, different iron structures for household use, and do motor repairing work. Born and brought up in a rural area, it was easy for Rafiq to identify with the problems people face in their daily lives, a fact that finds reflection in the products he designs. Given the poor condition of electricity in the region, he was in dire need of an electricity generator for his workshop. However, he did not have the funds to make a purchase. This prompted him to design a pressure generator for producing electricity. Rafiq claims to have developed a generator, which can produce 40W electricity. His innovation won him a lot of admiration in the district as also an invitation to the Islamic University of Science and Technology to demonstrate his device. Rafiq devotes most of his time working on his innovations and developing new prototypes. His wife is very considerate and supportive of his efforts and majorly shoulders the responsibility of the family, giving him the much-needed time to follow his passion. She hopes that one day her husband’s persistence pays off – ‘Mehnat tas Chu fal’, she says, implying hard work secures reward. This iron ladder has a multipurpose use in horticulture during harvesting and branch cuttingand is more secure than those that currently exist in the market. It is designed like a tripodwith a full height of up to 12 feet. Its wide pillar length ensures that a person can stand on itsecurely without losing balance. A basket can be pulled up and down by means of a ropepulley attached to the supporting pillar, which can be adjusted by hand without the need foran additional tool. This ladder can be folded to half its size and used as a 6 feet ladder whenopen. It is portable and ideal for both indoor and outdoor use. The ladder is made of strong material which can hold up to 100 kgs of weight. The producthas yet to go to the market. However, it is safe and secure and easy to carry, making it apotential winner. The ladder gained recognition and was awarded during the 9th NationalBiennial Grassroots Innovation Awards 2017, held on March 4th, 2017 at RashtrapatiBhavan, New Delhi.', 'https://gian.org/multilingual_data/folded-ladder/', 'https://gian.org/wp-content/uploads/2023/06/image013-768x1024.jpg', '["https://gian.org/wp-content/uploads/2023/06/image013-768x1024.jpg","https://gian.org/wp-content/uploads/2023/06/image014-768x1024.jpg","https://gian.org/wp-content/uploads/2023/06/image014.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=Es-qc9zUcg0"]'::jsonb, 'Jammu and Kashmir', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Mohd Rafiq Ahanger"},{"key":"Location","value":"Jammu and Kashmir"},{"key":"Details of Innovation","value":"In 1995, at the age of 20, he set up his own workshop to make grill gates, different iron structures for household use, and do motor repairing work. Born and brought up in a rural area, it was easy for Rafiq to identify with the problems people face in their daily lives, a fact that finds reflection in the products he designs. Given the poor condition of electricity in the region, he was in dire need of an electricity generator for his workshop. However, he did not have the funds to make a purchase. This prompted him to design a pressure generator for producing electricity. Rafiq claims to have developed a generator, which can produce 40W electricity. His innovation won him a lot of admiration in the district as also an invitation to the Islamic University of Science and Technology to demonstrate his device. Rafiq devotes most of his time working on his innovations and developing new prototypes. His wife is very considerate and supportive of his efforts and majorly shoulders the responsibility of the family, giving him the much-needed time to follow his passion. She hopes that one day her husband’s persistence pays off – ‘Mehnat tas Chu fal’, she says, implying hard work secures reward. This iron ladder has a multipurpose use in horticulture during harvesting and branch cuttingand is more secure than those that currently exist in the market. It is designed like a tripodwith a full height of up to 12 feet. Its wide pillar length ensures that a person can stand on itsecurely without losing balance. A basket can be pulled up and down by means of a ropepulley attached to the supporting pillar, which can be adjusted by hand without the need foran additional tool. This ladder can be folded to half its size and used as a 6 feet ladder whenopen. It is portable and ideal for both indoor and outdoor use. The ladder is made of strong material which can hold up to 100 kgs of weight. The producthas yet to go to the market. However, it is safe and secure and easy to carry, making it apotential winner. The ladder gained recognition and was awarded during the 9th NationalBiennial Grassroots Innovation Awards 2017, held on March 4th, 2017 at RashtrapatiBhavan, New Delhi."},{"key":"Multimedia Links","value":"https://www.youtube.com/watch?v=Es-qc9zUcg0"}]'::jsonb, ARRAY['horticulture', 'tool', 'device']::text[], 'Folded Ladder Mr. Mohd Rafiq Ahanger Jammu and Kashmir Mohd Rafiq Ahanger, 42 years old, is a blacksmith involved in fabrication work since the last 25 years. His claim to fame is the development of a multipurpose tool, which can be used as an axe, hammer, chisel, blade, screwdriver driver for domestic or other carpentry tasks. Born in the family of blacksmiths, Rafiq did not have an easy childhood due to financial problems. It was tough for his father to raise eight children – two sons and six daughters. He recalls that though they come from a lower income background, he was cushioned from the shocks of poverty by his supportive parents, who went the extra mile to provide for their children. Since childhood, he had access to blacksmith tools, iron and steel, which he loved to play around with. He would use them to repair old gadgets, and make toys or small replicas. He studied till class ten and then took up odd jobs before finally settling into his father’s workshop. In 1995, at the age of 20, he set up his own workshop to make grill gates, different iron structures for household use, and do motor repairing work. Born and brought up in a rural area, it was easy for Rafiq to identify with the problems people face in their daily lives, a fact that finds reflection in the products he designs. Given the poor condition of electricity in the region, he was in dire need of an electricity generator for his workshop. However, he did not have the funds to make a purchase. This prompted him to design a pressure generator for producing electricity. Rafiq claims to have developed a generator, which can produce 40W electricity. His innovation won him a lot of admiration in the district as also an invitation to the Islamic University of Science and Technology to demonstrate his device. Rafiq devotes most of his time working on his innovations and developing new prototypes. His wife is very considerate and supportive of his efforts and majorly shoulders the responsibility of the family, giving him the much-needed time to follow his passion. She hopes that one day her husband’s persistence pays off – ‘Mehnat tas Chu fal’, she says, implying hard work secures reward. This iron ladder has a multipurpose use in horticulture during harvesting and branch cuttingand is more secure than those that currently exist in the market. It is designed like a tripodwith a full height of up to 12 feet. Its wide pillar length ensures that a person can stand on itsecurely without losing balance. A basket can be pulled up and down by means of a ropepulley attached to the supporting pillar, which can be adjusted by hand without the need foran additional tool. This ladder can be folded to half its size and used as a 6 feet ladder whenopen. It is portable and ideal for both indoor and outdoor use. The ladder is made of strong material which can hold up to 100 kgs of weight. The producthas yet to go to the market. However, it is safe and secure and easy to carry, making it apotential winner. The ladder gained recognition and was awarded during the 9th NationalBiennial Grassroots Innovation Awards 2017, held on March 4th, 2017 at RashtrapatiBhavan, New Delhi. horticulture tool device https://www.youtube.com/watch?v=Es-qc9zUcg0', '{"innovation_slug":"folded-ladder","detail_url":"https://gian.org/multilingual_data/folded-ladder/","innovation_title":"Folded Ladder","innovator_name":"Mr. Mohd Rafiq Ahanger","location":"Jammu and Kashmir","innovator_bio":"Mohd Rafiq Ahanger, 42 years old, is a blacksmith involved in fabrication work since the last 25 years. His claim to fame is the development of a multipurpose tool, which can be used as an axe, hammer, chisel, blade, screwdriver driver for domestic or other carpentry tasks. Born in the family of blacksmiths, Rafiq did not have an easy childhood due to financial problems. It was tough for his father to raise eight children – two sons and six daughters. He recalls that though they come from a lower income background, he was cushioned from the shocks of poverty by his supportive parents, who went the extra mile to provide for their children. Since childhood, he had access to blacksmith tools, iron and steel, which he loved to play around with. He would use them to repair old gadgets, and make toys or small replicas. He studied till class ten and then took up odd jobs before finally settling into his father’s workshop.","innovation_details":"In 1995, at the age of 20, he set up his own workshop to make grill gates, different iron structures for household use, and do motor repairing work. Born and brought up in a rural area, it was easy for Rafiq to identify with the problems people face in their daily lives, a fact that finds reflection in the products he designs. Given the poor condition of electricity in the region, he was in dire need of an electricity generator for his workshop. However, he did not have the funds to make a purchase. This prompted him to design a pressure generator for producing electricity. Rafiq claims to have developed a generator, which can produce 40W electricity. His innovation won him a lot of admiration in the district as also an invitation to the Islamic University of Science and Technology to demonstrate his device. Rafiq devotes most of his time working on his innovations and developing new prototypes. His wife is very considerate and supportive of his efforts and majorly shoulders the responsibility of the family, giving him the much-needed time to follow his passion. She hopes that one day her husband’s persistence pays off – ‘Mehnat tas Chu fal’, she says, implying hard work secures reward. This iron ladder has a multipurpose use in horticulture during harvesting and branch cuttingand is more secure than those that currently exist in the market. It is designed like a tripodwith a full height of up to 12 feet. Its wide pillar length ensures that a person can stand on itsecurely without losing balance. A basket can be pulled up and down by means of a ropepulley attached to the supporting pillar, which can be adjusted by hand without the need foran additional tool. This ladder can be folded to half its size and used as a 6 feet ladder whenopen. It is portable and ideal for both indoor and outdoor use. The ladder is made of strong material which can hold up to 100 kgs of weight. The producthas yet to go to the market. However, it is safe and secure and easy to carry, making it apotential winner. The ladder gained recognition and was awarded during the 9th NationalBiennial Grassroots Innovation Awards 2017, held on March 4th, 2017 at RashtrapatiBhavan, New Delhi.","innovator_images":["https://gian.org/wp-content/uploads/2023/06/image012.png"],"innovation_images":["https://gian.org/wp-content/uploads/2023/06/image013-768x1024.jpg","https://gian.org/wp-content/uploads/2023/06/image014-768x1024.jpg","https://gian.org/wp-content/uploads/2023/06/image014.jpg"],"multimedia_links":["https://www.youtube.com/watch?v=Es-qc9zUcg0"],"tags":["horticulture","tool","device"],"latitude":33.8987336,"longitude":75.2245693,"listing_excerpt":"Mr. Mohd Rafiq Ahanger"}'::jsonb, now(), now());
insert into public.gian_innovations (portal_product_id, portal_vendor_id, vendor_name, product_name, product_description, product_link, product_image_url, product_gallery_urls, product_video_urls, product_location_text, product_categories, product_subcategories, product_specifications, tags, search_text, raw_product, synced_at, updated_at) values ('groundnut-digger-turmeric-digger-garlic-digger', 'mr-sanjaybhai-tilva-gujarat', 'Mr. Sanjaybhai Tilva', 'Groundnut Digger/Turmeric Digger/Garlic Digger', 'Sanjay has five acres of cultivable land where he primarily grows groundnut. Working in the field, he realized how difficult and time-consuming it was to dig up the groundnuts. He discussed the issue with other farmers who also said that they had to incur losses due to the high cost and limited availability of labor to dig out the groundnuts. It was sometime in the year 2007 that Sanjay decided to come up with a solution. Initially, he developed a hand-operated plough; however, its efficiency was low and the device itself was labor-intensive. He then went on to develop a tractor-operated plough; however, this too had its limitation in that the groundnut pods either got broken or left in the ground. Working persistently, he was finally able to develop a prototype in 2009, which he modified to add two wheels under the conveyor for vibration. Finally, the machine was able to do what it was designed to. Sanjay recalls that the entire period of experimentation was a trying one and that he had to constantly swim against the tide to successfully culminate his journey. He also acknowledges the support of his elder brother and one of his friends in motivating him towards a successful solution. Sanjay’s innovation is a tractor-mounted, PTO-powered machine with a telescopic propeller shaft, suitable for tractors of 35 HP and above. It can dig out and uproot groundnuts from the soil. The harvesting blade (V shaped) of the machine is used to uproot the groundnuts. The blade is hardened by treating in oil at a very high temperature to make it suitable for work in different kinds of soil. It has an adjustable width and with variable penetration angle. Once uprooted, the conveyer belt conveys the groundnuts from the ground level to a higher level. During the process, the belt keeps vibrating, as a result of which the pods get cleaned of the attached soil. The collection box then opens to form the bed for groundnuts to dry. As the machine is heavy, wheels are provided at the rear to reduce the load on the tractor. Though the productivity of the machine depends on the type of soil, on an average, it can harvest about 3 to 4 Veega (0.4 Acre) per hour. In comparison to other alternatives, this machine not only mechanizes the digging but also undertakes cleaning and drying as well. Other alternatives commonly used are single offset beam digger and manual labor. In the latter case, three to five persons are required to pull out the plants, which have already been dug, and then clean the groundnuts, that is, remove soil from the plants. With the single offset digger, digging is done mechanically and subsequently, the pods are collected manually. This machine saves considerable labor, operating time and cost of operation compared to conventional methods. Moreover, this machine can be used in different kinds of soil. The testing of the device was done at CAET, Junagadh Agricultural University, Junagadh and the results were found to be appreciable. The price of the machine is Rs. 95,000 – (Ex-factory India packaging). The price does not include transportation cost, taxes etc. NIF felicitated the innovator with a National award in the Seventh Biennial Award Function of National Innovation Foundation. In 2019, Sanjay received marketing support from GIAN and SIDBI under MVIF (Micro Venture Innovation Fund). Technical Specifications Fuel Consumption – 1 lit/h Prime mover – 35 HP PTO Tractor Weight of Device – 374 kg Digging Efficiency – 98% Effective Width of cutting – 1250 mm Effective Depth of cutting – 100 – 120 mm Status of Innovation: Mr. Sanjay Tilwa has managed to sell a few units of his groundnut digger. The product has received appreciation from both experts and farmers, pointing to a good potential in the market. While working on the ground digger, Sanjay realized that he would have to diversify as this machine had a season-based demand. Accordingly, he developed another innovative tool – the reversible ploughs, which are also attached to the tractor. There are different variations of the plough, including manual, machine, hydraulic operated and a few more. He began selling these a few months back and has managed decent sales. Presently, Sanjay is actively engaged in fabricating and improving the digging machine, which he plans to make suitable for multiple crops.', 'https://gian.org/multilingual_data/groundnut-digger-turmeric-digger-garlic-digger/', 'https://gian.org/wp-content/uploads/2023/06/image010.png', '["https://gian.org/wp-content/uploads/2023/06/image010.png","https://gian.org/wp-content/uploads/2023/06/image011.jpg"]'::jsonb, '["https://www.youtube.com/watch?v=Ky0p3BUd2pc"]'::jsonb, 'Gujarat', ARRAY[]::text[], ARRAY[]::text[], '[{"key":"Innovator Name","value":"Mr. Sanjaybhai Tilva"},{"key":"Location","value":"Gujarat"},{"key":"Details of Innovation","value":"Sanjay has five acres of cultivable land where he primarily grows groundnut. Working in the field, he realized how difficult and time-consuming it was to dig up the groundnuts. He discussed the issue with other farmers who also said that they had to incur losses due to the high cost and limited availability of labor to dig out the groundnuts. It was sometime in the year 2007 that Sanjay decided to come up with a solution. Initially, he developed a hand-operated plough; however, its efficiency was low and the device itself was labor-intensive. He then went on to develop a tractor-operated plough; however, this too had its limitation in that the groundnut pods either got broken or left in the ground. Working persistently, he was finally able to develop a prototype in 2009, which he modified to add two wheels under the conveyor for vibration. Finally, the machine was able to do what it was designed to. Sanjay recalls that the entire period of experimentation was a trying one and that he had to constantly swim against the tide to successfully culminate his journey. He also acknowledges the support of his elder brother and one of his friends in motivating him towards a successful solution. Sanjay’s innovation is a tractor-mounted, PTO-powered machine with a telescopic propeller shaft, suitable for tractors of 35 HP and above. It can dig out and uproot groundnuts from the soil. The harvesting blade (V shaped) of the machine is used to uproot the groundnuts. The blade is hardened by treating in oil at a very high temperature to make it suitable for work in different kinds of soil. It has an adjustable width and with variable penetration angle. Once uprooted, the conveyer belt conveys the groundnuts from the ground level to a higher level. During the process, the belt keeps vibrating, as a result of which the pods get cleaned of the attached soil. The collection box then opens to form the bed for groundnuts to dry. As the machine is heavy, wheels are provided at the rear to reduce the load on the tractor. Though the productivity of the machine depends on the type of soil, on an average, it can harvest about 3 to 4 Veega (0.4 Acre) per hour. In comparison to other alternatives, this machine not only mechanizes the digging but also undertakes cleaning and drying as well. Other alternatives commonly used are single offset beam digger and manual labor. In the latter case, three to five persons are required to pull out the plants, which have already been dug, and then clean the groundnuts, that is, remove soil from the plants. With the single offset digger, digging is done mechanically and subsequently, the pods are co